  // ── Vendor management (official Sippy docs 107434) ───────────────────────

  // GET /api/sippy/vendors — listVendors() / getVendorsList() — docs 107434
  // Query: limit?, offset?, namePattern?
  app.get('/api/sippy/vendors', async (req: any, res) => {
    try {
      const settings = await storage.getSippySettings();
      if (!settings) return res.status(503).json({ vendors: [], error: 'Sippy not configured.' });
      const opts: Parameters<typeof sippy.listSippyVendors>[2] = {};
      if (req.query.limit)       opts.limit       = parseInt(req.query.limit       as string, 10);
      if (req.query.offset)      opts.offset      = parseInt(req.query.offset      as string, 10);
      if (req.query.namePattern) opts.namePattern = req.query.namePattern as string;
      // Try each credential pair — swap automatically if primary returns 401
      const credPairs = sippyXmlCredsPairs(settings);
      const credsPresent = credPairs.some(p => p.username && p.password);
      let result: { vendors: any[]; error?: string } = {
        vendors: [],
        error: credsPresent ? undefined : 'No credentials configured.',
      };
      if (xmlRpcIsBlocked()) {
        result = { vendors: [], error: 'Sippy temporarily unavailable — paused after repeated failures. Retrying automatically.' };
      } else if (credsPresent) {
        for (const { username, password } of credPairs) {
          result = await sippy.listSippyVendors(username, password, opts, sippyPortalUrl(settings));
          if (!result.error || (!result.error.includes('401') && !result.error.includes('403'))) break;
        }
      }
      res.json(result);
    } catch (e: any) { res.status(500).json({ vendors: [], error: e.message }); }
  });

  // POST /api/sippy/vendors — createVendor() — docs 107434
  // Body: { name, webPassword, webLogin, iTimeZone, ...optional fields }
  // Returns: { success, iVendor, message }
  app.post('/api/sippy/vendors', (req: any, res, next) => requireRole(['admin', 'management'], req, res, next), async (req: any, res) => {
    try {
      const b = req.body ?? {};
      const { name, webPassword, webLogin } = b;
      if (!name || !webPassword || !webLogin) {
        return res.status(400).json({ success: false, error: 'name, webPassword, and webLogin are required.' });
      }
      const settings = await storage.getSippySettings();
      if (!settings) return res.status(503).json({ success: false, error: 'Sippy not configured.' });
      const { username, password } = sippyXmlCreds(settings);

      // Build a whitelist of safe params for createVendor.
      // iTimeZone, iLang, iExportType, iPasswordPolicy, roundUp, costRoundUp, decimalPrecision
      // are excluded on creation — they either cause Fatal errors on some Sippy versions
      // or can be set via updateVendor after the vendor is created.
      const opts: sippy.CreateVendorOpts = {
        name,
        webLogin,
        webPassword,
      };
      if (b.baseCurrency)  opts.baseCurrency  = b.baseCurrency;
      if (b.companyName)   opts.companyName   = b.companyName;
      if (b.salutation)    opts.salutation    = b.salutation;
      if (b.firstName)     opts.firstName     = b.firstName;
      if (b.midInit)       opts.midInit       = b.midInit;
      if (b.lastName)      opts.lastName      = b.lastName;
      if (b.streetAddr)    opts.streetAddr    = b.streetAddr;
      if (b.state)         opts.state         = b.state;
      if (b.postalCode)    opts.postalCode    = b.postalCode;
      if (b.city)          opts.city          = b.city;
      if (b.country)       opts.country       = b.country;
      if (b.contact)       opts.contact       = b.contact;
      if (b.phone)         opts.phone         = b.phone;
      if (b.fax)           opts.fax           = b.fax;
      if (b.altPhone)      opts.altPhone      = b.altPhone;
      if (b.altContact)    opts.altContact    = b.altContact;
      if (b.email)         opts.email         = b.email;
      if (b.cc)            opts.cc            = b.cc;
      if (b.bcc)           opts.bcc           = b.bcc;

      const result = await sippy.createSippyVendor(username, password, opts, sippyPortalUrl(settings));
      if (!result.success) {
        console.error('[create-vendor] Sippy rejected:', result.message, '| opts keys:', Object.keys(opts).join(', '));
        return res.status(400).json(result);
      }
      res.status(201).json(result);
      regenDataflowDoc();
    } catch (e: any) { res.status(500).json({ success: false, error: e.message }); }
  });

  // GET /api/sippy/vendors/:id — getVendorInfo() — docs 107434
  // :id can be numeric (i_vendor) or a string name
  // Query: iCustomer? (trusted mode)
  // Returns: { success, vendor: SippyVendor & extra fields, message }
  app.get('/api/sippy/vendors/:id', async (req: any, res) => {
    try {
      const { id } = req.params;
      const { iCustomer } = req.query ?? {};
      const settings = await storage.getSippySettings();
      if (!settings) return res.status(503).json({ success: false, error: 'Sippy not configured.' });
      const { username, password } = sippyXmlCreds(settings);
      const numId = parseInt(id, 10);
      const lookup = !isNaN(numId) ? { iVendor: numId } : { name: id };
      const result = await sippy.getSippyVendorInfo(username, password, lookup, {
        iCustomer: iCustomer !== undefined ? parseInt(iCustomer as string, 10) : undefined,
        portalUrl: sippyPortalUrl(settings),
      });
      if (!result.success) return res.status(404).json(result);
      res.json(result);
    } catch (e: any) { res.status(500).json({ success: false, error: e.message }); }
  });

