  // ── EMAIL CENTRE ──────────────────────────────────────────────────────────

  // POST /api/email/bulk-send — send a composed email to a list of recipients
  // Body: { recipients: [{accountId, name, email, balance, creditLimit, kamName}], subject, body }
  // Uses the same Gmail transport as the alert system.
  app.post('/api/email/bulk-send', (req: any, res, next) => requireRole(['admin'], req, res, next), async (req: any, res) => {
    try {
      const { recipients, subject, body } = req.body ?? {};
      if (!subject?.trim()) return res.status(400).json({ error: 'subject is required' });
      if (!body?.trim())    return res.status(400).json({ error: 'body is required' });
      if (!Array.isArray(recipients) || recipients.length === 0) {
        return res.status(400).json({ error: 'recipients list is required' });
      }

      const results: { accountId: string; name: string; email: string; status: 'sent' | 'no_email' | 'error'; error?: string }[] = [];
      let sent = 0, skipped = 0, failed = 0;

      for (const r of recipients) {
        if (!r.email?.trim()) {
          results.push({ accountId: r.accountId, name: r.name, email: '', status: 'no_email' });
          skipped++;
          continue;
        }

        // Personalise subject and body with account-level tokens
        const personalSubject = subject
          .replace(/\{name\}/gi, r.name || r.accountId)
          .replace(/\{account\}/gi, r.accountId)
          .replace(/\{kam\}/gi, r.kamName || '');
        const personalBody = body
          .replace(/\{name\}/gi, r.name || r.accountId)
          .replace(/\{account\}/gi, r.accountId)
          .replace(/\{balance\}/gi, typeof r.balance === 'number' ? `$${r.balance.toFixed(2)}` : r.balance ?? '')
          .replace(/\{credit_limit\}/gi, typeof r.creditLimit === 'number' ? `$${r.creditLimit.toFixed(2)}` : r.creditLimit ?? '')
          .replace(/\{kam\}/gi, r.kamName || '');

        // Wrap in the branded email template (plain-text body → HTML)
        const html = `<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;background:#0f0f0f;color:#e0e0e0;padding:24px">
<div style="max-width:600px;margin:0 auto;background:#1a1a2e;border-radius:12px;overflow:hidden">
  <div style="background:#4f46e5;padding:20px 24px">
    <h1 style="margin:0;font-size:18px;color:#fff">📡 Bitsauto Monitoring</h1>
  </div>
  <div style="padding:24px;white-space:pre-wrap;line-height:1.6">${personalBody.replace(/</g,'&lt;').replace(/>/g,'&gt;')}</div>
  <div style="padding:12px 24px;background:#111;font-size:12px;color:#666">
    Sent via Bitsauto Monitoring &bull; ${new Date().toUTCString()}
  </div>
</div></body></html>`;

        const result = await emailSvc.sendDirectEmail({ to: r.email.trim(), subject: personalSubject, html });
        if (result.ok) {
          results.push({ accountId: r.accountId, name: r.name, email: r.email, status: 'sent' });
          sent++;
        } else {
          results.push({ accountId: r.accountId, name: r.name, email: r.email, status: 'error', error: result.error });
          failed++;
        }

        // Small delay between sends to avoid overwhelming the mail server
        await new Promise(ok => setTimeout(ok, 120));
      }

      console.log(`[email-centre] Bulk send complete: ${sent} sent, ${failed} failed, ${skipped} skipped`);
      res.json({ results, sent, failed, skipped });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // ── FAS EVENTS ────────────────────────────────────────────────────────────

  // GET /api/fas-events — list recorded FAS events
  app.get('/api/fas-events', async (req: any, res) => {
    try {
      const limit = req.query.limit ? Math.min(500, Number(req.query.limit)) : 100;
      const events = await storage.getFasEvents(limit);

      // Find first non-numeric vendor name from cache (works regardless of how many vendors exist)
      let firstVendorName = '';
      for (const val of connectionVendorCache.values()) {
        if (!/^\d+$/.test(val)) { firstVendorName = val; break; }
      }

      // If we have a vendor name and there are empty-vendor rows, permanently backfill them in DB
      if (firstVendorName) {
        const backfilled = await storage.backfillFasEventVendors(firstVendorName);
        if (backfilled > 0) {
          console.log(`[fas-events] DB-backfilled vendor="${firstVendorName}" on ${backfilled} events`);
          // Re-fetch so response reflects the updated rows
          const updated = await storage.getFasEvents(limit);
          const resolved = updated.map(e => {
            let clientName = e.clientName;
            if (!clientName || clientName.match(/^Acct[#.]?\d+$/i)) {
              const m = clientName?.match(/\d+/);
              clientName = (m ? accountNameCache.get(m[0]) : undefined) ?? clientName ?? 'Unknown';
            }
            return { ...e, clientName };
          });
          return res.json({ events: resolved });
        }
      }

      // Normal path — re-resolve stale client names; vendor is already correct in DB
      const resolved = events.map(e => {
        let clientName = e.clientName;
        if (!clientName || clientName.match(/^Acct[#.]?\d+$/i)) {
          const m = clientName?.match(/\d+/);
          clientName = (m ? accountNameCache.get(m[0]) : undefined) ?? clientName ?? 'Unknown';
        }
        // In-memory vendor fallback in case DB still has empty (should not happen after backfill above)
        const vendor = e.vendor || firstVendorName;
        return { ...e, clientName, vendor };
      });

      // Client Portal Scope — KAM-role users see only their assigned accounts' events
      const scope = await resolveUserScope(req);
      const scoped = scope.clis
        ? resolved.filter(e => (e.caller && scope.clis!.has(e.caller)) || (e.callee && scope.clis!.has(e.callee)))
        : resolved;
      res.json({ events: scoped });
    } catch (e: any) { res.status(500).json({ events: [], error: e.message }); }
  });

  // POST /api/fas/analyze — fetch Sippy CDRs for a date range and run full FAS analysis.
  // Stores new FAS events in DB and returns vendor-level fraud scoring.
  // Body: { startDate, endDate, limit? }
  app.post('/api/fas/analyze', async (req: any, res) => {
    try {
      const settings = await storage.getSettings();
      const credPairs = sippyXmlCredsPairs(settings);

      const startDate = req.body.startDate ?? sippy.toSippyDate(new Date(Date.now() - 86400000));
      const endDate   = req.body.endDate   ?? sippy.toSippyDate(new Date());
      const limit     = Math.min(1000, Number(req.body.limit ?? 500));

      const fasMinPdd          = settings.fasMinPddSecs ?? 10;
      const fasMaxBill         = settings.fasMaxBillSecs ?? 5;
      const fasEarlyAnswerSecs = settings.fasEarlyAnswerSecs ?? 2;
      const fasShortCallSecs   = settings.fasShortCallSecs ?? 10;

      // Fetch CDRs from Sippy — try each credential pair (handles swapped settings in DB)
      let cdrs: Awaited<ReturnType<typeof sippy.getSippyCDRs>> = [];
      for (const { username, password } of credPairs) {
        cdrs = await sippy.getSippyCDRs(username, password, limit, { startDate, endDate });
        if (cdrs.length > 0) break;
      }

      if (cdrs.length === 0) {
        return res.json({ analyzed: 0, fasEvents: 0, vendorScores: [], message: 'No CDRs found for the selected period.' });
      }

      // Enrich every CDR with FAS analysis
      // Sippy CDR result field: '0' = success (SIP 200 OK); other values are SIP response codes (486, 603, etc.)
      type EnrichedRow = {
        callId?: string; caller?: string; callee?: string;
        clientName?: string; vendor?: string;
        sipCode?: number | null; pddSecs?: number | null; billSecs?: number | null;
        isFas: boolean; fasReason: string; fraudScore: number; reason?: string;
      };
      const enriched: EnrichedRow[] = cdrs.map(cdr => {
        // Map Sippy result string → numeric SIP code (0 = success → 200)
        const rawResult = parseInt(String(cdr.result ?? '').trim()) || 0;
        const sipCodeVal: number | null = rawResult === 0 ? 200 : (rawResult >= 100 ? rawResult : null);
        // cdr.duration = billed_duration in seconds (the correct field for billing)
        const billSecsVal = cdr.duration ?? 0;
        // Use pdd1xx (time to 1st SIP response) as PDD for FAS detection.
        // cdr.pdd is Sippy's internal conn_proc_time (~5ms), not the ring delay.
        // pdd1xx is the actual post-dial delay (SIP INVITE → first 1xx response).
        const ringDelay = cdr.pdd1xx ?? cdr.pdd ?? null;
        const fasResult = detectFas({
          sipCode:  sipCodeVal,
          pddSecs:  ringDelay,
          billSecs: billSecsVal,
          fasMinPddSecs:    fasMinPdd,
          fasMaxBillSecs:   fasMaxBill,
          fasEarlyAnswerSecs,
          fasShortCallSecs,
        });
        // Resolve client name: prefer clientName from CDR, then cdr.user (raw Sippy field),
        // then accountNameCache by accountId/iAccount (raw Sippy field is accountId, not iAccount)
        const resolvedClient = cdr.clientName
          || cdr.user
          || accountNameCache.get(String(cdr.accountId ?? cdr.iAccount ?? ''))
          || (cdr.accountId ? `Acct#${cdr.accountId}` : cdr.iAccount ? `Acct#${cdr.iAccount}` : 'Unknown');
        // Resolve vendor: prefer CDR field, then connection cache, then first known vendor
        const resolvedVendor = (() => {
          if (cdr.vendor) return cdr.vendor;
          if (cdr.iConnection) {
            const v = connectionVendorCache.get(String(cdr.iConnection));
            if (v && !/^\d+$/.test(v)) return v;
          }
          // Fallback: first non-numeric vendor name found in cache (works for any number of vendors)
          for (const val of connectionVendorCache.values()) {
            if (!/^\d+$/.test(val)) return val;
          }
          return '';
        })();
        return {
          callId:     cdr.callId ?? '',
          caller:     cdr.caller ?? '',
          callee:     cdr.callee ?? '',
          clientName: resolvedClient,
          vendor:     resolvedVendor,
          sipCode:    sipCodeVal,
          pddSecs:    ringDelay,
          billSecs:   billSecsVal,
          isFas:      fasResult.isFas,
          fasReason:  fasResult.reason,
          fraudScore: fasResult.fraudScore,
          reason:     fasResult.reason,
        };
      });

      // Store new FAS events (skip duplicates silently)
      let savedCount = 0;
      for (const r of enriched) {
        if (r.isFas && r.callId) {
          try {
            await storage.createFasEvent({
              callId:     String(r.callId),
              caller:     r.caller ?? '',
              callee:     r.callee ?? '',
              clientName: r.clientName ?? '',
              vendor:     r.vendor ?? '',
              pddSecs:    r.pddSecs ?? null,
              billSecs:   r.billSecs ?? null,
              sipCode:    r.sipCode ?? null,
              reason:     r.fasReason,
              fraudScore: r.fraudScore,
              alertSent:  false,
            });
            savedCount++;
          } catch { /* duplicate */ }
        }
      }

      // Build risk scores grouped by CLIENT name (vendor not available in CDR API)
      const byClient: Record<string, typeof enriched> = {};
      for (const r of enriched) {
        const v = r.clientName || 'Unknown';
        if (!byClient[v]) byClient[v] = [];
        byClient[v].push(r);
      }
      const vendorScores = Object.entries(byClient).map(([vendor, rows]) =>
        calcVendorFraudStats(vendor, rows.map(r => ({
          sipCode: r.sipCode, pddSecs: r.pddSecs, billSecs: r.billSecs,
          reason: r.reason, isFas: r.isFas, fraudScore: r.fraudScore,
        })))
      ).sort((a, b) => b.fraudScore - a.fraudScore);

      res.json({ analyzed: enriched.length, fasEvents: savedCount, vendorScores });
    } catch (e: any) { res.status(500).json({ analyzed: 0, fasEvents: 0, vendorScores: [], error: e.message }); }
  });

  // GET /api/fas/vendor-scores — compute client-level fraud scores from stored FAS events in DB
  app.get('/api/fas/vendor-scores', async (_req, res) => {
    try {
      const events = await storage.getFasEvents(500);
      const byClient: Record<string, typeof events> = {};
      for (const e of events) {
        let name = e.clientName || e.vendor || 'Unknown';
        // Re-resolve stale "Acct#N" names from the live account name cache
        if (name.match(/^Acct[#.]?\d+$/i)) {
          const m = name.match(/\d+/);
          name = (m ? accountNameCache.get(m[0]) : undefined) ?? name;
        }
        if (!byClient[name]) byClient[name] = [];
        byClient[name].push(e);
      }
      const vendorScores = Object.entries(byClient).map(([vendor, rows]) =>
        calcVendorFraudStats(vendor, rows.map(r => ({
          sipCode: r.sipCode, pddSecs: r.pddSecs, billSecs: r.billSecs,
          reason: r.reason, isFas: true, fraudScore: r.fraudScore ?? 0,
        })))
      ).sort((a, b) => b.fraudScore - a.fraudScore);
      res.json({ vendorScores });
    } catch (e: any) { res.status(500).json({ vendorScores: [], error: e.message }); }
  });

  // ── FAS VENDOR SETTINGS CRUD ──────────────────────────────────────────────

  // GET /api/fas/vendor-settings — list all per-vendor suppression + alert threshold settings
  app.get('/api/fas/vendor-settings', (req: any, res, next) => requireRole(['management'], req, res, next), async (_req, res) => {
    try {
      const rows = await storage.listFasVendorSettings();
      res.json({ settings: rows });
    } catch (e: any) { res.status(500).json({ settings: [], error: e.message }); }
  });

  // POST /api/fas/vendor-settings — upsert settings for a vendor
  app.post('/api/fas/vendor-settings', (req: any, res, next) => requireRole(['management'], req, res, next), async (req: any, res) => {
    try {
      const { vendor, suppressed, alertThreshold } = req.body;
      if (!vendor) return res.status(400).json({ error: 'vendor required' });
      const row = await storage.upsertFasVendorSetting(vendor, {
        suppressed: !!suppressed,
        alertThreshold: alertThreshold != null ? Number(alertThreshold) : undefined,
      });
      res.json({ setting: row });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // DELETE /api/fas/vendor-settings/:vendor — remove vendor settings
  app.delete('/api/fas/vendor-settings/:vendor', (req: any, res, next) => requireRole(['management'], req, res, next), async (req: any, res) => {
    try {
      await storage.deleteFasVendorSetting(decodeURIComponent(req.params.vendor));
      res.json({ ok: true });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // GET /api/fas/vendor-events?vendor=X — FAS events filtered by vendor name
  app.get('/api/fas/vendor-events', (req: any, res, next) => requireRole(['management'], req, res, next), async (req: any, res) => {
    try {
      const vendor = req.query.vendor as string | undefined;
      const limit = Math.min(500, Number(req.query.limit ?? 200));
      const events = await storage.getFasEvents(limit, vendor);
      const resolved = events.map(e => {
        let clientName = e.clientName;
        if (!clientName || clientName.match(/^Acct[#.]?\d+$/i)) {
          const m = clientName?.match(/\d+/);
          clientName = (m ? accountNameCache.get(m[0]) : undefined) ?? clientName ?? 'Unknown';
        }
        return { ...e, clientName };
      });
      res.json({ events: resolved, total: resolved.length });
    } catch (e: any) { res.status(500).json({ events: [], error: e.message }); }
  });

  // GET /api/fas/vendor-trend?vendor=X — daily FAS count for the past 7 days per vendor
  app.get('/api/fas/vendor-trend', (req: any, res, next) => requireRole(['management'], req, res, next), async (req: any, res) => {
    try {
      const vendor = req.query.vendor as string | undefined;
      const days = Math.min(30, Number(req.query.days ?? 7));
      const since = new Date(Date.now() - days * 86400000);
      // Fetch a larger pool of events to compute daily buckets
      const events = await storage.getFasEvents(2000, vendor);
      const recent = events.filter(e => new Date(e.detectedAt) >= since);
      // Group by day (UTC date string)
      const byDay: Record<string, number> = {};
      for (let d = 0; d < days; d++) {
        const day = new Date(Date.now() - d * 86400000).toISOString().slice(0, 10);
        byDay[day] = 0;
      }
      for (const e of recent) {
        const day = new Date(e.detectedAt).toISOString().slice(0, 10);
        if (day in byDay) byDay[day]++;
      }
      const trend = Object.entries(byDay)
        .sort(([a], [b]) => a.localeCompare(b))
        .map(([date, count]) => ({ date, count }));
      res.json({ trend, vendor: vendor ?? 'all', days });
    } catch (e: any) { res.status(500).json({ trend: [], error: e.message }); }
  });

  // GET /api/sippy/recording-download/:callId — redirect to real audio file on recording server
  // Reads recordingServerUrl from settings. If configured, redirects to:
  //   {recordingServerUrl}/calls/{callId}.wav
  // If not configured, returns JSON { configured: false }.
  app.get('/api/sippy/recording-download/:callId', (req: any, res, next) => requireRole(['admin', 'management', 'viewer', 'noc_operator', 'team_lead', 'super_admin'], req, res, next), async (req: any, res: any) => {
    try {
      const { callId } = req.params;
      const settings = await storage.getSettings();
      const recUrl = (settings as any).recordingServerUrl?.trim();
      if (!recUrl) {
        return res.json({ configured: false, message: 'No recording server URL configured. Add one in Settings → Call Recordings.' });
      }
      const base = recUrl.replace(/\/+$/, '');
      const fileUrl = `${base}/calls/${encodeURIComponent(callId)}.wav`;
      res.redirect(302, fileUrl);
    } catch (e: any) { res.status(500).json({ configured: false, error: e.message }); }
  });

  // GET /api/sippy/recording-config — return recording server URL status (configured/not)
  app.get('/api/sippy/recording-config', (req: any, res, next) => requireRole(['admin', 'management', 'viewer', 'noc_operator', 'team_lead', 'super_admin'], req, res, next), async (_req: any, res: any) => {
    try {
      const settings = await storage.getSettings();
      const recUrl = (settings as any).recordingServerUrl?.trim() || null;
      res.json({ configured: !!recUrl, url: recUrl ?? null });
    } catch (e: any) { res.status(500).json({ configured: false, error: e.message }); }
  });

  // PATCH /api/sippy/recording-config — save recording server URL
  app.patch('/api/sippy/recording-config', (req: any, res, next) => requireRole(['admin'], req, res, next), async (req: any, res: any) => {
    try {
      const { url } = req.body ?? {};
      await storage.updateSettings({ recordingServerUrl: url?.trim() || null } as any);
      res.json({ ok: true });
    } catch (e: any) { res.status(500).json({ ok: false, error: e.message }); }
  });

  // GET /api/sippy/recordings — CDR-backed recording list (last 72 h, answered calls)
  // Sippy does not expose a recordings XML-RPC API, so this derives the list from the
  // in-memory CDR cache (only CDRs with duration > 0 = calls that actually connected).
  // Status = "available" when a recording server URL is configured and duration > 0.
  app.get('/api/sippy/recordings', (req: any, res: any, next: any) => requireRole(['admin', 'management', 'noc_operator', 'team_lead', 'super_admin', 'viewer'], req, res, next), async (_req: any, res: any) => {
    try {
      const settings   = await storage.getSettings();
      const recUrl     = (settings as any).recordingServerUrl?.trim() || null;
      const now        = Date.now();
      const cutoff72h  = now - 72 * 3_600_000;
      const cutoff90d  = now - 90 * 24 * 3_600_000;

      const raw = [...cdrCache.values()]
        .filter((c: any) => {
          const ts = sippy.parseSippyDate(c.startTime)?.getTime() ?? 0;
          return ts >= cutoff72h;
        })
        .sort((a: any, b: any) => {
          const ta = sippy.parseSippyDate(a.startTime)?.getTime() ?? 0;
          const tb = sippy.parseSippyDate(b.startTime)?.getTime() ?? 0;
          return tb - ta;
        })
        .slice(0, 500);

      const recordings = raw.map((c: any) => {
        const ts  = sippy.parseSippyDate(c.startTime)?.getTime() ?? 0;
        const dur = Number(c.duration ?? c.billDuration ?? 0);
        const codec = (c.codec ?? 'G.711').replace(/['"]/g, '').trim() || 'G.711';

        // Estimate file size (bytes): G.729≈1KB/s, Opus≈6KB/s, G.711≈8KB/s
        const kbps     = codec.includes('729') ? 8 : codec.toLowerCase().includes('opus') ? 48 : 64;
        const sizeKb   = dur > 0 ? Math.round(dur * kbps / 8) : 0;
        const fileSizeStr = sizeKb === 0 ? '—'
          : sizeKb < 1024 ? `${sizeKb} KB`
          : `${(sizeKb / 1024).toFixed(1)} MB`;

        const retainUntil = ts ? new Date(ts + 90 * 24 * 3_600_000).toISOString().slice(0, 10) : '—';
        const isExpired   = ts > 0 && ts < cutoff90d;
        const status: 'available' | 'processing' | 'expired' =
          isExpired           ? 'expired'    :
          dur === 0           ? 'processing' :
          recUrl              ? 'available'  : 'available';

        const callId = c.callId && !String(c.callId).startsWith('portal-cdr-') && !String(c.callId).startsWith('admin-cdr-')
          ? String(c.callId)
          : String(c.iCdr ?? c.iCall ?? `cdr-${ts}`);

        const clientName = c.clientName ?? accountNameCache.get(String(c.iAccount ?? '')) ?? null;

        return {
          id:          `rec-${callId}`,
          callId,
          direction:   (c.direction ?? (clientName ? 'outbound' : 'inbound')) as 'inbound' | 'outbound',
          caller:      (c.caller ?? c.cli ?? '—').toString(),
          callee:      (c.callee ?? c.cld ?? '—').toString(),
          startTime:   c.startTime ?? new Date(ts).toISOString(),
          duration:    dur,
          fileSize:    fileSizeStr,
          codec,
          encrypted:   true,
          retainUntil,
          status,
          clientName,
          vendor:      c.vendor ?? null,
          cost:        Number(c.cost ?? 0),
        };
      });

      res.json({ recordings, configured: !!recUrl, url: recUrl });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // GET /api/sippy/recording-status — probe Sippy for call recording configuration
  // Uses getSystemConfig XML-RPC to check if recording is enabled at system level.
  app.get('/api/sippy/recording-status', (req: any, res, next) => requireRole(['management'], req, res, next), async (_req, res) => {
    try {
      const settings = await storage.getSettings();
      if (!settings?.apiAdminUsername || !settings?.apiAdminPassword) {
        return res.json({ enabled: false, status: 'no_credentials', message: 'Sippy credentials not configured.' });
      }
      const apiUrl = sippyPortalUrl(settings);
      const username = settings.apiAdminUsername;
      const password = settings.apiAdminPassword;

      const result = await sippy.getSystemConfig(username, password, { portalUrl: apiUrl });
      if (!result.success) {
        return res.json({ enabled: false, status: 'api_error', message: result.message });
      }

      // Look for call_recording or record_calls keys in the system config
      const recordingKeys = ['call_recording', 'record_calls', 'recording_enabled',
        'enable_recording', 'voice_recording', 'call_record'];
      let recordingEntry: { key: string; currentValue: string | null } | null = null;
      for (const entry of result.config) {
        if (entry.key && recordingKeys.some(k => entry.key!.toLowerCase().includes(k.replace('_', '')))) {
          recordingEntry = entry;
          break;
        }
      }

      if (!recordingEntry) {
        // Key not found — recording is likely NOT configured at system level
        return res.json({
          enabled: false,
          status: 'not_configured',
          message: 'No call recording configuration key found in Sippy system config. Recording is likely not enabled on this switch.',
          configKeysScanned: result.config.length,
        });
      }

      const val = (recordingEntry.currentValue ?? '').toLowerCase();
      const enabled = val === '1' || val === 'yes' || val === 'true' || val === 'enabled';
      res.json({
        enabled,
        status: enabled ? 'active' : 'disabled',
        configKey: recordingEntry.key,
        configValue: recordingEntry.currentValue,
        message: enabled
          ? `Call recording is ACTIVE on this switch (${recordingEntry.key}=${recordingEntry.currentValue})`
          : `Call recording key found but is disabled (${recordingEntry.key}=${recordingEntry.currentValue})`,
      });
    } catch (e: any) { res.status(500).json({ enabled: false, status: 'error', message: e.message }); }
  });

  // ── CDR ENRICHMENT ENDPOINT ───────────────────────────────────────────────
  // POST /api/enrich-cdr — enriches a batch of CDR records with country, trunk class, FAS, etc.
  // Used by the frontend to enhance CDR data from Sippy/VOS3000

  app.post('/api/enrich-cdr', async (req, res) => {
    try {
      const settings = await storage.getSettings();
      const cdrs: any[] = req.body.cdrs ?? [];
      const fasMinPdd          = settings.fasMinPddSecs ?? 10;
      const fasMaxBill         = settings.fasMaxBillSecs ?? 5;
      const fasEarlyAnswerSecs = settings.fasEarlyAnswerSecs ?? 2;
      const fasShortCallSecs   = settings.fasShortCallSecs ?? 10;

      const enriched = cdrs.map(cdr => {
        const result = enrichCdr({
          caller: cdr.caller ?? cdr.cli ?? '',
          callee: cdr.callee ?? cdr.cld ?? '',
          accountId: cdr.accountId ?? cdr.iAccount ?? cdr.i_account ?? null,
          sipCode: cdr.sipCode ?? cdr.disconnect_code ?? null,
          pddSecs: cdr.pdd ?? null,
          billSecs: cdr.billSecs ?? cdr.billed_duration ?? null,
          fasMinPddSecs: fasMinPdd,
          fasMaxBillSecs: fasMaxBill,
          fasEarlyAnswerSecs,
          fasShortCallSecs,
        });
        return { ...cdr, ...result };
      });

      // Record any new FAS detections
      for (const cdr of enriched) {
        if (cdr.isFas && cdr.callId) {
          try {
            const event = await storage.createFasEvent({
              callId: String(cdr.callId ?? cdr.call_id ?? cdr.id ?? ''),
              caller: cdr.caller ?? cdr.cli ?? '',
              callee: cdr.callee ?? cdr.cld ?? '',
              vendor: cdr.vendor ?? '',
              pddSecs: cdr.pddSecs ?? null,
              billSecs: cdr.billSecs ?? null,
              sipCode: cdr.sipCode ?? null,
              reason: cdr.fasReason ?? '',
              fraudScore: cdr.fraudScore ?? null,
              alertSent: false,
            });
            // Fire email alert (non-blocking)
            const emailPayload = emailSvc.buildFasAlertEmail({
              callId: event.callId,
              caller: event.caller ?? '',
              callee: event.callee ?? '',
              vendor: event.vendor ?? '',
              pddSecs: event.pddSecs ?? 0,
              billSecs: event.billSecs ?? 0,
              reason: event.reason ?? '',
            });
            emailSvc.sendAlertEmail(emailPayload).then(sent => {
              if (sent) storage.markFasAlertSent(event.id);
            });
            // WhatsApp alert (non-blocking)
            waSvc.sendWhatsAppAlert('fas', waSvc.formatFasAlert({
              callId: event.callId, caller: event.caller ?? '', callee: event.callee ?? '',
              vendor: event.vendor ?? '', pddSecs: event.pddSecs ?? 0,
              billSecs: event.billSecs ?? 0, reason: event.reason ?? '',
            })).catch(() => {});
          } catch {
            // skip duplicate
          }
        }
      }

      res.json({ enriched });
    } catch (e: any) { res.status(500).json({ enriched: [], error: e.message }); }
  });

  // GET /api/sippy/accounts/:id/info — retrieve all attributes of an account (docs 107327)
  // Query: accountUsername (lookup by username instead of i_account), iCustomer (trusted mode, 2024+)
  app.get('/api/sippy/accounts/:id/info', async (req: any, res) => {
    try {
      const iAccount = parseInt(req.params.id, 10);
      if (isNaN(iAccount)) return res.status(400).json({ error: 'Invalid i_account.' });
      const settings = await storage.getSettings();
      const { username, password } = sippyXmlCreds(settings);
      const iCustomer = req.query.iCustomer ? parseInt(req.query.iCustomer as string, 10) : undefined;
      const info = await sippy.getAccountInfo(username, password, sippyPortalUrl(settings), iAccount, undefined, iCustomer);
      if (!info) return res.status(404).json({ error: 'Account not found or Sippy returned a fault.' });
      res.json(info);
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // ── ACCOUNT MONITORING — balance alerts ───────────────────────────────────
  // POST /api/sippy/accounts/:id/check-balance — explicitly check & alert on low balance
  app.post('/api/sippy/accounts/:id/check-balance', async (req: any, res) => {
    try {
      const iAccount = Number(req.params.id);
      const settings = await storage.getSettings();
      const { username, password } = sippyXmlCreds(settings);
      const info = await sippy.getAccountInfo(username, password, sippyPortalUrl(settings), iAccount);
      const balance = info?.balance ?? 0;
      const creditLimit = info?.creditLimit ?? 0;   // camelCase (was credit_limit)
      const threshold = settings.balanceAlertThreshold ?? 10;
      const accountName = info?.name ?? `Account #${iAccount}`;

      const isLow = balance < threshold;
      if (isLow) {
        const emailPayload = emailSvc.buildBalanceAlertEmail({ accountName, balance, creditLimit, threshold });
        const profiles = await storage.getClientProfiles();
        const match = profiles.find(p => p.name?.toLowerCase() === accountName?.toLowerCase());
        await emailSvc.sendAlertEmail({ ...emailPayload, clientEmail: match?.alertEmail });
        // WhatsApp alert (non-blocking)
        waSvc.sendWhatsAppAlert('balance', waSvc.formatBalanceAlert({ accountName, balance, creditLimit, threshold })).catch(() => {});
      }
      res.json({ ok: true, balance, creditLimit, isLow, accountName });
    } catch (e: any) { res.status(500).json({ ok: false, error: e.message }); }
  });

