  // NOTE: GET /api/sippy/routing-groups (listSippyRoutingGroups discovery helper) already
  // registered above at line ~1486. The routes below implement the full official CRUD.

  // GET /api/sippy/routing-groups/list — listRoutingGroups() with full filter support
  // Query: namePattern, namePatternNot, iRoutingGroup, includeMembersCount
  app.get('/api/sippy/routing-groups/list', async (req: any, res) => {
    try {
      const settings = await storage.getSippySettings();
      if (!settings) return res.status(503).json({ success: false, error: 'Sippy not configured.' });
      const { username, password } = sippyXmlCreds(settings);
      const { namePattern, namePatternNot, iRoutingGroup, includeMembersCount } = req.query as any;
      const result = await sippy.listRoutingGroups(username, password, {
        namePattern:         namePattern        || undefined,
        namePatternNot:      namePatternNot     || undefined,
        iRoutingGroup:       iRoutingGroup      ? parseInt(iRoutingGroup, 10) : undefined,
        includeMembersCount: includeMembersCount ? includeMembersCount === 'true' : undefined,
        portalUrl: sippyPortalUrl(settings),
      });
      if (!result.success) return res.status(422).json({ success: false, error: result.message });
      res.json(result);
    } catch (e: any) { res.status(500).json({ success: false, error: e.message }); }
  });

  // POST /api/sippy/routing-groups — addRoutingGroup() [direct — no approval]
  app.post('/api/sippy/routing-groups', async (req: any, res) => {
    try {
      const userId = req.user?.claims?.sub;
      if (!userId) return res.status(401).json({ success: false, error: 'Unauthorized' });
      const settings = await storage.getSippySettings();
      if (!settings) return res.status(503).json({ success: false, error: 'Sippy not configured.' });
      const { username, password } = sippyXmlCreds(settings);
      const { name, policy, description, timeout_2xx, lrn_enabled, lrn_translation_rule } = req.body ?? {};
      if (!name)   return res.status(400).json({ success: false, error: 'name is required.' });
      if (!policy && policy !== 0) return res.status(400).json({ success: false, error: 'policy is required.' });
      const result = await sippy.addRoutingGroup(username, password, name, policy, {
        description:        description         || undefined,
        timeout2xx:         timeout_2xx         ? parseInt(timeout_2xx, 10) : undefined,
        lrnEnabled:         !!lrn_enabled,
        lrnTranslationRule: lrn_translation_rule || undefined,
        portalUrl:          sippyPortalUrl(settings),
      });
      if (!result.success) return res.status(422).json({ success: false, error: result.message });
      res.json({ success: true, iRoutingGroup: result.iRoutingGroup });
    } catch (e: any) { res.status(500).json({ success: false, error: e.message }); }
  });

  // ── Routing Cache API ────────────────────────────────────────────────────────
  // GET /api/routing-cache/status — sync metadata + item counts
  app.get('/api/routing-cache/status', (req: any, res: any, next: any) => requireRole(['admin', 'management'], req, res, next), async (_req, res) => {
    try {
      const meta = await getRoutingCacheMeta();
      res.json(meta ?? { last_sync_status: 'pending', rg_count: 0, ds_count: 0, conn_count: 0 });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // GET /api/routing-cache/routing-groups — cached routing groups
  app.get('/api/routing-cache/routing-groups', (req: any, res: any, next: any) => requireRole(['admin', 'management'], req, res, next), async (_req, res) => {
    try {
      const groups = await getCachedRoutingGroups();
      res.json({ groups });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // GET /api/routing-cache/destination-sets — cached destination sets
  app.get('/api/routing-cache/destination-sets', (req: any, res: any, next: any) => requireRole(['admin', 'management'], req, res, next), async (_req, res) => {
    try {
      const sets = await getCachedDestinationSets();
      res.json({ sets });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // GET /api/routing-cache/connections — cached connections
  app.get('/api/routing-cache/connections', (req: any, res: any, next: any) => requireRole(['admin', 'management'], req, res, next), async (_req, res) => {
    try {
      const connections = await getCachedConnections();
      res.json({ connections });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // POST /api/routing-cache/sync — force immediate re-sync (admin + management)
  app.post('/api/routing-cache/sync', (req: any, res: any, next: any) => requireRole(['admin', 'management'], req, res, next), async (_req, res) => {
    try {
      const result = await syncRoutingCache(true);
      res.json(result);
    } catch (e: any) { res.status(500).json({ ok: false, message: e.message }); }
  });

  // GET /api/routing-cache/routing-groups/:id/detail — live members enriched with cached connection/DS names
  app.get('/api/routing-cache/routing-groups/:id/detail',
    (req: any, res: any, next: any) => requireRole(['admin','management'], req, res, next),
    async (req: any, res: any) => {
      try {
        const id = parseInt(req.params.id, 10);
        if (isNaN(id)) return res.status(400).json({ error: 'Invalid routing group ID' });
        const settings = await storage.getSippySettings();
        if (!settings) return res.status(503).json({ error: 'Sippy not configured' });
        const { username, password } = sippyXmlCreds(settings);
        // Fetch live members from Sippy
        const mResult = await sippy.listRoutingGroupMembers(username, password, id, { portalUrl: sippyPortalUrl(settings) });
        // Enrich with cached connection info
        const cachedConns  = await getCachedConnections();
        const connMap = new Map((cachedConns as any[]).map((c: any) => [c.i_connection, c]));
        // Enrich with cached destination set names
        const cachedDSets  = await getCachedDestinationSets();
        const dsMap   = new Map((cachedDSets as any[]).map((d: any) => [d.i_destination_set, d]));
        const members = (mResult.members ?? []).map((m: any) => {
          const conn = m.iConnection    ? (connMap.get(m.iConnection) as any)    : null;
          const ds   = m.iDestinationSet ? (dsMap.get(m.iDestinationSet) as any) : null;
          return {
            iRoutingGroupMember: m.iRoutingGroupMember,
            iConnection:         m.iConnection,
            iConnectionGroup:    m.iConnectionGroup,
            iDestinationSet:     m.iDestinationSet,
            preference:          m.preference,
            weight:              m.weight,
            activationDate:      m.activationDate,
            expirationDate:      m.expirationDate,
            connectionName:      conn?.name       ?? (m.iConnection      ? `Connection #${m.iConnection}`       : null),
            vendorName:          conn?.vendor_name ?? null,
            blocked:             conn?.blocked     ?? false,
            host:                conn?.host        ?? null,
            destSetName:         ds?.name          ?? (m.iDestinationSet  ? `DS #${m.iDestinationSet}`           : null),
            destSetRouteCount:   ds?.route_count   ?? null,
          };
        });
        res.json({ members, ok: mResult.success, message: mResult.message });
      } catch (e: any) {
        res.status(500).json({ error: e.message });
      }
    }
  );

  // ── Routing Impact Simulator ─────────────────────────────────────────────
  // GET /api/routing-simulator/preview — read-only, on-demand, no Sippy writes.
  // For each routing group: baseline weighted CI health + per-entry removal simulations.
  app.get('/api/routing-simulator/preview', (req: any, res: any, next: any) => requireRole(['admin', 'management', 'noc_operator', 'viewer', 'team_lead', 'super_admin'], req, res, next), async (req: any, res: any) => {
    try {
      const settings        = await storage.getSettings();
      const sippySettings   = await storage.getSippySettings();
      if (!sippySettings) return res.status(503).json({ message: 'Sippy not configured' });
      const { username: sippyUser, password: sippyPass } = sippyXmlCreds(sippySettings);
      const portalUrl       = sippyPortalUrl(sippySettings);

      // ── 1. CI data (same pipeline as /api/carrier-intelligence) ───────────
      const period = 90;
      let baseRows: Array<{ name: string; totalCalls: number; acdSec: number; asr: number; avgPdd: number; billableCalls: number; durationSec: number; amount: number }> = [];
      try {
        const portal = await sippy.getSippyPerAccountStats(
          settings?.portalUsername ?? '', settings?.portalPassword ?? '', period,
          settings?.apiAdminUsername ?? '', settings?.apiAdminPassword ?? '',
        );
        if (portal.ok && portal.vendors.some((v: any) => v.totalCalls > 0))
          baseRows = portal.vendors.map((v: any) => ({ name: v.name, totalCalls: v.totalCalls, billableCalls: v.billableCalls, durationSec: v.durationSec, acdSec: v.acdSec, asr: v.asr, avgPdd: v.avgPdd, amount: v.amount }));
      } catch { /* fall through */ }

      function computeCI(r: { asr: number; acdSec: number; avgPdd: number; totalCalls: number }) {
        if (r.totalCalls === 0) return { healthScore: 0, state: 'UNSCORED', confidence: 'NONE', asr: 0 };
        const conf = Math.min(1, Math.log10(r.totalCalls + 1) / 2);
        const hs   = Math.max(0, Math.min(100, Math.round((Math.min(100, (r.asr / 50) * 100) * 0.35) + (Math.min(100, (Math.min(r.acdSec, 120) / 120) * 100) * 0.30) + (Math.max(0, 100 - (r.avgPdd / 10) * 100) * 0.15) + (conf * 10 * 0.20))));
        const fas  = (r.asr > 55 && r.acdSec > 0 && r.acdSec < 30) ? 'CRITICAL' : (r.asr > 45 && r.acdSec > 0 && r.acdSec < 45) ? 'MEDIUM' : null;
        const state = fas ? 'FAS_RISK' : (r.totalCalls >= 10 && r.asr === 0) ? 'CRITICAL' : hs >= 70 ? 'HEALTHY' : hs >= 55 ? 'STABLE' : hs >= 35 ? 'DEGRADED' : 'CRITICAL';
        return { healthScore: hs, state, confidence: r.totalCalls >= 100 ? 'HIGH' : r.totalCalls >= 20 ? 'MEDIUM' : 'LOW', asr: r.asr };
      }
      const ciMap = new Map<string, ReturnType<typeof computeCI>>();
      for (const r of baseRows) ciMap.set(r.name.toLowerCase().replace(/\(.*?\)/g, '').replace(/[^a-z0-9]/g, ''), { ...computeCI(r) });

      function lookupCI(connName: string) {
        const ck = connName.toLowerCase().replace(/\(.*?\)/g, '').replace(/[^a-z0-9]/g, '');
        for (const [k, v] of ciMap.entries()) { if (k === ck || k.includes(ck) || (ck.length >= 5 && ck.includes(k))) return v; }
        return null;
      }

      // ── 2. AI Ops events (48h) ─────────────────────────────────────────────
      const { db }          = await import('./db');
      const { aiOpsEvents } = await import('../shared/schema');
      const { gte: gteOp, desc: descOp } = await import('drizzle-orm');
      const events = await db.select().from(aiOpsEvents).where(gteOp(aiOpsEvents.createdAt, new Date(Date.now() - 48 * 60 * 60 * 1000))).orderBy(descOp(aiOpsEvents.createdAt));

      function getAiOpsSignal(connName: string): 'YES' | 'PARTIAL' | 'NONE' {
        const ck = connName.toLowerCase().replace(/[^a-z0-9]/g, '');
        if (ck.length < 3) return 'NONE';
        const matched = events.filter(e => { if (!e.entity) return false; const ek = e.entity.toLowerCase().replace(/^carrier:/, '').replace(/[^a-z0-9]/g, ''); return ek.length >= 3 && (ek.includes(ck) || ck.includes(ek) || (ck.length >= 6 && ek.includes(ck.slice(0, 6)))); });
        if (matched.length === 0) return 'NONE';
        return matched.some(e => e.severity === 'high' || e.severity === 'critical') ? 'YES' : 'PARTIAL';
      }

      // ── 3. Routing groups + per-group member enrichment + simulation ───────
      const cachedConns  = await getCachedConnections();
      const connMap      = new Map((cachedConns as any[]).map((c: any) => [c.i_connection, c]));
      const cachedGroups = await getCachedRoutingGroups() as any[];
      const result       = [];

      for (const grp of cachedGroups) {
        let rawMembers: any[] = [];
        try {
          const mResult = await sippy.listRoutingGroupMembers(sippyUser, sippyPass, grp.i_routing_group, { portalUrl });
          rawMembers = mResult.members ?? [];
        } catch { rawMembers = []; }

        const allCount    = rawMembers.length;
        const activeRaw   = rawMembers.filter((m: any) => !connMap.get(m.iConnection)?.blocked);

        const entries = activeRaw.map((m: any) => {
          const conn     = m.iConnection ? (connMap.get(m.iConnection) as any) : null;
          const connName = conn?.name ?? (m.iConnection ? `Connection #${m.iConnection}` : 'Unknown');
          const weight   = Math.max(1, m.weight ?? 1);
          return { connectionName: connName, vendorName: conn?.vendor_name ?? null, weight, preference: m.preference ?? 1, ciHealth: lookupCI(connName), aiOpsSignal: getAiOpsSignal(connName) };
        });

        const totalWeight  = entries.reduce((s: number, e: any) => s + e.weight, 0) || 1;
        const baselineHS   = Math.round(entries.reduce((s: number, e: any) => s + (e.weight / totalWeight) * (e.ciHealth?.healthScore ?? 50), 0));
        const baselineRisk = baselineHS >= 75 ? 'LOW' : baselineHS >= 55 ? 'MEDIUM' : baselineHS >= 35 ? 'HIGH' : 'CRITICAL';

        const simulations = entries.map((removed: any) => {
          const rest = entries.filter((e: any) => e.connectionName !== removed.connectionName);
          const rw   = rest.reduce((s: number, e: any) => s + e.weight, 0) || 1;
          const proj = Math.round(rest.reduce((s: number, e: any) => s + (e.weight / rw) * (e.ciHealth?.healthScore ?? 50), 0));
          const delta = proj - baselineHS;
          const floorDist = (raw: number[]) => { const fl = raw.map(Math.floor); const rem = 100 - fl.reduce((s, v) => s + v, 0); const mi = raw.reduce((best, v, i) => (v % 1) > (raw[best] % 1) ? i : best, 0); return fl.map((v, i) => i === mi ? v + Math.max(0, rem) : v); };
          const newPcts = floorDist(rest.map((e: any) => (e.weight / rw) * 100));
          const oldPcts = floorDist(rest.map((e: any) => (e.weight / totalWeight) * 100));
          const trafficRedistribution = rest.map((e: any, i: number) => ({ connectionName: e.connectionName, newContributionPct: newPcts[i], oldContributionPct: oldPcts[i] }));
          return { removedEntry: removed.connectionName, projectedHealthScore: proj, delta, riskDelta: delta > 5 ? 'IMPROVES' : delta < -5 ? 'WORSENS' : 'NEUTRAL', trafficRedistribution };
        }).sort((a: any, b: any) => Math.abs(b.delta) - Math.abs(a.delta));

        result.push({ groupId: grp.i_routing_group, groupName: grp.name, policy: grp.policy ?? null, baseline: { healthScore: baselineHS, riskLevel: baselineRisk, entriesCount: allCount, activeEntriesCount: entries.length }, entries: entries.map((e: any) => ({ connectionName: e.connectionName, vendorName: e.vendorName, weight: e.weight, preference: e.preference, contributionPct: Math.round((e.weight / totalWeight) * 100), ciHealth: e.ciHealth ? { healthScore: e.ciHealth.healthScore, state: e.ciHealth.state, confidence: e.ciHealth.confidence, asr: e.ciHealth.asr } : null, aiOpsSignal: e.aiOpsSignal })), simulations });
      }

      res.json({ groups: result, computedAt: new Date().toISOString(), ciConnections: ciMap.size });
    } catch (e: any) { res.status(500).json({ message: e.message }); }
  });

  // ── Connection Coverage Map ───────────────────────────────────────────────
  // GET /api/coverage/matrix — Connection × Destination-Set coverage matrix
  // Fetches live RG members from Sippy (parallel), cross-references cached
  // connections and DS, and returns gap analysis (unused conns, orphan DS,
  // redundancy gaps where a DS is served by only one connection).
  app.get('/api/coverage/matrix',
    (req: any, res: any, next: any) => requireRole(['admin', 'management'], req, res, next),
    async (_req: any, res: any) => {
      try {
        const t0 = Date.now();
        const settings = await storage.getSippySettings();
        if (!settings) return res.status(503).json({ error: 'Sippy not configured' });
        const { username, password } = sippyXmlCreds(settings);
        const pUrl = sippyPortalUrl(settings);

        // Load all cached data in parallel
        const [cachedRGs, cachedDSets, cachedConns] = await Promise.all([
          getCachedRoutingGroups(),
          getCachedDestinationSets(),
          getCachedConnections(),
        ]);

        // Fetch live members for every RG (parallel, best-effort)
        type MemberLink = { iConnection: number; iDestinationSet: number | null; preference: number | null; weight: number | null; rgName: string; iRg: number };
        const links: MemberLink[] = [];

        const memberResults = await Promise.allSettled(
          (cachedRGs as any[]).map(async (rg: any) => {
            const result = await sippy.listRoutingGroupMembers(
              username, password, rg.i_routing_group,
              { portalUrl: pUrl }
            );
            for (const m of result.members ?? []) {
              if (!m.iConnection) continue;
              links.push({
                iConnection:     m.iConnection,
                iDestinationSet: m.iDestinationSet ?? null,
                preference:      m.preference ?? null,
                weight:          m.weight ?? null,
                rgName:          rg.name ?? `RG#${rg.i_routing_group}`,
                iRg:             rg.i_routing_group,
              });
            }
          })
        );

        const failedRGs = memberResults.filter(r => r.status === 'rejected').length;

        // Build lookup maps: iConnection → {iDS, rgName}[] and iDS → {iConnection, connName}[]
        type DSRef  = { iDS: number; dsName: string; routeCount: number; rgName: string; iRg: number; preference: number | null };
        type ConnRef = { iConnection: number; connName: string; vendorName: string; preference: number | null; rgName: string };

        const connToDSets  = new Map<number, DSRef[]>();
        const dSetToConns  = new Map<number, ConnRef[]>();

        const connMap = new Map((cachedConns as any[]).map((c: any) => [c.i_connection, c]));
        const dsMap   = new Map((cachedDSets as any[]).map((d: any) => [d.i_destination_set, d]));

        for (const link of links) {
          if (!link.iConnection || !link.iDestinationSet) continue;
          const ds   = dsMap.get(link.iDestinationSet);
          const conn = connMap.get(link.iConnection);
          if (!ds || !conn) continue;

          // conn → DS
          if (!connToDSets.has(link.iConnection)) connToDSets.set(link.iConnection, []);
          const existing = connToDSets.get(link.iConnection)!;
          if (!existing.some(e => e.iDS === link.iDestinationSet && e.iRg === link.iRg)) {
            existing.push({ iDS: link.iDestinationSet, dsName: ds.name, routeCount: ds.route_count ?? 0, rgName: link.rgName, iRg: link.iRg, preference: link.preference });
          }

          // DS → conn
          if (!dSetToConns.has(link.iDestinationSet)) dSetToConns.set(link.iDestinationSet, []);
          const existing2 = dSetToConns.get(link.iDestinationSet)!;
          if (!existing2.some(e => e.iConnection === link.iConnection && e.rgName === link.rgName)) {
            existing2.push({ iConnection: link.iConnection, connName: conn.name, vendorName: conn.vendor_name, preference: link.preference, rgName: link.rgName });
          }
        }

        // Build enriched connection list
        const connections = (cachedConns as any[]).map((c: any) => ({
          iConnection: c.i_connection,
          name:        c.name,
          vendorName:  c.vendor_name ?? null,
          host:        c.host ?? null,
          protocol:    c.protocol ?? null,
          blocked:     c.blocked ?? false,
          coveredDSets: connToDSets.get(c.i_connection) ?? [],
        }));

        // Build enriched DS list
        const destinationSets = (cachedDSets as any[]).map((d: any) => ({
          iDS:                 d.i_destination_set,
          name:                d.name,
          routeCount:          d.route_count ?? 0,
          cldTranslation:      d.cld_translation ?? null,
          connectedConnections: dSetToConns.get(d.i_destination_set) ?? [],
        }));

        // Gaps
        const unusedConnections     = connections.filter(c => c.coveredDSets.length === 0);
        const orphanDSets           = destinationSets.filter(d => d.connectedConnections.length === 0);
        const singleCoveredDSets    = destinationSets.filter(d => d.connectedConnections.length === 1);

        res.json({
          connections,
          destinationSets,
          gaps: { unusedConnections, orphanDSets, singleCoveredDSets },
          rgCount:    cachedRGs.length,
          failedRGs,
          buildTimeMs: Date.now() - t0,
        });
      } catch (e: any) { res.status(500).json({ error: e.message }); }
    }
  );

  // ── QBR Dashboard ─────────────────────────────────────────────────────────
  // GET /api/qbr/metrics?hours=N — per-vendor quality metrics from CDR cache
  // Computes ASR, ACD, PDD and a composite QBR score per vendor/connection.
  app.get('/api/qbr/metrics',
    (req: any, res: any, next: any) => requireRole(['admin', 'management'], req, res, next),
    async (req: any, res: any) => {
      try {
        const hours = Math.min(Math.max(parseInt(String(req.query.hours ?? '24')) || 24, 1), 168);
        const cutoff = Date.now() - hours * 3600 * 1000;

        // Enrich from connection cache (vendor name / host / protocol)
        const cachedConns = await getCachedConnections();

        // ── Primary: Sippy portal (authoritative — full traffic volume) ──────────
        try {
          const settings   = await storage.getSettings();
          const portalUser = settings.portalUsername   || settings.apiAdminUsername || '';
          const portalPass = settings.portalPassword   || settings.apiAdminPassword || '';
          const adminUser  = settings.apiAdminUsername || '';
          const adminPass  = settings.apiAdminPassword || '';
          const toDate     = new Date();
          const fromDate   = new Date(toDate.getTime() - hours * 3600 * 1000);

          const portalResult = await sippy.getSippyPerAccountStats(
            portalUser, portalPass, hours * 60,
            adminUser, adminPass,
            fromDate, toDate,
          );

          if (portalResult.ok && portalResult.vendors.length > 0) {
            const vendors = portalResult.vendors.map(r => {
              const conn = (cachedConns as any[]).find(
                (c: any) => (c.vendorName ?? c.name ?? '').toLowerCase() === r.name.toLowerCase()
              );
              const asr   = r.asr;
              const acd   = r.acdSec;
              const pddMs = r.avgPdd * 1000;   // portal returns seconds; formula uses ms
              const asrS  = Math.min(asr, 100);
              const acdS  = Math.min(acd / 120 * 100, 100);
              const pddS  = Math.max(0, 100 - (pddMs / 4000 * 100));
              const qbr   = Math.round((asrS * 0.40 + acdS * 0.30 + pddS * 0.30) * 10) / 10;
              const status: 'excellent' | 'good' | 'degraded' | 'critical' =
                qbr >= 80 ? 'excellent' : qbr >= 60 ? 'good' : qbr >= 40 ? 'degraded' : 'critical';
              return {
                vendor: r.name, connectionName: conn?.name, host: conn?.host,
                protocol: conn?.protocol, blocked: conn?.blocked ?? false,
                totalCalls: r.totalCalls, answeredCalls: r.billableCalls,
                asr, acd, pdd: pddMs, qbrScore: qbr, status,
                totalMinutes: Math.round(r.durationSec / 60 * 10) / 10,
                totalCost: Math.round(r.amount * 100) / 100,
              };
            }).sort((a: any, b: any) => b.qbrScore - a.qbrScore);

            const totCalls    = vendors.reduce((s, v) => s + v.totalCalls, 0);
            const totAnswered = vendors.reduce((s, v) => s + v.answeredCalls, 0);
            const netAsr      = totCalls > 0 ? Math.round(totAnswered / totCalls * 1000) / 10 : 0;
            const wAcd        = totAnswered > 0
              ? Math.round(vendors.reduce((s, v) => s + v.acd * v.answeredCalls, 0) / totAnswered * 10) / 10 : 0;
            const pddSets     = vendors.filter(v => v.pdd > 0);
            const netPdd      = pddSets.length > 0
              ? Math.round(pddSets.reduce((s, v) => s + v.pdd, 0) / pddSets.length * 10) / 10 : 0;

            return res.json({
              vendors,
              summary: {
                totalCalls: totCalls, answeredCalls: totAnswered,
                asr: netAsr, acd: wAcd, pdd: netPdd,
                activeRoutes: vendors.length,
                degradedRoutes: vendors.filter(v => v.status === 'degraded' || v.status === 'critical').length,
              },
              meta: { hours, source: 'portal', cdrsAnalyzed: portalResult.origTotal.totalCalls, updatedAt: new Date().toISOString() },
            });
          }
          console.warn('[qbr/metrics] Portal returned no vendor data — falling back to CDR cache');
        } catch (portalErr: any) {
          console.warn('[qbr/metrics] Portal error:', (portalErr as any).message, '— falling back to CDR cache');
        }

        // ── Fallback: CDR cache ─────────────────────────────────────────────────
        // Filter CDR cache to the requested time window
        const windowCdrs = [...cdrCache.values()].filter(c => {
          const ts = c.startTime  ? new Date(c.startTime).getTime()
                   : c.connectTime ? new Date(c.connectTime).getTime() : 0;
          return ts >= cutoff;
        });

        type VGroup = {
          vendor: string; connName?: string; host?: string; protocol?: string; blocked: boolean;
          total: number; answered: number; totalDur: number; totalPdd: number; pddN: number; totalCost: number;
        };
        const groups = new Map<string, VGroup>();

        for (const cdr of windowCdrs) {
          // Resolve vendor label
          let vendor = cdr.vendor;
          if (!vendor && cdr.iConnection) {
            const conn = (cachedConns as any[]).find(
              (c: any) => String(c.i_connection ?? c.iConnection) === String(cdr.iConnection)
            );
            vendor = conn?.vendorName ?? conn?.name;
          }
          vendor = vendor || 'Unknown';

          if (!groups.has(vendor)) {
            const conn = (cachedConns as any[]).find(
              (c: any) => c.vendorName === vendor || c.name === vendor
            );
            groups.set(vendor, {
              vendor, connName: conn?.name, host: conn?.host,
              protocol: conn?.protocol, blocked: conn?.blocked ?? false,
              total: 0, answered: 0, totalDur: 0, totalPdd: 0, pddN: 0, totalCost: 0,
            });
          }

          const g = groups.get(vendor)!;
          g.total++;
          const rc  = parseInt(String(cdr.result ?? '').trim()) || 0;
          const dur = cdr.totalDuration ?? cdr.duration ?? 0;
          if (rc === 0 && dur > 0) { g.answered++; g.totalDur += dur; }
          if (cdr.pdd != null && cdr.pdd >= 0) { g.totalPdd += cdr.pdd; g.pddN++; }
          g.totalCost += cdr.cost ?? 0;
        }

        // Compute per-vendor QBR metrics and score
        const vendors = [...groups.values()].map(g => {
          const asr = g.total > 0 ? Math.round(g.answered / g.total * 1000) / 10 : 0;
          const acd = g.answered > 0 ? Math.round(g.totalDur / g.answered * 10) / 10 : 0;
          const pdd = g.pddN > 0 ? Math.round(g.totalPdd / g.pddN * 10) / 10 : 0;

          // QBR composite score: 40% ASR + 30% ACD (capped 120 s) + 30% PDD (0-4000 ms inverted)
          const asrS = Math.min(asr, 100);
          const acdS = Math.min(acd / 120 * 100, 100);
          const pddS = Math.max(0, 100 - (pdd / 4000 * 100));
          const qbr  = Math.round((asrS * 0.40 + acdS * 0.30 + pddS * 0.30) * 10) / 10;

          const status: 'excellent' | 'good' | 'degraded' | 'critical' =
            qbr >= 80 ? 'excellent' : qbr >= 60 ? 'good' : qbr >= 40 ? 'degraded' : 'critical';

          return {
            vendor: g.vendor, connectionName: g.connName, host: g.host,
            protocol: g.protocol, blocked: g.blocked,
            totalCalls: g.total, answeredCalls: g.answered,
            asr, acd, pdd, qbrScore: qbr, status,
            totalMinutes: Math.round(g.totalDur / 60 * 10) / 10,
            totalCost: Math.round(g.totalCost * 100) / 100,
          };
        }).sort((a, b) => b.qbrScore - a.qbrScore);

        // Network-level summary
        const totCalls    = vendors.reduce((s, v) => s + v.totalCalls, 0);
        const totAnswered = vendors.reduce((s, v) => s + v.answeredCalls, 0);
        const netAsr      = totCalls > 0 ? Math.round(totAnswered / totCalls * 1000) / 10 : 0;
        const wAcd        = totAnswered > 0
          ? Math.round(vendors.reduce((s, v) => s + v.acd * v.answeredCalls, 0) / totAnswered * 10) / 10 : 0;
        const pddSets     = vendors.filter(v => v.pdd > 0);
        const netPdd      = pddSets.length > 0
          ? Math.round(pddSets.reduce((s, v) => s + v.pdd, 0) / pddSets.length * 10) / 10 : 0;

        res.json({
          vendors,
          summary: {
            totalCalls: totCalls, answeredCalls: totAnswered,
            asr: netAsr, acd: wAcd, pdd: netPdd,
            activeRoutes: vendors.length,
            degradedRoutes: vendors.filter(v => v.status === 'degraded' || v.status === 'critical').length,
          },
          meta: { hours, cdrsAnalyzed: windowCdrs.length, updatedAt: cdrCacheUpdatedAt },
        });
      } catch (e: any) { res.status(500).json({ error: e.message }); }
    }
  );

