  // PATCH /api/monitoring/alert-rules/:id
  app.patch('/api/monitoring/alert-rules/:id', async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      await storage.updateAlertRule(id, req.body);
      res.json({ ok: true });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // DELETE /api/monitoring/alert-rules/:id
  app.delete('/api/monitoring/alert-rules/:id', async (req, res) => {
    try {
      await storage.deleteAlertRule(parseInt(req.params.id));
      res.json({ ok: true });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // ── Boot-time caches + 30-min refresh ────────────────────────────────────────
  // Stagger the two fetches slightly so they don't hit the switch simultaneously.
  // Use a short delay so the DB is ready but still much faster than the previous 3s
  // which caused numeric account IDs to appear in live-call client name fields.
  setTimeout(() => refreshAccountCache(),           500);
  setTimeout(() => refreshConnectionVendorCache(),  1500);
  setInterval(() => refreshAccountCache(),          30 * 60 * 1000);
  setInterval(() => refreshConnectionVendorCache(), 30 * 60 * 1000);

  // ── Vendor balance tracker (every 60 s) ─────────────────────────────────────
  // Stores timestamped vendor balance snapshots for balance-delta vendor cost computation.
  setTimeout(() => refreshVendorBalances(), 9000);   // first snapshot ~9 s after boot
  setInterval(() => refreshVendorBalances(), 60_000); // then every 60 s

  // ── Call snapshot background poller (every 60 s) ──────────────────────────
  // Polls live Sippy calls and upserts each into call_snapshots for 24h history.
  // Interval increased 30s→60s to reduce Sippy load (still ample for live NOC).
  // ── Concurrent-call history buffer (for live graphs) ─────────────────────────
  // Stores {ts, count, calls[]} every 60s — max 48h of data (2880 points).
  const CONCURRENT_HISTORY_HOURS = 48;
  interface ConcurrentPoint {
    ts: number;
    count: number;
    connected: number;    // calls in Connected ccState
    routing: number;      // calls in routing/setup states (ARComplete, WaitRoute, etc.)
    byClient:      Record<string, number>;
    byVendor:      Record<string, number>;
    byCodec:       Record<string, number>;
    byDirection:   Record<string, number>;
    byDestination: Record<string, number>;
    byBreakout:    Record<string, number>;
    byCountry:     Record<string, number>;
  }
  const concurrentHistory: ConcurrentPoint[] = [];

  // Destination lookup uses the full 19,088-entry dial-codes.json (longest-match prefix)
  function calleeToCountry(callee: string): string {
    const m = lookupDialCode(callee);
    return m ? m.country : 'Unknown';
  }

  function calleeToBreakout(callee: string): string {
    const m = lookupDialCode(callee);
    return m ? m.breakout : 'Unknown';
  }

  function calleeToDestination(callee: string): string {
    const m = lookupDialCode(callee);
    return m ? m.destination : 'Unknown';
  }

  function pushConcurrentPoint(calls: Awaited<ReturnType<typeof sippy.getSippyActiveCalls>>) {
    const cutoff = Date.now() - CONCURRENT_HISTORY_HOURS * 3600 * 1000;
    // Evict old points
    while (concurrentHistory.length > 0 && concurrentHistory[0].ts < cutoff) concurrentHistory.shift();

    const byClient:      Record<string, number> = {};
    const byVendor:      Record<string, number> = {};
    const byCodec:       Record<string, number> = {};
    const byDirection:   Record<string, number> = {};
    const byDestination: Record<string, number> = {};
    const byBreakout:    Record<string, number> = {};
    const byCountry:     Record<string, number> = {};

    let connected = 0, routing = 0;

    for (const c of calls) {
      const rawId    = String(c.accountId ?? c.iCustomer ?? '').trim();
      const client   = c.user || accountNameCache.get(rawId) || (rawId && !/^\d+$/.test(rawId) ? rawId : 'Unknown');
      const vendor   = c.vendor || (c.connection ? connectionVendorCache.get(c.connection) : undefined) || 'Unknown';
      const codec    = (c.codec && c.codec !== '-') ? c.codec : 'Unknown';
      const dir      = c.direction || 'unknown';
      const match    = lookupDialCode(c.callee ?? '');
      const country  = match ? match.country  : 'Unknown';
      const breakout = match ? match.breakout : 'Unknown';
      const dest     = match ? match.destination : 'Unknown';
      byClient[client]           = (byClient[client]           || 0) + 1;
      byVendor[vendor]           = (byVendor[vendor]           || 0) + 1;
      byCodec[codec]             = (byCodec[codec]             || 0) + 1;
      byDirection[dir]           = (byDirection[dir]           || 0) + 1;
      byDestination[dest]        = (byDestination[dest]        || 0) + 1;
      byBreakout[breakout]       = (byBreakout[breakout]       || 0) + 1;
      byCountry[country]         = (byCountry[country]         || 0) + 1;
      // Track connected vs routing state
      if (c.status === 'Connected' || c.status?.toLowerCase().includes('connect')) connected++;
      else routing++;
    }

    concurrentHistory.push({ ts: Date.now(), count: calls.length, connected, routing, byClient, byVendor, byCodec, byDirection, byDestination, byBreakout, byCountry });

    // Notify watcher of any client names seen for the first time (new traffic alert)
    for (const clientName of Object.keys(byClient)) {
      if (clientName && clientName !== 'Unknown') {
        notifyNewClientTraffic(clientName);
      }
    }
  }

  // Per-entity concurrent history — keyed by dimension → entity name → snapshot array
  type EntSnap = { ts: number; count: number; connected: number; routing: number };
  const entityConcurrentHistory = new Map<string, Map<string, EntSnap[]>>();
  const ENT_MAX_SNAP     = 480; // 8h at 45s intervals
  const ENT_MAX_ENTITIES = 30;  // top 30 entities tracked per dimension

  // Persistent entity registry — keeps entities visible even when concurrent calls drop to zero.
  // Entities persist up to: Clients/Vendors 24h, Countries 12h, Destinations 6h after last call.
  interface EntityPresence {
    lastSeen: number; firstSeen: number;
    currentActive: number; currentConnected: number; currentRouting: number;
    connectRate: number; peakToday: number; peakTs: number;
  }
  const entityPresenceCache = new Map<string, Map<string, EntityPresence>>();
  const ENTITY_RETENTION: Record<string, number> = {
    client: 86_400_000, vendor: 86_400_000, country: 43_200_000, destination: 21_600_000,
  };

  // ── BitsEye Alert Engine state ─────────────────────────────────────────────
  // Cooldown map prevents alert storms: 30 min per (metric, dim, entity).
  const bitseyeAlertCooldown  = new Map<string, number>(); // key: `${metric}:${dim}:${name}`
  const bitseyeEntityIdleCycles = new Map<string, number>(); // key: `${dim}:${name}` → consecutive idle polls
  let _cachedAlertRulesForEngine: typeof alertRulesTable.$inferSelect[] | null = null;
  let _cachedAlertRulesTsEngine = 0;

  // Cross-dim topology cache — tracks which cross-dim entities co-occur with each entity.
  // Only updated when entity is active; preserved when entity goes idle, enabling idle sub-tree.
  // Structure: dim → entityName → crossDim → crossEntityName → lastCount
  const crossDimCache = new Map<string, Map<string, Map<string, Map<string, number>>>>();

  let _snapshotRunning  = false;
  let _csnapWriteCount  = 0;   // used to throttle hourly prune (every 80 cycles ≈ 1h at 45s)
  async function snapshotActiveCalls(): Promise<void> {
    if (_snapshotRunning) return; // mutex — skip if previous cycle still in progress
    _snapshotRunning = true;
    const _snapT0 = Date.now();
    try {
      const settings = await storage.getSippySettings();
      if (!settings) return;
      const credPairs = sippyXmlCredsPairs(settings);
      const portalUrl = sippyPortalUrl(settings);
      // Try each credential pair — RTST1 first (XML-RPC capable), ssp-root as fallback
      let raw: Awaited<ReturnType<typeof sippy.getSippyActiveCalls>> = [];
      for (const { username, password } of credPairs) {
        raw = await sippy.getSippyActiveCalls(username, password, portalUrl, undefined, undefined, undefined, true);
        if (raw.length > 0) break;
      }

      // Push to concurrent history (even if 0, to track dips)
      pushConcurrentPoint(raw);

      // ── Enrich and cache results so /api/sippy/live-calls can serve from memory ──
      const ccStateMap: Record<string, 'connected' | 'routing'> = {
        Connected: 'connected', ARComplete: 'routing', WaitRoute: 'routing',
        WaitAuth: 'routing', Idle: 'routing',
      };
      const TERMINATED = new Set(['Dead', 'Disconnecting', 'Disconnected', 'Released', 'Rejected']);
      const enrichedCalls = raw
        .filter(c => !TERMINATED.has(c.status ?? ''))
        .map(c => {
          const dialMatch = lookupDialCode(c.callee ?? '');
          const resolvedVendor = c.vendor
            || (c.connection ? connectionVendorCache.get(c.connection) : undefined)
            || (c.iVendorId  ? connectionVendorCache.get(c.iVendorId)  : undefined);
          const resolvedConnection = c.connection
            ? (connectionNameCache.get(c.connection) || c.connection)
            : undefined;
          return {
            ...c,
            clientName:   c.user || accountNameCache.get(c.accountId ?? '') || (c.accountId ? `Acct.${c.accountId}` : undefined),
            vendor:       resolvedVendor,
            connection:   resolvedConnection,
            ccState:      c.status,
            callStatus:   ccStateMap[c.status ?? ''] ?? (c.status?.toLowerCase().includes('connect') ? 'connected' : 'routing'),
            destCountry:  dialMatch?.country  ?? null,
            destBreakout: dialMatch?.breakout ?? null,
            destFull:     dialMatch?.destination ?? null,
            trunkClass:   dialMatch?.trunkClass  ?? null,
            trunkPrefix:  dialMatch?.trunkPrefix ?? null,
          };
        });

      // Update liveCallsCache so the API endpoint can serve instantly without hitting Sippy
      if (enrichedCalls.length > 0) {
        consecutiveZeros = 0;
        liveCallsCache = { calls: enrichedCalls, ts: Date.now() };
      } else {
        consecutiveZeros++;
        if (consecutiveZeros >= ZERO_CONFIRM_COUNT) {
          liveCallsCache = { calls: [], ts: Date.now() };
        }
      }

      // ── Update per-entity concurrent history + persistent presence registry ──
      // Guard: only update entity state when we trust this poll result.
      // If enrichedCalls is empty but consecutiveZeros < ZERO_CONFIRM_COUNT, this is
      // likely a transient session blip — keep previous entity state intact so entities
      // don't flicker to idle after a single failed poll.
      if (enrichedCalls.length > 0 || consecutiveZeros >= ZERO_CONFIRM_COUNT) {
        const nowEnt = Date.now();
        const dimGetters: [string, (c: any) => string | null][] = [
          ['client',      (c: any) => c.clientName || (c.accountId ? `Acct.${c.accountId}` : null)],
          ['vendor',      (c: any) => c.vendor || c.connection || null],
          ['country',     (c: any) => c.destCountry || null],
          ['destination', (c: any) => c.destFull || c.destCountry || null],
        ];
        for (const [dim, getKey] of dimGetters) {
          // Build live counts for this snapshot
          const aggMap = new Map<string, { count: number; connected: number; routing: number }>();
          for (const c of enrichedCalls) {
            const key = getKey(c);
            if (!key) continue;
            const ex = aggMap.get(key) ?? { count: 0, connected: 0, routing: 0 };
            ex.count++;
            if (c.callStatus === 'connected') ex.connected++; else ex.routing++;
            aggMap.set(key, ex);
          }

          // ── entityConcurrentHistory: push snapshots for currently-active entities ──
          const dimMap = entityConcurrentHistory.get(dim) ?? new Map<string, EntSnap[]>();
          const sorted = [...aggMap.entries()].sort((a, b) => b[1].count - a[1].count).slice(0, ENT_MAX_ENTITIES);
          for (const [name, counts] of sorted) {
            const hist = dimMap.get(name) ?? [];
            hist.push({ ts: nowEnt, ...counts });
            if (hist.length > ENT_MAX_SNAP) hist.splice(0, hist.length - ENT_MAX_SNAP);
            dimMap.set(name, hist);
          }

          // ── entityPresenceCache: persist all known entities, mark idle ones ──
          const presMap = entityPresenceCache.get(dim) ?? new Map<string, EntityPresence>();
          const retention = ENTITY_RETENTION[dim] ?? 86_400_000;

          // Update currently-active entities
          for (const [name, counts] of aggMap.entries()) {
            const ex: EntityPresence = presMap.get(name) ?? {
              lastSeen: nowEnt, firstSeen: nowEnt,
              currentActive: 0, currentConnected: 0, currentRouting: 0,
              connectRate: 0, peakToday: 0, peakTs: nowEnt,
            };
            ex.currentActive    = counts.count;
            ex.currentConnected = counts.connected;
            ex.currentRouting   = counts.routing;
            ex.connectRate      = counts.count > 0 ? Math.round(counts.connected / counts.count * 100) : 0;
            ex.lastSeen         = nowEnt;
            // Reset peak daily if > 24h old, or update if new high
            if (nowEnt - ex.peakTs > 86_400_000) { ex.peakToday = counts.count; ex.peakTs = nowEnt; }
            else if (counts.count > ex.peakToday)  { ex.peakToday = counts.count; ex.peakTs = nowEnt; }
            presMap.set(name, ex);
          }

          // For every known entity NOT in the current active set → push a zero-snapshot.
          // This runs every poll cycle regardless of whether the entity was active last cycle.
          // Guarantees continuous time-series continuity: idle traffic becomes flat-at-zero,
          // not "missing data" that collapses the chart line.
          for (const [name, pres] of presMap.entries()) {
            if (!aggMap.has(name)) {
              pres.currentActive = 0; pres.currentConnected = 0;
              pres.currentRouting = 0; pres.connectRate = 0;
              const hist = dimMap.get(name) ?? [];
              hist.push({ ts: nowEnt, count: 0, connected: 0, routing: 0 });
              if (hist.length > ENT_MAX_SNAP) hist.splice(0, hist.length - ENT_MAX_SNAP);
              dimMap.set(name, hist);
            }
          }

          // Prune entities beyond their retention window.
          // Entities with lastSeen=0 are bootstrapped (never seen with live calls) — never prune them.
          for (const [name, pres] of presMap.entries()) {
            if (pres.lastSeen > 0 && nowEnt - pres.lastSeen > retention) {
              presMap.delete(name);
              dimMap.delete(name);
            }
          }

          // ── crossDimCache: record co-occurring cross-dim entities for active entities ──
          // Enables idle sub-tree: topology is remembered even when calls stop.
          const getDimKeyLocal = (d: string, c: any): string | null => {
            if (d === 'client')      return c.clientName || (c.accountId ? `Acct.${c.accountId}` : null);
            if (d === 'vendor')      return c.vendor || c.connection || null;
            if (d === 'country')     return c.destCountry || null;
            if (d === 'destination') return c.destFull || c.destCountry || null;
            return null;
          };
          const dimCrossCache = crossDimCache.get(dim) ?? new Map<string, Map<string, Map<string, number>>>();
          for (const c of enrichedCalls) {
            const key = getKey(c);
            if (!key) continue;
            const entityCross = dimCrossCache.get(key) ?? new Map<string, Map<string, number>>();
            for (const cd of ['client', 'vendor', 'country', 'destination']) {
              if (cd === dim) continue;
              const crossKey = getDimKeyLocal(cd, c);
              if (!crossKey) continue;
              const cdMap = entityCross.get(cd) ?? new Map<string, number>();
              cdMap.set(crossKey, (cdMap.get(crossKey) ?? 0) + 1);
              entityCross.set(cd, cdMap);
            }
            dimCrossCache.set(key, entityCross);
          }
          crossDimCache.set(dim, dimCrossCache);

          entityPresenceCache.set(dim, presMap);
          entityConcurrentHistory.set(dim, dimMap);
        }
      }

      // ── Persist concurrent snapshots to DB (CALLS metric source for DAILY/WEEKLY) ──
      // Reads the last point from each entity's in-memory history and batch-writes to
      // concurrent_snapshots table. MAX(active) per bucket in queryConcurrentHistory()
      // ensures DAILY/WEEKLY CALLS graphs always reflect true concurrency peaks, not CDR totals.
      {
        const snapRows: { dim: string; entityName: string; ts: number; active: number; connected: number; routing: number }[] = [];
        for (const [csDim, dimMap] of entityConcurrentHistory) {
          for (const [entityName, snaps] of dimMap) {
            const last = snaps[snaps.length - 1];
            if (last) {
              snapRows.push({ dim: csDim, entityName, ts: last.ts, active: last.count, connected: last.connected, routing: last.routing ?? 0 });
            }
          }
        }
        if (snapRows.length > 0) {
          storage.insertConcurrentSnapshots(snapRows).catch((e: any) => console.warn('[csnap] insert error:', e.message));
        }
        _csnapWriteCount = (_csnapWriteCount + 1) % 80;
        if (_csnapWriteCount === 0) {
          storage.pruneConcurrentSnapshots().catch((e: any) => console.warn('[csnap] prune error:', e.message));
        }
      }

      // ── Persist to DB for history ──────────────────────────────────────────────
      const now = new Date();
      for (const c of raw) {
        if (!c.callId) continue;
        const vendorName = c.vendor || (c.connection ? connectionVendorCache.get(c.connection) : undefined);
        const rawId     = String(c.accountId ?? c.iCustomer ?? '').trim();
        const cachedName = rawId ? accountNameCache.get(rawId) : undefined;
        const clientName = c.user || cachedName || (rawId && !/^\d+$/.test(rawId) ? rawId : undefined);
        await storage.upsertCallSnapshot({
          sippyCallId:     c.callId,
          caller:          c.caller,
          callee:          c.callee,
          clientName:      clientName,
          vendor:          vendorName,
          accountId:       c.accountId,
          iCustomer:       c.iCustomer,
          iEnvironment:    c.iEnvironment,
          direction:       c.direction,
          codec:           c.codec && c.codec !== '-' ? c.codec : undefined,
          ccState:         c.status,
          maxDurationSecs: c.duration ?? 0,
          pddMs:           Math.round((c.delay ?? 0) * 1000),
          mediaIpCaller:   c.mediaIpCaller,
          mediaIpCallee:   c.mediaIpCallee,
          connection:      c.connection,
          firstSeen:       now,
          lastSeen:        now,
        });
      }
      await storage.cleanupOldSnapshots();

      // ── Persist entity presence to DB every 5 minutes ────────────────────────
      if (Date.now() - _lastPresencePersist > PRESENCE_PERSIST_INTERVAL) {
        persistPresenceToDb().catch(() => {});
      }

      // ── Run BitsEye threshold engine (after presence cache is updated) ─────
      runBitsEyeThresholdEngine().catch(err =>
        console.warn('[bitseye-alerts] engine error:', err.message)
      );

      // ── Push NOC tick to all connected WebSocket clients ────────────────────
      broadcastNocTick({
        callCount:  liveCallsCache.calls.length,
        alertCount: 0,
        updatedAt:  new Date().toISOString(),
      });
    } catch (e: any) {
      console.warn('[snapshot-bg] error:', e.message);
    } finally {
      const _snapMs = Date.now() - _snapT0;
      if (_snapMs > 5000) console.warn(`[perf] snapshotActiveCalls took ${_snapMs}ms`);
      else console.debug(`[perf] snapshotActiveCalls ${_snapMs}ms`);
      _snapshotRunning = false;
    }
  }
  setTimeout(() => snapshotActiveCalls(), 8000);            // first run at startup
  setInterval(() => snapshotActiveCalls(), 45 * 1000);      // every 45 s — slightly under UI's 60s poll

  // ── Incident Escalation Scheduler ────────────────────────────────────────
  // Resends alert emails for unresolved incidents on a severity-weighted cadence.
  // Severity windows: critical=15m, high=60m, medium/low=no repeat.
  // In-memory tracker (no schema change) — resets cleanly on server restart.
  const incidentEscalationTracker = new Map<number, number>(); // incidentId → lastNotifiedAt ms
  const ESCALATION_WINDOWS: Record<string, number> = {
    critical: 15 * 60_000,
    high:     60 * 60_000,
    medium:   0, // no repeat
    low:      0, // no repeat
  };

  let _escalationRunning = false;
  async function runEscalationSweep(): Promise<void> {
    if (_escalationRunning) return;
    _escalationRunning = true;
    try {
      const { eq: drizzleEq2 } = await import('drizzle-orm');
      const openIncidents = await db.select().from(incidentsTable)
        .where(drizzleEq2(incidentsTable.status, 'active'));

      const now = Date.now();

      // Purge resolved incidents from tracker to prevent memory growth
      const activeIds = new Set(openIncidents.map((i: any) => i.id));
      for (const id of incidentEscalationTracker.keys()) {
        if (!activeIds.has(id)) incidentEscalationTracker.delete(id);
      }

      for (const incident of openIncidents as any[]) {
        const window = ESCALATION_WINDOWS[incident.severity] ?? 0;
        if (window === 0) continue; // this severity level does not escalate

        // On first escalation check, seed from openedAt so we don't immediately resend
        // a reminder for an incident that was just created (give it one full window first)
        const lastNotified = incidentEscalationTracker.get(incident.id) ?? incident.openedAt.getTime();
        if (now - lastNotified < window) continue;

        const windowLabel = ESCALATION_WINDOWS[incident.severity] === 15 * 60_000 ? '15m' : '60m';
        const reminderTitle = `[ESCALATION – every ${windowLabel}] ${incident.title}`;

        const sent = await emailSvc.sendAlertEmail(emailSvc.buildIncidentAlertEmail({
          title:           reminderTitle,
          summary:         `This incident has been open for ${Math.round((now - incident.openedAt.getTime()) / 60_000)} minutes and has not been resolved.\n\n${incident.summary ?? incident.title}`,
          severity:        incident.severity,
          metric:          incident.incidentType,
          entityName:      incident.entityName ?? incident.entityId,
          entityType:      incident.entityType,
          metricValue:     null,
          threshold:       null,
          suggestedAction: incident.suggestedAction ?? 'Review incident in the Bitsauto monitoring dashboard.',
          openedAt:        incident.openedAt,
        }));

        if (sent) {
          incidentEscalationTracker.set(incident.id, now);
          console.log(`[escalation] Reminder sent — incident #${incident.id} (${incident.severity}): ${incident.title}`);
        }
      }
    } catch (err: any) {
      console.warn('[escalation] Sweep error:', err.message);
    } finally {
      _escalationRunning = false;
    }
  }
  // Start 2 minutes after boot (let system settle + initial alerts fire first)
  setTimeout(() => runEscalationSweep(), 2 * 60_000);
  setInterval(() => runEscalationSweep(), 5 * 60_000);

  // ── BitsEye Threshold Engine ──────────────────────────────────────────────
  // Runs after each snapshotActiveCalls() cycle. Uses entityPresenceCache (live
  // concurrent metrics) and cdrCache (rolling 1h CDRs) to detect operational
  // anomalies and write incidents to the DB. Auto-resolves when metrics recover.
  // Metrics supported: asr_drop | traffic_gone | cps_spike
  async function runBitsEyeThresholdEngine(): Promise<void> {
    const _bseT0 = Date.now();
    // Cache alert rules from DB for 5 min to avoid per-cycle DB hits
    if (!_cachedAlertRulesForEngine || Date.now() - _cachedAlertRulesTsEngine > 5 * 60_000) {
      _cachedAlertRulesForEngine = await db.select().from(alertRulesTable);
      _cachedAlertRulesTsEngine = Date.now();
    }
    const rules = (_cachedAlertRulesForEngine ?? []).filter((r: any) => r.enabled);
    if (rules.length === 0) return;

    const now = Date.now();
    // Only run when the live cache is fresh (prevents false alerts from stale data)
    const cacheAgeMs = now - (liveCallsCache as any).ts;
    if ((liveCallsCache as any).ts === 0 || cacheAgeMs > 120_000) return;

    // ── Compute rolling 1h ASR per (dim, entity) from cdrCache ──
    const cutoff1h = now - 3_600_000;
    const asrAccum = new Map<string, { total: number; answered: number }>();
    for (const c of cdrCache.values()) {
      const ts = sippy.parseSippyDate(c.startTime)?.getTime() ?? 0;
      if (ts < cutoff1h) continue;
      const pairs: [string, string | undefined][] = [
        ['client', (c as any).clientName || accountNameCache.get(String((c as any).iAccount ?? ''))],
        ['vendor', (c as any).vendor],
      ];
      for (const [dim, name] of pairs) {
        if (!name) continue;
        const key = `${dim}:${name}`;
        const ex = asrAccum.get(key) ?? { total: 0, answered: 0 };
        ex.total++;
        if (((c as any).duration ?? 0) > 0) ex.answered++;
        asrAccum.set(key, ex);
      }
    }

    // ── Evaluate each tracked entity against all applicable rules ──
    for (const [dim, presMap] of entityPresenceCache.entries()) {
      for (const [name, pres] of presMap.entries()) {
        if (pres.lastSeen === 0) continue; // bootstrapped placeholder — never had live traffic
        const entityKey = `${dim}:${name}`;

        // Update idle cycle counter
        if (pres.currentActive === 0) {
          bitseyeEntityIdleCycles.set(entityKey, (bitseyeEntityIdleCycles.get(entityKey) ?? 0) + 1);
        } else {
          bitseyeEntityIdleCycles.set(entityKey, 0);
        }
        const idleCycles = bitseyeEntityIdleCycles.get(entityKey) ?? 0;

        // Compute 1h ASR for this entity
        const asrData = asrAccum.get(entityKey);
        const asr1h = asrData && asrData.total >= 10
          ? Math.round(asrData.answered / asrData.total * 100)
          : null;

        // Concurrent spike: compare current vs 5-min rolling baseline
        const hist = entityConcurrentHistory.get(dim)?.get(name) ?? [];
        const baseline6 = hist.slice(-7, -1); // last ~4.5 min
        const baselineAvg = baseline6.length >= 3
          ? baseline6.reduce((s: number, p: any) => s + p.count, 0) / baseline6.length
          : null;
        const spikeRatio = baselineAvg && baselineAvg > 0
          ? Math.round(pres.currentActive / baselineAvg * 100 - 100)
          : null;

        for (const rule of rules as any[]) {
          // Carrier / entity scoping
          if (rule.carrier && rule.carrier !== name && rule.carrier !== entityKey) continue;

          // Metric applicability
          let metricValue: number | null = null;
          if (rule.metric === 'asr_drop') {
            if (!['client', 'vendor'].includes(dim)) continue;
            if (asr1h === null) continue;
            metricValue = asr1h;
          } else if (rule.metric === 'traffic_gone') {
            if (pres.peakToday === 0) continue; // entity never had traffic today
            metricValue = idleCycles; // number of consecutive idle 45s polls
          } else if (rule.metric === 'cps_spike') {
            if (spikeRatio === null) continue;
            metricValue = spikeRatio;
          } else continue;

          const breached = rule.comparison === 'gt'
            ? metricValue > rule.threshold
            : metricValue < rule.threshold;

          if (!breached) {
            // Auto-resolve any open incident for this (metric, entity) now that it recovered
            await db.update(incidentsTable)
              .set({ status: 'resolved', resolvedAt: new Date(now), updatedAt: new Date(now) } as any)
              .where(and(eq(incidentsTable.entityId, entityKey), eq(incidentsTable.incidentType, rule.metric), eq(incidentsTable.status, 'active')))
              .catch(() => {});
            continue;
          }

          // Cooldown: 30 min per (metric, entity)
          const coolKey = `${rule.metric}:${entityKey}`;
          const lastFired = bitseyeAlertCooldown.get(coolKey) ?? 0;
          if (now - lastFired < 30 * 60_000) continue;

          // Check for already-open incident
          const hasOpen = await db.select({ id: incidentsTable.id }).from(incidentsTable)
            .where(and(eq(incidentsTable.entityId, entityKey), eq(incidentsTable.incidentType, rule.metric), eq(incidentsTable.status, 'active')))
            .limit(1).then((r: any[]) => r.length > 0).catch(() => false);
          if (hasOpen) continue;

          bitseyeAlertCooldown.set(coolKey, now);

          // Severity
          const humanDim = dim.charAt(0).toUpperCase() + dim.slice(1);
          const severity: string =
            rule.metric === 'traffic_gone' ? (idleCycles >= 8 ? 'critical' : 'high') :
            rule.metric === 'asr_drop'     ? (metricValue < 20 ? 'critical' : metricValue < 35 ? 'high' : 'medium') :
            (metricValue > 200 ? 'high' : 'medium');

          const title =
            rule.metric === 'traffic_gone'
              ? `Traffic stopped: ${name} (${humanDim}) — idle ${idleCycles * 45}s`
              : rule.metric === 'asr_drop'
              ? `ASR degraded: ${name} — ${metricValue}% (threshold <${rule.threshold}%)`
              : `Concurrent spike: ${name} — +${metricValue}% above baseline`;

          const summary =
            rule.metric === 'traffic_gone'
              ? `${name} reached a peak of ${pres.peakToday} concurrent calls today but has been idle for ${idleCycles * 45}s.`
              : rule.metric === 'asr_drop'
              ? `${name} rolling 1h ASR is ${metricValue}%. Threshold: <${rule.threshold}%. Sample: ${asrData?.total ?? '?'} CDRs.`
              : `${name} concurrent calls spiked ${metricValue}% above the recent ${Math.round(baselineAvg!)} call baseline.`;

          await db.insert(incidentsTable).values({
            entityType:      dim,
            entityId:        entityKey,
            entityName:      name,
            incidentType:    rule.metric,
            severity,
            confidence:      85,
            title,
            summary,
            reasons:         [title] as any,
            suggestedAction:
              rule.metric === 'traffic_gone' ? 'Verify routing configuration and Sippy call routing for this entity.' :
              rule.metric === 'asr_drop'     ? 'Review CDR quality data, vendor routing, and destination coverage.' :
              'Investigate sudden call volume increase — possible route hijack or unplanned volume.',
            status:   'active',
            source:   'bitseye_threshold_engine',
            openedAt: new Date(now),
            updatedAt: new Date(now),
          } as any).catch(() => {});

          // Fire incident email via the HTML template (non-blocking, honours SMTP config)
          emailSvc.sendAlertEmail(emailSvc.buildIncidentAlertEmail({
            title,
            summary,
            severity,
            metric:          rule.metric,
            entityName:      name,
            entityType:      dim,
            metricValue,
            threshold:       rule.threshold,
            suggestedAction:
              rule.metric === 'traffic_gone' ? 'Verify routing configuration and Sippy call routing for this entity.' :
              rule.metric === 'asr_drop'     ? 'Review CDR quality data, vendor routing, and destination coverage.' :
              'Investigate sudden call volume increase — possible route hijack or unplanned volume.',
            openedAt: new Date(now),
          })).catch(() => {});

          console.log(`[bitseye-alerts] ${severity.toUpperCase()} — ${title}`);
        }
      }
    }
    const _bseMs = Date.now() - _bseT0;
    if (_bseMs > 3000) console.warn(`[perf] runBitsEyeThresholdEngine took ${_bseMs}ms`);
  }

  // ── BitsEye Alert API endpoints ───────────────────────────────────────────
  // GET /api/bitseye/alerts — recent incidents from the threshold engine (last 24h)
  app.get('/api/bitseye/alerts', async (_req: any, res: any) => {
    try {
      const { desc: drizzleDesc, gte: drizzleGte } = await import('drizzle-orm');
      const cutoff = new Date(Date.now() - 24 * 3_600_000);
      const rows = await db.select().from(incidentsTable)
        .where(drizzleGte(incidentsTable.openedAt, cutoff))
        .orderBy(drizzleDesc(incidentsTable.openedAt));
      res.json(rows);
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // PATCH /api/incidents/:id/status — acknowledge or resolve an incident
  app.patch('/api/incidents/:id/status', async (req: any, res: any) => {
    try {
      const id = parseInt(req.params.id);
      const { status } = req.body as { status: 'acknowledged' | 'resolved' };
      if (!['acknowledged', 'resolved'].includes(status)) {
        return res.status(400).json({ error: 'status must be acknowledged or resolved' });
      }
      const update: any = { status, updatedAt: new Date() };
      if (status === 'resolved') update.resolvedAt = new Date();
      await db.update(incidentsTable).set(update).where(eq(incidentsTable.id, id));
      // Invalidate threshold engine cooldown — look up entityId+incidentType to reconstruct the key
      if (status === 'resolved') {
        const [resolved] = await db.select({ entityId: incidentsTable.entityId, incidentType: incidentsTable.incidentType })
          .from(incidentsTable).where(eq(incidentsTable.id, id)).limit(1).catch(() => []);
        if (resolved) {
          const coolKey = `${resolved.incidentType}:${resolved.entityId}`;
          bitseyeAlertCooldown.delete(coolKey);
        }
      }
      res.json({ ok: true });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // ── Presence persistence: load from DB then supplement with KAM accounts ──────
  // Phase 1 (T+2s): reload persisted idle entities for ALL 4 dimensions from the
  //   entity_presence_registry table — covers vendor/country/destination too.
  // Phase 2 (T+2s): top-up the client dimension from kamAccounts for any client
  //   not already in the DB registry (e.g. never-called-yet new accounts).
  // Phase 3 (every 300s): persist current entityPresenceCache back to DB so
  //   idle entities survive the next server restart.
  let _lastPresencePersist = 0;
  async function persistPresenceToDb(): Promise<void> {
    try {
      const rows: { dim: string; entityName: string; lastSeen: number; firstSeen: number; peakToday: number; peakTs: number }[] = [];
      for (const [dim, presMap] of entityPresenceCache.entries()) {
        for (const [entityName, pres] of presMap.entries()) {
          // Only persist entities that have been seen live (lastSeen>0) to avoid
          // writing stub "Acct.X" bootstrap entries that will never match live calls.
          if (pres.lastSeen > 0) {
            rows.push({ dim, entityName, lastSeen: pres.lastSeen, firstSeen: pres.firstSeen, peakToday: pres.peakToday, peakTs: pres.peakTs });
          }
        }
      }
      if (rows.length) await storage.upsertEntityPresence(rows);
      _lastPresencePersist = Date.now();
    } catch (e: any) {
      console.warn('[presence-persist] error:', e.message);
    }
  }

  setTimeout(async () => {
    try {
      const nowMs = Date.now();

      // ── Phase 1: Load from DB (all 4 dimensions) ──────────────────────────────
      let dbLoaded = 0;
      try {
        const dbRows = await storage.loadEntityPresence();
        for (const row of dbRows) {
          const presMap = entityPresenceCache.get(row.dim) ?? new Map<string, EntityPresence>();
          if (!presMap.has(row.entityName)) {
            presMap.set(row.entityName, {
              lastSeen: row.lastSeen, firstSeen: row.firstSeen,
              currentActive: 0, currentConnected: 0, currentRouting: 0,
              connectRate: 0, peakToday: row.peakToday, peakTs: row.peakTs,
            });
            dbLoaded++;
          }
          entityPresenceCache.set(row.dim, presMap);
        }
        if (dbLoaded) console.log(`[presence-bootstrap] restored ${dbLoaded} entities from DB registry`);
      } catch (e: any) {
        console.warn('[presence-bootstrap] DB load failed:', e.message);
      }

      // ── Phase 2: Top-up client dim from KAM accounts (for never-called clients) ─
      const allAccs = await storage.getKamAccounts();
      const clientPresMap = entityPresenceCache.get('client') ?? new Map<string, EntityPresence>();
      let seeded = 0;
      for (const acc of allAccs) {
        const resolvedName = acc.clientName
          || (acc.accountId ? accountNameCache.get(String(acc.accountId)) : undefined)
          || null;  // no Acct.{id} fallback — stub names don't match live call names
        if (resolvedName && !clientPresMap.has(resolvedName)) {
          clientPresMap.set(resolvedName, {
            lastSeen: 0, firstSeen: nowMs,
            currentActive: 0, currentConnected: 0, currentRouting: 0,
            connectRate: 0, peakToday: 0, peakTs: nowMs,
          });
          seeded++;
        }
      }
      if (seeded > 0) {
        entityPresenceCache.set('client', clientPresMap);
        console.log(`[presence-bootstrap] seeded ${seeded} clients from KAM accounts registry`);
      }
    } catch (e: any) {
      console.warn('[presence-bootstrap] error:', e.message);
    }
  }, 2000);

  // ── Phase 3: Full Sippy inventory bootstrap — runs at T+12s ─────────────────
  // By T+12s: accountCache (T+0.5s), connectionVendorCache (T+1.5s + ~8s fetch),
  // and first snapshotActiveCalls (T+8s, CDR cache populated) are all complete.
  // Seeds ALL 4 dimensions from authoritative Sippy inventory so the sidebar is
  // fully populated even before live calls arrive.
  setTimeout(async () => {
    try {
      const nowMs = Date.now();

      // ── Clients: all Sippy accounts from accountNameCache ─────────────────────
      const clientPresMap = entityPresenceCache.get('client') ?? new Map<string, EntityPresence>();
      let clientSeeded = 0;
      for (const username of accountNameCache.values()) {
        if (username && !clientPresMap.has(username)) {
          clientPresMap.set(username, {
            lastSeen: 0, firstSeen: nowMs,
            currentActive: 0, currentConnected: 0, currentRouting: 0,
            connectRate: 0, peakToday: 0, peakTs: nowMs,
          });
          clientSeeded++;
        }
      }
      if (clientSeeded > 0) {
        entityPresenceCache.set('client', clientPresMap);
        console.log(`[presence-bootstrap] seeded ${clientSeeded} clients from Sippy account inventory`);
      }

      // ── Vendors: unique vendor names from connectionVendorCache values ─────────
      // The cache stores many key types (iVendor ID, connection name, IP, vendor name).
      // Extract only human-readable vendor names: non-numeric, non-IP unique values.
      const vendorPresMap = entityPresenceCache.get('vendor') ?? new Map<string, EntityPresence>();
      let vendorSeeded = 0;
      const seenVendorNames = new Set<string>();
      for (const vendorName of connectionVendorCache.values()) {
        if (!vendorName) continue;
        if (/^\d+$/.test(vendorName)) continue;              // skip pure-numeric IDs
        if (/^\d{1,3}\.\d{1,3}/.test(vendorName)) continue; // skip IP addresses
        if (seenVendorNames.has(vendorName)) continue;
        seenVendorNames.add(vendorName);
        if (!vendorPresMap.has(vendorName)) {
          vendorPresMap.set(vendorName, {
            lastSeen: 0, firstSeen: nowMs,
            currentActive: 0, currentConnected: 0, currentRouting: 0,
            connectRate: 0, peakToday: 0, peakTs: nowMs,
          });
          vendorSeeded++;
        }
      }
      if (vendorSeeded > 0) {
        entityPresenceCache.set('vendor', vendorPresMap);
        console.log(`[presence-bootstrap] seeded ${vendorSeeded} vendors from Sippy vendor inventory`);
      }

      // ── Countries + Destinations: from 72h CDR history ────────────────────────
      // cdrCache is the rolling 72h CDR window populated by snapshotActiveCalls.
      // Each CDR has cdr.country and cdr.areaName fields set by dial-code lookup.
      const countryPresMap = entityPresenceCache.get('country') ?? new Map<string, EntityPresence>();
      const destPresMap    = entityPresenceCache.get('destination') ?? new Map<string, EntityPresence>();
      let countrySeeded = 0, destSeeded = 0;
      for (const cdr of cdrCache.values()) {
        const country = (cdr as any).country;
        const area    = (cdr as any).areaName || country;
        if (country && country !== 'Unknown' && !countryPresMap.has(country)) {
          countryPresMap.set(country, {
            lastSeen: 0, firstSeen: nowMs,
            currentActive: 0, currentConnected: 0, currentRouting: 0,
            connectRate: 0, peakToday: 0, peakTs: nowMs,
          });
          countrySeeded++;
        }
        if (area && area !== 'Unknown' && !destPresMap.has(area)) {
          destPresMap.set(area, {
            lastSeen: 0, firstSeen: nowMs,
            currentActive: 0, currentConnected: 0, currentRouting: 0,
            connectRate: 0, peakToday: 0, peakTs: nowMs,
          });
          destSeeded++;
        }
      }
      if (countrySeeded > 0) {
        entityPresenceCache.set('country', countryPresMap);
        console.log(`[presence-bootstrap] seeded ${countrySeeded} countries from CDR history`);
      }
      if (destSeeded > 0) {
        entityPresenceCache.set('destination', destPresMap);
        console.log(`[presence-bootstrap] seeded ${destSeeded} destinations from CDR history`);
      }

      // Persist the newly seeded inventory to DB immediately so they survive restart.
      persistPresenceToDb().catch(() => {});

    } catch (e: any) {
      console.warn('[presence-bootstrap] inventory phase error:', e.message);
    }
  }, 12000);

  // Periodic DB persist — runs inside snapshotActiveCalls every 300s
  // (hoisted here so snapshotActiveCalls can call it)
  const PRESENCE_PERSIST_INTERVAL = 300_000; // 5 minutes

  // GET /api/sippy/live-graphs — live concurrent call history + breakdowns
  app.get('/api/sippy/live-graphs', (req: any, res) => {
    res.setHeader('Cache-Control', 'no-cache, no-store, must-revalidate');
    const hours   = Math.min(Number(req.query.hours) || 3, CONCURRENT_HISTORY_HOURS);
    const cutoffMs = Date.now() - hours * 3600 * 1000;

    const window = concurrentHistory.filter(p => p.ts >= cutoffMs);

    // Build time-series (minute buckets for ≤6h, 5-min for ≤24h, 15-min for >24h)
    const bucketMs = hours <= 6 ? 60_000 : hours <= 24 ? 5 * 60_000 : 15 * 60_000;
    const bucketMap = new Map<number, number[]>();
    for (const p of window) {
      const b = Math.floor(p.ts / bucketMs) * bucketMs;
      if (!bucketMap.has(b)) bucketMap.set(b, []);
      bucketMap.get(b)!.push(p.count);
    }
    const trend = Array.from(bucketMap.entries())
      .sort((a, b) => a[0] - b[0])
      .map(([ts, counts]) => ({
        time: new Date(ts).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: false }),
        avg:  Math.round(counts.reduce((s, v) => s + v, 0) / counts.length),
        peak: Math.max(...counts),
      }));

    // Aggregate latest breakdown (last 5 data points to smooth noise)
    const recent = window.slice(-5);
    const aggClient:      Record<string, number> = {};
    const aggVendor:      Record<string, number> = {};
    const aggCodec:       Record<string, number> = {};
    const aggDir:         Record<string, number> = {};
    const aggDestination: Record<string, number> = {};
    const aggBreakout:    Record<string, number> = {};
    const aggCountry:     Record<string, number> = {};
    for (const p of recent) {
      for (const [k, v] of Object.entries(p.byClient))           aggClient[k]      = Math.max(aggClient[k]      || 0, v);
      for (const [k, v] of Object.entries(p.byVendor))           aggVendor[k]      = Math.max(aggVendor[k]      || 0, v);
      for (const [k, v] of Object.entries(p.byCodec))            aggCodec[k]       = Math.max(aggCodec[k]       || 0, v);
      for (const [k, v] of Object.entries(p.byDirection))        aggDir[k]         = Math.max(aggDir[k]         || 0, v);
      for (const [k, v] of Object.entries(p.byDestination ?? {})) aggDestination[k] = Math.max(aggDestination[k] || 0, v);
      for (const [k, v] of Object.entries(p.byBreakout ?? {}))   aggBreakout[k]    = Math.max(aggBreakout[k]    || 0, v);
      for (const [k, v] of Object.entries(p.byCountry ?? {}))    aggCountry[k]     = Math.max(aggCountry[k]     || 0, v);
    }

    // CDR-based destination/breakout stats (accumulated from rolling CDR cache)
    const cdrDestMap:    Record<string, number> = {};
    const cdrCountryMap: Record<string, number> = {};
    const cdrBreakoutMap:Record<string, number> = {};
    const cdrCutoffMs = Date.now() - hours * 3600 * 1000;
    for (const c of cdrCache.values()) {
      const ts = c.startTime ? new Date(c.startTime).getTime() : c.connectTime ? new Date(c.connectTime).getTime() : 0;
      if (ts < cdrCutoffMs) continue;
      const callee = (c as any).callee ?? (c as any).cld ?? '';
      const m = lookupDialCode(callee);
      if (m) {
        cdrDestMap[m.destination]    = (cdrDestMap[m.destination]    || 0) + 1;
        cdrCountryMap[m.country]     = (cdrCountryMap[m.country]     || 0) + 1;
        cdrBreakoutMap[m.breakout]   = (cdrBreakoutMap[m.breakout]   || 0) + 1;
      } else {
        const fallback = (c as any).country || calleeToCountry(callee);
        cdrDestMap[fallback] = (cdrDestMap[fallback] || 0) + 1;
      }
    }

    const toArr = (m: Record<string, number>, top = 15) =>
      Object.entries(m).sort((a, b) => b[1] - a[1]).slice(0, top).map(([name, calls]) => ({ name, calls }));

    // Filter Client Traffic Pulse to ONLY known customer accounts of the
    // currently configured primary switch. The accountNameCache is populated
    // from the primary switch's listSippyAccounts call, so any client name
    // that isn't in this set (carrier connections, vendor names, stale entries
    // from a previously primary switch) is hidden. When the user swaps a
    // secondary switch into primary, the cache repopulates and that switch's
    // accounts will start appearing automatically.
    const knownClientNames = new Set(
      Array.from(accountNameCache.values()).map(n => n.toLowerCase())
    );
    const filteredAggClient: Record<string, number> = {};
    if (knownClientNames.size > 0) {
      for (const [name, calls] of Object.entries(aggClient)) {
        if (knownClientNames.has(name.toLowerCase())) filteredAggClient[name] = calls;
      }
    } else {
      // Cache is empty (e.g. server just started and Sippy hasn't synced) —
      // fall back to showing everything so the page isn't blank.
      Object.assign(filteredAggClient, aggClient);
    }

    const last = concurrentHistory[concurrentHistory.length - 1];
    res.json({
      trend,
      byClient:            toArr(filteredAggClient),
      byVendor:            toArr(aggVendor),
      byCodec:             toArr(aggCodec),
      byDirection:         toArr(aggDir),
      byDestination:       toArr(aggDestination),
      byBreakout:          toArr(aggBreakout),
      byCountry:           toArr(aggCountry),
      cdrByDestination:    toArr(cdrDestMap),
      cdrByCountry:        toArr(cdrCountryMap),
      cdrByBreakout:       toArr(cdrBreakoutMap),
      cdrTotal:            Object.values(cdrDestMap).reduce((s, v) => s + v, 0),
      liveCount:           last?.count ?? 0,
      peakCount:           window.length ? Math.max(...window.map(p => p.count)) : 0,
      windowHours:         hours,
      pointsCollected:     concurrentHistory.length,
      oldestPoint:         concurrentHistory[0]?.ts ?? null,
    });
  });

  // GET /api/dial-lookup/:number — resolve a number to country/breakout/destination
  app.get('/api/dial-lookup/:number', (req: any, res) => {
    const m = lookupDialCode(req.params.number);
    if (!m) return res.json({ found: false, number: req.params.number });
    res.json({ found: true, number: req.params.number, ...m });
  });

  // GET /api/dial-codes — serve raw dial-codes JSON for client-side prefix lookup
  app.get('/api/dial-codes', dialCodesHandler);

  // GET /api/country-codes — serve structured global country + mobile codes (452 entries)
  let _countryCodesJson: string | null = null;
