  // ═══════════════════════════════════════════════════════════════════════════
  // Cost Optimisation Recommendations Engine
  // Multi-factor smart analysis of CDR cache + rate cards → actionable insights
  // ═══════════════════════════════════════════════════════════════════════════
  app.get('/api/cost-optimisation/analyse', (req: any, res: any, next: any) => requireRole(['admin','management'], req, res, next), async (_req: any, res: any) => {
    try {
      const hours = Math.min(720, Math.max(1, Number(_req.query.hours) || 168));
      const cutoff = Date.now() - hours * 3600 * 1000;
      const analysisDays = hours / 24;

      // ── Data prep: portal-primary, CDR cache fallback ─────────────────────
      type VStats = { vendor: string; totalCalls: number; answeredCalls: number; billedSec: number; totalCost: number; pddSum: number; pddN: number; };
      type VM = VStats & { asr: number; acdSec: number; avgPddSec: number; billedMin: number; costPerMin: number; };
      let vendors: VM[] = [];
      let offPeakCalls = 0; let offPeakCost = 0;

      // ── Primary: Sippy portal (authoritative — full volume for cost analysis) ──
      let _costPortalLoaded = false;
      try {
        const settings   = await storage.getSettings();
        const portalUser = settings.portalUsername   || settings.apiAdminUsername || '';
        const portalPass = settings.portalPassword   || settings.apiAdminPassword || '';
        const adminUser  = settings.apiAdminUsername || '';
        const adminPass  = settings.apiAdminPassword || '';
        const toDate     = new Date();
        const fromDate   = new Date(toDate.getTime() - hours * 3600 * 1000);

        const portalResult = await sippy.getSippyPerAccountStats(
          portalUser, portalPass, hours * 60,
          adminUser, adminPass,
          fromDate, toDate,
        );

        if (portalResult.ok && portalResult.vendors.length > 0) {
          vendors = portalResult.vendors
            .filter(r => r.name)
            .map(r => {
              const billedSec  = r.durationSec;
              const billedMin  = billedSec / 60;
              const totalCost  = r.amount;
              const costPerMin = billedMin > 0 ? totalCost / billedMin : 0;
              const avgPddSec  = r.avgPdd;   // portal returns seconds
              return {
                vendor: r.name, totalCalls: r.totalCalls, answeredCalls: r.billableCalls,
                billedSec, totalCost,
                pddSum: avgPddSec > 0 ? avgPddSec * r.billableCalls : 0,
                pddN:   avgPddSec > 0 ? r.billableCalls : 0,
                asr: r.asr, acdSec: r.acdSec, avgPddSec, billedMin, costPerMin,
              };
            });
          vendors.sort((a, b) => b.totalCost - a.totalCost);
          _costPortalLoaded = true;
        } else {
          console.warn('[cost-opt] Portal returned no data — falling back to CDR cache');
        }
      } catch (portalErr: any) {
        console.warn('[cost-opt] Portal error:', (portalErr as any).message, '— falling back to CDR cache');
      }

      // ── Fallback: CDR cache ─────────────────────────────────────────────────
      if (!_costPortalLoaded) {
        const cdrs = [...cdrCache.values()].filter(c => {
          const ts = c.startTime ? new Date(c.startTime).getTime()
            : c.connectTime ? new Date(c.connectTime).getTime() : 0;
          return ts >= cutoff;
        });

        if (cdrs.length === 0) {
          return res.json({ recommendations: [], summary: { totalSpend: 0, estimatedMonthlySpend: 0, totalPotentialMonthlySavings: 0, cdrCount: 0, vendorCount: 0, analysisDays, portfolioCPM: 0, lowestCPM: null }, hours, generatedAt: new Date().toISOString() });
        }

        const vendorMap = new Map<string, VStats>();
        for (const c of cdrs) {
          let vendor = c.vendor || '';
          if (!vendor && c.iConnection) vendor = connectionVendorCache.get(c.iConnection) || '';
          if (!vendor) continue;
          if (!vendorMap.has(vendor)) vendorMap.set(vendor, { vendor, totalCalls: 0, answeredCalls: 0, billedSec: 0, totalCost: 0, pddSum: 0, pddN: 0 });
          const v = vendorMap.get(vendor)!;
          v.totalCalls++;
          const isAns = String(c.result) === '0' && (Number(c.duration) || 0) > 0;
          if (isAns) { v.answeredCalls++; v.billedSec += Number(c.duration) || 0; }
          v.totalCost += Number(c.cost) || 0;
          const pdd = Number(c.pdd1xx ?? c.pdd) || 0;
          if (pdd > 0) { v.pddSum += pdd; v.pddN++; }
          const hr = c.startTime ? new Date(c.startTime).getUTCHours() : -1;
          if (hr >= 0 && hr < 6) { offPeakCalls++; offPeakCost += Number(c.cost) || 0; }
        }

        for (const [, v] of vendorMap) {
          const asr        = v.totalCalls > 0 ? (v.answeredCalls / v.totalCalls) * 100 : 0;
          const acdSec     = v.answeredCalls > 0 ? v.billedSec / v.answeredCalls : 0;
          const avgPddSec  = v.pddN > 0 ? v.pddSum / v.pddN : 0;
          const billedMin  = v.billedSec / 60;
          const costPerMin = billedMin > 0 ? v.totalCost / billedMin : 0;
          vendors.push({ ...v, asr, acdSec, avgPddSec, billedMin, costPerMin });
        }
        vendors.sort((a, b) => b.totalCost - a.totalCost);
      }

      if (vendors.length === 0) {
        return res.json({ recommendations: [], summary: { totalSpend: 0, estimatedMonthlySpend: 0, totalPotentialMonthlySavings: 0, cdrCount: 0, vendorCount: 0, analysisDays, portfolioCPM: 0, lowestCPM: null }, hours, generatedAt: new Date().toISOString() });
      }

      // ── 4. Portfolio aggregates ─────────────────────────────────────────────
      const totalSpend   = vendors.reduce((s, v) => s + v.totalCost, 0);
      const totalMinutes = vendors.reduce((s, v) => s + v.billedMin, 0);
      const totalCalls   = vendors.reduce((s, v) => s + v.totalCalls, 0);
      const portfolioAvgCPM = totalMinutes > 0 ? totalSpend / totalMinutes : 0;
      const cpmVals = vendors.filter(v => v.billedMin > 5).map(v => v.costPerMin);
      const cpmMean = cpmVals.length > 0 ? cpmVals.reduce((a, b) => a + b, 0) / cpmVals.length : 0;
      const cpmStd  = cpmVals.length > 1 ? Math.sqrt(cpmVals.reduce((s, x) => s + (x - cpmMean) ** 2, 0) / cpmVals.length) : 0;
      const lowestCpm = cpmVals.length > 0 ? Math.min(...cpmVals.filter(v => v > 0)) : null;
      const monthlyFactor = 30 / Math.max(analysisDays, 0.5);

      // ── 5. Rate cards (for unmanaged vendor detection) ──────────────────────
      const allCards = await storage.getRateCards();
      const vendorCardNames = new Set(allCards.filter(rc => rc.cardType === 'vendor').map(rc => rc.vendorName.toLowerCase()));

      // ── 6. Recommendation rules ─────────────────────────────────────────────
      type Rec = { id: string; category: string; priority: string; title: string; description: string; vendor?: string; metrics: { label: string; value: string }[]; estimatedMonthlySavings: number; confidence: number; actions: string[]; };
      const recs: Rec[] = [];

      for (const v of vendors) {
        const conf = Math.min(95, 40 + Math.round(v.totalCalls / 5));

        // Rule 1 — High cost vendor
        if (v.billedMin > 10 && cpmStd > 0 && v.costPerMin > cpmMean + cpmStd) {
          const excess = v.costPerMin - cpmMean;
          const savings = excess * v.billedMin * monthlyFactor;
          recs.push({ id: `high-cost-${v.vendor}`, category: 'cost_reduction', priority: savings > 300 ? 'high' : 'medium',
            title: `${v.vendor} — Above-Average Cost Per Minute`,
            description: `At $${v.costPerMin.toFixed(5)}/min, ${v.vendor} is ${((v.costPerMin - cpmMean) / cpmMean * 100).toFixed(1)}% above the portfolio mean ($${cpmMean.toFixed(5)}/min). Renegotiating rates or routing some traffic to lower-cost carriers with comparable quality could generate meaningful savings.`,
            vendor: v.vendor,
            metrics: [{ label: 'Vendor CPM', value: `$${v.costPerMin.toFixed(5)}` }, { label: 'Portfolio Mean CPM', value: `$${cpmMean.toFixed(5)}` }, { label: 'Volume', value: `${v.billedMin.toFixed(0)} min` }, { label: 'ASR', value: `${v.asr.toFixed(1)}%` }],
            estimatedMonthlySavings: savings, confidence: conf,
            actions: [`Request rate revision from ${v.vendor} citing portfolio benchmark data.`, `Test alternative vendors using the LCR Analyser for your key destinations.`, `Set a CPM ceiling threshold alert for this carrier.`] });
        }

        // Rule 2 — Poor quality (low ASR)
        if (v.asr < 50 && v.totalCalls >= 30) {
          const unanswered = v.totalCalls - v.answeredCalls;
          const revLoss = unanswered * 0.05 * monthlyFactor;
          recs.push({ id: `poor-quality-${v.vendor}`, category: 'quality_alert', priority: v.asr < 20 ? 'high' : 'medium',
            title: `${v.vendor} — Low Answer Rate (${v.asr.toFixed(1)}%)`,
            description: `${v.vendor} answered only ${v.asr.toFixed(1)}% of calls — ${unanswered.toLocaleString()} attempts failed over the last ${analysisDays.toFixed(0)} days. Below-benchmark ASR degrades customer experience and inflates cost-per-connected-minute. Consider reducing or suspending traffic allocation.`,
            vendor: v.vendor,
            metrics: [{ label: 'ASR', value: `${v.asr.toFixed(1)}%` }, { label: 'Unanswered', value: unanswered.toLocaleString() }, { label: 'Total Calls', value: v.totalCalls.toLocaleString() }, { label: 'ACD', value: `${v.acdSec.toFixed(0)}s` }],
            estimatedMonthlySavings: revLoss, confidence: Math.min(90, conf),
            actions: [`File a performance SLA breach report with ${v.vendor}.`, `Reduce ${v.vendor}'s traffic weight in Sippy LCR tables.`, `Enable automatic failover to backup carrier on ring timeout.`] });
        }

        // Rule 3 — Zero answer (route failure)
        if (v.answeredCalls === 0 && v.totalCalls >= 10) {
          recs.push({ id: `zero-answer-${v.vendor}`, category: 'anomaly', priority: 'high',
            title: `${v.vendor} — Zero Answered Calls (Route Failure)`,
            description: `${v.vendor} received ${v.totalCalls.toLocaleString()} call attempts with 0% ASR over the last ${analysisDays.toFixed(0)} days — indicating a complete route failure or misconfiguration. All traffic should be immediately re-routed.`,
            vendor: v.vendor,
            metrics: [{ label: 'Call Attempts', value: v.totalCalls.toLocaleString() }, { label: 'ASR', value: '0.0%' }, { label: 'Wasted Spend', value: `$${v.totalCost.toFixed(4)}` }, { label: 'Est. Monthly Loss', value: `$${(v.totalCost * monthlyFactor).toFixed(2)}` }],
            estimatedMonthlySavings: v.totalCost * monthlyFactor, confidence: 98,
            actions: [`Immediately suspend traffic to ${v.vendor}.`, `Contact ${v.vendor} NOC to investigate route failure.`, `Review SIP trace logs for disconnect cause codes.`] });
        }

        // Rule 4 — High PDD
        if (v.avgPddSec > 4 && v.answeredCalls >= 20) {
          const revLoss = v.answeredCalls * Math.min(0.3, (v.avgPddSec - 4) * 0.05) * 0.04 * monthlyFactor;
          recs.push({ id: `high-pdd-${v.vendor}`, category: 'quality_alert', priority: v.avgPddSec > 8 ? 'high' : 'medium',
            title: `${v.vendor} — High Post-Dial Delay (${v.avgPddSec.toFixed(1)}s)`,
            description: `${v.vendor}'s average PDD is ${v.avgPddSec.toFixed(1)}s, well above the ≤2s industry benchmark. Extended ring delay increases caller abandonment and degrades perceived quality scores. Escalate to vendor NOC or configure this carrier as last-resort.`,
            vendor: v.vendor,
            metrics: [{ label: 'Avg PDD', value: `${v.avgPddSec.toFixed(2)}s` }, { label: 'Benchmark', value: '≤ 2.0s' }, { label: 'Answered Calls', value: v.answeredCalls.toLocaleString() }, { label: 'ACD', value: `${v.acdSec.toFixed(0)}s` }],
            estimatedMonthlySavings: revLoss, confidence: 65,
            actions: [`Raise PDD SLA escalation ticket with ${v.vendor}.`, `Re-order LCR table to route through this vendor last.`, `Monitor PDD trend in Vendor SLA Scorecard.`] });
        }

        // Rule 5 — No rate card loaded
        if (!vendorCardNames.has(v.vendor.toLowerCase()) && v.totalCost > 5) {
          const estMonthly = v.totalCost * monthlyFactor;
          recs.push({ id: `no-ratecard-${v.vendor}`, category: 'risk', priority: estMonthly > 200 ? 'high' : 'medium',
            title: `${v.vendor} — No Rate Card Loaded`,
            description: `${v.vendor} has generated an estimated $${estMonthly.toFixed(2)}/month in spend but has no rate card in the system. Without a reference rate card, billing discrepancies may go undetected and LCR optimisation is incomplete.`,
            vendor: v.vendor,
            metrics: [{ label: 'Est. Monthly Spend', value: `$${estMonthly.toFixed(2)}` }, { label: 'Period Spend', value: `$${v.totalCost.toFixed(4)}` }, { label: 'Volume', value: `${v.billedMin.toFixed(0)} min` }],
            estimatedMonthlySavings: 0, confidence: 99,
            actions: [`Upload ${v.vendor}'s rate card in the Rate Card Manager.`, `Use Rate Card → Verify vs Sippy to detect any billing discrepancies.`, `Request the latest rate schedule from ${v.vendor}.`] });
        }

        // Rule 6 — Negotiation leverage
        const shareOfSpend = totalSpend > 0 ? (v.totalCost / totalSpend) * 100 : 0;
        if (shareOfSpend > 25 && v.costPerMin > portfolioAvgCPM && v.billedMin > 30) {
          const savings = v.totalCost * 0.10 * monthlyFactor;
          recs.push({ id: `leverage-${v.vendor}`, category: 'opportunity', priority: 'high',
            title: `${v.vendor} — Negotiation Leverage (${shareOfSpend.toFixed(0)}% of Spend)`,
            description: `${v.vendor} accounts for ${shareOfSpend.toFixed(1)}% of total spend (~$${(v.totalCost * monthlyFactor).toFixed(0)}/mo) at an above-average rate. Your traffic volume gives you significant leverage. A negotiated 10% rate reduction would save an estimated $${savings.toFixed(0)}/month.`,
            vendor: v.vendor,
            metrics: [{ label: 'Spend Share', value: `${shareOfSpend.toFixed(1)}%` }, { label: 'Est. Monthly', value: `$${(v.totalCost * monthlyFactor).toFixed(2)}` }, { label: 'CPM', value: `$${v.costPerMin.toFixed(5)}` }, { label: 'Volume', value: `${v.billedMin.toFixed(0)} min` }],
            estimatedMonthlySavings: savings, confidence: 70,
            actions: [`Schedule a rate review with ${v.vendor} — present traffic volume data.`, `Request volume-discount tier structure.`, `Benchmark competitor rates via LCR Analyser before negotiation.`] });
        }
      }

      // Rule 7 — Vendor concentration risk
      if (vendors.length > 0 && totalCalls > 50) {
        const top = vendors[0];
        const topShare = (top.totalCalls / totalCalls) * 100;
        if (topShare > 60) {
          recs.push({ id: 'concentration-risk', category: 'risk', priority: topShare > 80 ? 'high' : 'medium',
            title: `Concentration Risk — ${top.vendor} Carries ${topShare.toFixed(0)}% of Traffic`,
            description: `${top.vendor} handles ${topShare.toFixed(0)}% of all call traffic. A disruption, rate hike, or outage at this single vendor would severely impact operations. Industry best practice is no single vendor above 40–50%.`,
            vendor: top.vendor,
            metrics: [{ label: 'Traffic Share', value: `${topShare.toFixed(1)}%` }, { label: 'Calls', value: top.totalCalls.toLocaleString() }, { label: 'Active Vendors', value: vendors.filter(v => v.totalCalls > 0).length.toString() }],
            estimatedMonthlySavings: 0, confidence: 95,
            actions: [`Onboard at least one alternative vendor for redundancy.`, `Configure load-balanced routing split across vendors.`, `Set up automatic failover in Sippy for key destination groups.`] });
        }
      }

      // Rule 8 — Best value vendor (expand usage)
      const qualityVendors = vendors.filter(v => v.asr >= 65 && v.billedMin > 20);
      if (qualityVendors.length > 0 && cpmMean > 0) {
        const best = [...qualityVendors].sort((a, b) => a.costPerMin - b.costPerMin)[0];
        if (best.costPerMin < cpmMean * 0.85) {
          const savings = (cpmMean - best.costPerMin) * (totalMinutes * 0.1) * monthlyFactor;
          recs.push({ id: 'best-value-vendor', category: 'opportunity', priority: 'medium',
            title: `${best.vendor} — Best Value Carrier (Expand Usage)`,
            description: `${best.vendor} delivers ${best.asr.toFixed(0)}% ASR at $${best.costPerMin.toFixed(5)}/min — ${((1 - best.costPerMin / cpmMean) * 100).toFixed(0)}% below portfolio average — with excellent quality metrics. Routing additional traffic through this carrier could reduce blended cost.`,
            vendor: best.vendor,
            metrics: [{ label: 'ASR', value: `${best.asr.toFixed(1)}%` }, { label: 'CPM', value: `$${best.costPerMin.toFixed(5)}` }, { label: 'Portfolio Avg', value: `$${cpmMean.toFixed(5)}` }, { label: 'Volume', value: `${best.billedMin.toFixed(0)} min` }],
            estimatedMonthlySavings: savings, confidence: Math.min(80, 40 + Math.round(best.totalCalls / 10)),
            actions: [`Increase ${best.vendor}'s routing weight in Sippy LCR tables.`, `Run LCR Analyser to confirm routing efficiency for key destinations.`, `Negotiate a capacity commitment for further rate improvements.`] });
        }
      }

      // Rule 9 — Off-peak routing opportunity
      const offPeakPct = totalCalls > 0 ? (offPeakCalls / totalCalls) * 100 : 0;
      if (offPeakCalls > 50 && offPeakPct > 5) {
        recs.push({ id: 'off-peak-routing', category: 'strategy', priority: 'low',
          title: `Time-Based Routing — ${offPeakPct.toFixed(0)}% Off-Peak Traffic`,
          description: `${offPeakPct.toFixed(1)}% of calls (${offPeakCalls.toLocaleString()}) occur during off-peak hours (midnight–6am UTC). Many carriers offer reduced off-peak rates. Configuring time-based routing rules to favour cheaper carriers during these hours could reduce blended cost.`,
          metrics: [{ label: 'Off-Peak Calls', value: offPeakCalls.toLocaleString() }, { label: '% of Traffic', value: `${offPeakPct.toFixed(1)}%` }, { label: 'Est. Monthly Off-Peak Spend', value: `$${(offPeakCost * monthlyFactor).toFixed(2)}` }],
          estimatedMonthlySavings: offPeakCost * 0.15 * monthlyFactor, confidence: 55,
          actions: [`Request off-peak rate schedules from your top 3 vendors.`, `Configure time-based routing rules in Sippy dialplan.`, `Use Call Flow Simulator to model routing change impact.`] });
      }

      // ── 7. Sort: priority → estimated savings ──────────────────────────────
      const priOrd: Record<string, number> = { high: 3, medium: 2, low: 1 };
      recs.sort((a, b) => {
        const pd = (priOrd[b.priority] || 0) - (priOrd[a.priority] || 0);
        return pd !== 0 ? pd : b.estimatedMonthlySavings - a.estimatedMonthlySavings;
      });

      const totalSavings = recs.reduce((s, r) => s + r.estimatedMonthlySavings, 0);
      res.json({
        recommendations: recs,
        summary: { totalSpend: parseFloat(totalSpend.toFixed(4)), estimatedMonthlySpend: parseFloat((totalSpend * monthlyFactor).toFixed(2)), totalPotentialMonthlySavings: parseFloat(totalSavings.toFixed(2)), cdrCount: cdrs.length, vendorCount: vendors.length, analysisDays: parseFloat(analysisDays.toFixed(1)), portfolioCPM: parseFloat(portfolioAvgCPM.toFixed(6)), lowestCPM: lowestCpm !== null ? parseFloat(lowestCpm.toFixed(6)) : null },
        hours, generatedAt: new Date().toISOString(),
      });
    } catch (e: any) { res.status(500).json({ message: e.message }); }
  });

  // ── WhatsApp Push Alerts ──────────────────────────────────────────────────

  // POST /api/whatsapp/test — send a test WhatsApp message
  app.post('/api/whatsapp/test', (req: any, res, next) => requireRole(['admin'], req, res, next), async (_req, res) => {
    try {
      const msg = [
        '✅ *Bitsauto Monitoring — Test Alert*',
        '━━━━━━━━━━━━━━━━━━',
        '📡 WhatsApp push alerts are configured correctly.',
        `🕒 ${new Date().toUTCString()}`,
        '━━━━━━━━━━━━━━━━━━',
        '_This is a test message. No action required._',
      ].join('\n');
      const result = await waSvc.sendWhatsAppAlert('test', msg);
      if (result.sent === 0 && result.failed === 0) {
        return res.json({ ok: false, error: 'WhatsApp not enabled or no phone numbers configured.' });
      }
      res.json({ ok: result.failed === 0, sent: result.sent, failed: result.failed });
    } catch (e: any) { res.status(500).json({ ok: false, error: e.message }); }
  });

  // GET /api/whatsapp/logs — delivery log
  app.get('/api/whatsapp/logs', (req: any, res, next) => requireRole(['admin', 'management'], req, res, next), async (_req, res) => {
    try {
      const logs = await storage.getWhatsappAlertLogs(200);
      res.json(logs);
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // ── Global Fix / Diagnostic System ─────────────────────────────────────────

  // ── Sippy API Health State (shared across health endpoint + bg job) ─────────
  const sippyHealth = {
    status:   'unknown' as 'healthy' | 'slow' | 'degraded' | 'unhealthy' | 'unconfigured' | 'unknown',
    auth:     'unknown' as 'valid' | 'invalid' | 'unknown',
    latencyMs:          null as number | null,
    lastSuccessAt:      null as Date | null,
    lastCheckedAt:      null as Date | null,
    lastError:          null as string | null,
    consecutiveFailures: 0,
    totalChecks:         0,
    recentChecks: [] as Array<{ at: string; ok: boolean; latencyMs: number; status: string }>,
  };

  // Helper — run one Sippy health probe (rate-limited to 60s unless forced)
  const runSippyHealthCheck = async (force = false): Promise<void> => {
    if (!force && sippyHealth.lastCheckedAt && Date.now() - sippyHealth.lastCheckedAt.getTime() < 60_000) return;
    sippyHealth.totalChecks++;
    sippyHealth.lastCheckedAt = new Date();

    // Check live session first — this is the authoritative source of connectivity.
    // We only read settings as a fallback to detect "truly unconfigured" state.
    const sess = sippy.getSippySessionStatus();
    const probeLatency = lastProbeResult?.latency ?? lastSwitchProbeResult?.latency ?? null;
    const lat = probeLatency ?? 0;

    if (sess.active) {
      // Session is live — definitely healthy regardless of settings read outcome.
      sippyHealth.latencyMs           = lat;
      sippyHealth.lastSuccessAt       = new Date();
      sippyHealth.auth                = 'valid';
      sippyHealth.consecutiveFailures = 0;
      sippyHealth.lastError           = null;
      sippyHealth.status              = lat > 5000 ? 'slow' : lat > 2000 ? 'slow' : 'healthy';
      sippyHealth.recentChecks.push({ at: new Date().toISOString(), ok: true, latencyMs: lat, status: sippyHealth.status });
    } else {
      // Session not active — check whether Sippy is configured at all.
      let settings: any = null;
      try { settings = await storage.getSippySettings(); } catch {}
      if (!settings?.portalUrl && !settings?.apiAdminUsername) {
        // No settings saved — genuinely unconfigured.
        sippyHealth.status = 'unconfigured';
        sippyHealth.auth   = 'unknown';
        // Don't push to recentChecks or count as a failure — just no config yet.
        return;
      }
      // Settings exist but session is inactive — connection failure.
      sippyHealth.consecutiveFailures++;
      sippyHealth.lastError  = 'No active Sippy session — portal login failed or credentials rejected.';
      sippyHealth.auth       = 'invalid';
      sippyHealth.status     = 'unhealthy';
      sippyHealth.latencyMs  = null;
      sippyHealth.recentChecks.push({ at: new Date().toISOString(), ok: false, latencyMs: 0, status: sippyHealth.status });
    }
    if (sippyHealth.recentChecks.length > 100) sippyHealth.recentChecks = sippyHealth.recentChecks.slice(-100);
  };

  // GET /api/sippy/health — real-time Sippy API health probe (all authenticated roles)
  app.get('/api/sippy/health', async (req: any, res: any) => {
    if (!req.isAuthenticated?.()) return res.status(401).json({ error: 'Unauthorized' });
    // Use cached health data (rate-limited to 60s) — avoids triggering an extra portal scrape
    // on every frontend poll. The background health probe already runs every 60 seconds.
    await runSippyHealthCheck(false);
    const last20    = sippyHealth.recentChecks.slice(-20);
    const errorRate = last20.length > 0
      ? ((last20.filter((c: any) => !c.ok).length / last20.length) * 100).toFixed(1) + '%'
      : '0.0%';
    const uptimeRate = last20.length > 0
      ? ((last20.filter((c: any) => c.ok).length / last20.length) * 100).toFixed(1) + '%'
      : '100.0%';
    res.json({
      status:               sippyHealth.status,
      auth:                 sippyHealth.auth,
      latency_ms:           sippyHealth.latencyMs,
      last_success_call:    sippyHealth.lastSuccessAt?.toISOString() ?? null,
      error:                sippyHealth.lastError,
      error_rate:           errorRate,
      uptime_rate:          uptimeRate,
      total_checks:         sippyHealth.totalChecks,
      consecutive_failures: sippyHealth.consecutiveFailures,
      recent_checks:        sippyHealth.recentChecks.slice(-10),
      checked_at:           sippyHealth.lastCheckedAt?.toISOString() ?? null,
    });
  });

  // GET /api/sippy/health/history — last 100 health check records
  app.get('/api/sippy/health/history', async (req: any, res: any) => {
    if (!req.isAuthenticated?.()) return res.status(401).json({ error: 'Unauthorized' });
    res.json({ history: sippyHealth.recentChecks.slice(-100) });
  });

  // Background Sippy health probe every 60 seconds
  setInterval(async () => { try { await runSippyHealthCheck(true); } catch {} }, 60_000);
  // Initial probe after server warms up (5s delay)
  setTimeout(async () => { try { await runSippyHealthCheck(true); } catch {} }, 5_000);

  // ── Phase 3: Auto-recovery state (shared across job + endpoints) ────────────
  const autoRecovery = {
    consecutiveSippyFailures: 0,
    lastAutoFixAt:            null as Date | null,
    cooldownMs:               5 * 60 * 1000, // 5-minute cooldown between auto-retries
    rules: [
      { id: 'sippy_retry',    name: 'Auto Retry Sippy API',    trigger: 'sippy_fail_3x',  enabled: true,  description: 'Triggers after 3 consecutive Sippy API failures. Logs auto-recovery event and retries connection.' },
      { id: 'cdr_stale_log',  name: 'CDR Cache Stale Alert',   trigger: 'cdr_stale_15m',  enabled: true,  description: 'Logs a warning when CDR cache has not refreshed in 15+ minutes.' },
    ],
    stats: { totalAutoFixes: 0, lastEvent: null as string | null },
  };

  // GET /api/fix/diagnose — full system health check (admin + management)
  // Optional query params: ?module=<page name> for module-specific additional checks
  //                        ?errors=<JSON array of frontend error strings>
  app.get('/api/fix/diagnose', (req: any, res: any, next: any) => requireRole(['admin', 'management'], req, res, next), async (req: any, res: any) => {
    const t0 = Date.now();
    const moduleName: string = (req.query.module as string | undefined) ?? '';
    let frontendErrors: string[] = [];
    try { frontendErrors = JSON.parse(req.query.errors as string || '[]'); } catch {}

    type CheckStatus = 'ok' | 'warn' | 'fail' | 'skip';
    type IssueSeverity = 'critical' | 'warning' | 'info';
    const checks: Array<{ id: string; name: string; status: CheckStatus; detail: string; durationMs: number }> = [];
    const issues: Array<{ type: string; severity: IssueSeverity; component: string; message: string; suggestion: string; autoFix: string | null; pastFix?: { action: string; outcome: string; performedBy: string | null; createdAt: string } | null }> = [];

    // ── 1. Settings configured? ──────────────────────────────────────────────
    let settings: any = null;
    const ts1 = Date.now();
    try {
      settings = await storage.getSippySettings();
      if (!settings?.portalUrl || !settings?.apiAdminUsername || !settings?.apiAdminPassword) {
        checks.push({ id: 'settings', name: 'Sippy Credentials', status: 'fail', detail: 'Portal URL, username or password missing', durationMs: Date.now() - ts1 });
        issues.push({ type: 'AUTH_ERROR', severity: 'critical', component: 'Settings', message: 'Sippy API credentials are not fully configured.', suggestion: 'Navigate to Settings → General Settings and enter the Sippy portal URL, admin username, and admin password.', autoFix: null });
      } else {
        checks.push({ id: 'settings', name: 'Sippy Credentials', status: 'ok', detail: `Portal: ${settings.portalUrl} · User: ${settings.apiAdminUsername}`, durationMs: Date.now() - ts1 });
      }
    } catch (e: any) {
      checks.push({ id: 'settings', name: 'Sippy Credentials', status: 'fail', detail: e.message, durationMs: Date.now() - ts1 });
      issues.push({ type: 'BACKEND_ERROR', severity: 'critical', component: 'Database', message: 'Cannot read Sippy settings from database: ' + e.message, suggestion: 'Check the PostgreSQL connection. The settings table may be inaccessible.', autoFix: 'check_db' });
    }

    // ── 2. Sippy session status ──────────────────────────────────────────────
    const ts2 = Date.now();
    try {
      const status = sippy.getSippySessionStatus();
      if (!status.mode || status.mode === 'none') {
        checks.push({ id: 'sippy_session', name: 'Sippy API Session', status: 'fail', detail: 'Session not established', durationMs: Date.now() - ts2 });
        issues.push({ type: 'API_FAILURE', severity: 'critical', component: 'Sippy API', message: 'No active Sippy API session found.', suggestion: 'The system has not established an XML-RPC session with Sippy. Check credentials and retry the API connection.', autoFix: 'retry_sippy' });
      } else {
        checks.push({ id: 'sippy_session', name: 'Sippy API Session', status: 'ok', detail: `Mode: ${status.mode} · User: ${status.username || 'n/a'}`, durationMs: Date.now() - ts2 });
      }
    } catch (e: any) {
      checks.push({ id: 'sippy_session', name: 'Sippy API Session', status: 'fail', detail: e.message, durationMs: Date.now() - ts2 });
      issues.push({ type: 'API_FAILURE', severity: 'critical', component: 'Sippy API', message: 'Error reading Sippy session: ' + e.message, suggestion: 'Restart the server or re-enter credentials in Settings.', autoFix: 'retry_sippy' });
    }

    // ── 3. Sippy live API call (listActiveCalls) — also caches result for module checks
    let cachedActiveCalls: any[] | null = null;
    const ts3 = Date.now();
    if (settings?.portalUrl && settings?.apiAdminUsername && settings?.apiAdminPassword) {
      try {
        cachedActiveCalls = await sippy.getSippyActiveCalls(settings.apiAdminUsername, settings.apiAdminPassword, settings.portalUrl, undefined, undefined, undefined, true);
        autoRecovery.consecutiveSippyFailures = 0;
        checks.push({ id: 'sippy_live', name: 'Sippy Live API Test', status: 'ok', detail: `listActiveCalls returned ${cachedActiveCalls.length} active calls`, durationMs: Date.now() - ts3 });
      } catch (e: any) {
        autoRecovery.consecutiveSippyFailures++;
        const msg = (e.message || '').toLowerCase();
        const isTimeout = msg.includes('timeout') || msg.includes('timed out') || msg.includes('etimedout');
        const isAuth    = msg.includes('auth') || msg.includes('401') || msg.includes('403') || msg.includes('unauthorized');
        checks.push({ id: 'sippy_live', name: 'Sippy Live API Test', status: 'fail', detail: e.message, durationMs: Date.now() - ts3 });
        if (isTimeout) {
          issues.push({ type: 'TIMEOUT', severity: 'critical', component: 'Sippy API', message: `Sippy API timed out: ${e.message}`, suggestion: 'The Sippy server did not respond within the timeout. Check network, firewall, and whether the Sippy service is running. Try Retry API below.', autoFix: 'retry_sippy' });
        } else if (isAuth) {
          issues.push({ type: 'AUTH_ERROR', severity: 'critical', component: 'Sippy API', message: `Sippy authentication rejected: ${e.message}`, suggestion: 'The Sippy server returned an auth error. Verify admin username and password in Settings → General Settings are correct for this Sippy version.', autoFix: null });
        } else {
          issues.push({ type: 'API_FAILURE', severity: 'critical', component: 'Sippy API', message: `API call failed: ${e.message}`, suggestion: 'Unexpected error contacting Sippy. Check server logs for details. Use Retry API below to attempt reconnection.', autoFix: 'retry_sippy' });
        }
      }
    } else {
      checks.push({ id: 'sippy_live', name: 'Sippy Live API Test', status: 'skip', detail: 'Skipped — credentials not configured', durationMs: Date.now() - ts3 });
    }

    // ── 4. CDR cache health ──────────────────────────────────────────────────
    const ts4 = Date.now();
    const cdrSz  = cdrCache.size;
    const cdrAge = cdrCacheUpdatedAt ? Date.now() - cdrCacheUpdatedAt.getTime() : null;
    const isStale = cdrAge !== null && cdrAge > 10 * 60 * 1000;
    if (cdrSz === 0) {
      checks.push({ id: 'cdr_cache', name: 'CDR Cache', status: 'warn', detail: 'Empty — no CDR data loaded yet', durationMs: Date.now() - ts4 });
      issues.push({ type: 'NO_DATA', severity: 'warning', component: 'CDR Cache', message: 'CDR cache is empty. Analytics, FAS and Reports will show no data.', suggestion: 'The cache warms automatically every 3 minutes. If it stays empty, check that the Sippy API is reachable and CDR permissions are granted to the admin account.', autoFix: 'warm_cdr_cache' });
    } else if (isStale) {
      checks.push({ id: 'cdr_cache', name: 'CDR Cache', status: 'warn', detail: `${cdrSz.toLocaleString()} records · ${Math.round(cdrAge! / 60000)}m old (stale >10m)`, durationMs: Date.now() - ts4 });
      issues.push({ type: 'DATA_MISMATCH', severity: 'warning', component: 'CDR Cache', message: `CDR cache has not refreshed in ${Math.round(cdrAge! / 60000)} minutes.`, suggestion: 'The background CDR job may have stalled. Check server logs for [cdr-cache] errors. If no errors appear, the Sippy CDR API may be returning empty results.', autoFix: 'warm_cdr_cache' });
    } else {
      checks.push({ id: 'cdr_cache', name: 'CDR Cache', status: 'ok', detail: `${cdrSz.toLocaleString()} records · updated ${cdrAge !== null ? Math.round(cdrAge / 1000) + 's ago' : 'recently'}`, durationMs: Date.now() - ts4 });
    }

    // ── 5. Database connectivity ─────────────────────────────────────────────
    const ts5 = Date.now();
    try {
      await storage.getSippySettings();
      checks.push({ id: 'database', name: 'PostgreSQL Database', status: 'ok', detail: 'Read query succeeded', durationMs: Date.now() - ts5 });
    } catch (e: any) {
      checks.push({ id: 'database', name: 'PostgreSQL Database', status: 'fail', detail: e.message, durationMs: Date.now() - ts5 });
      issues.push({ type: 'BACKEND_ERROR', severity: 'critical', component: 'Database', message: `Database unreachable: ${e.message}`, suggestion: 'Check the DATABASE_URL environment variable and confirm PostgreSQL is running.', autoFix: null });
    }

    // ── 6. FAS/IRSF engine health ────────────────────────────────────────────
    const ts6 = Date.now();
    try {
      await storage.getFasEvents(1);
      checks.push({ id: 'fas', name: 'FAS / IRSF Engine', status: 'ok', detail: `Engine active — events found in DB`, durationMs: Date.now() - ts6 });
    } catch (e: any) {
      checks.push({ id: 'fas', name: 'FAS / IRSF Engine', status: 'warn', detail: 'Cannot verify: ' + e.message, durationMs: Date.now() - ts6 });
    }

    // ── Module-specific additional checks ────────────────────────────────────
    const mod = moduleName.toLowerCase();

    // LIVE CALLS module
    if (mod === 'live calls') {
      const tsM = Date.now();
      if (cachedActiveCalls !== null) {
        if (cachedActiveCalls.length === 0) {
          checks.push({ id: 'mod_live_calls', name: 'Active Call Count', status: 'warn', detail: 'No active calls at this moment', durationMs: Date.now() - tsM });
          issues.push({ type: 'NO_DATA', severity: 'info', component: 'Live Calls', message: 'There are currently no active calls on the Sippy switch.', suggestion: 'This may be normal during off-peak hours. If you expect traffic, verify that trunks are UP in Sippy and that the correct account is selected.', autoFix: 'refresh_accounts' });
        } else {
          checks.push({ id: 'mod_live_calls', name: 'Active Call Count', status: 'ok', detail: `${cachedActiveCalls.length} call(s) confirmed live`, durationMs: Date.now() - tsM });
        }
      }
    }

    // CDR VIEWER module
    if (mod === 'cdr viewer') {
      const tsM = Date.now();
      if (cdrSz < 10) {
        checks.push({ id: 'mod_cdr_volume', name: 'CDR Data Volume', status: 'warn', detail: `Only ${cdrSz} CDR records — very low for analysis`, durationMs: Date.now() - tsM });
        issues.push({ type: 'NO_DATA', severity: 'warning', component: 'CDR Viewer', message: `CDR cache has only ${cdrSz} records. The viewer may show empty results.`, suggestion: 'Ensure the Sippy CDR API is accessible and the admin account has "showcdrs" permission. Try widening the date range filter in the CDR viewer.', autoFix: 'warm_cdr_cache' });
      } else {
        checks.push({ id: 'mod_cdr_volume', name: 'CDR Data Volume', status: 'ok', detail: `${cdrSz.toLocaleString()} CDRs available for viewing`, durationMs: Date.now() - tsM });
      }
    }

    // ANALYTICS module
    if (mod === 'analytics') {
      const tsM = Date.now();
      if (cdrSz < 100) {
        checks.push({ id: 'mod_analytics_data', name: 'Analytics Data Volume', status: 'warn', detail: `${cdrSz} records — analytics charts may be incomplete`, durationMs: Date.now() - tsM });
        issues.push({ type: 'NO_DATA', severity: 'warning', component: 'Analytics', message: `Analytics requires more CDR data. Currently ${cdrSz} records — charts and stats may be unreliable.`, suggestion: 'Analytics is most accurate with 1,000+ CDR records. Ensure the CDR cache is refreshing successfully and the time range covers a period with traffic.', autoFix: 'warm_cdr_cache' });
      } else {
        checks.push({ id: 'mod_analytics_data', name: 'Analytics Data Volume', status: 'ok', detail: `${cdrSz.toLocaleString()} CDRs available — analytics ready`, durationMs: Date.now() - tsM });
      }
      if (cdrAge !== null && cdrAge > 5 * 60 * 1000) {
        const tsM2 = Date.now();
        checks.push({ id: 'mod_analytics_age', name: 'Analytics Data Freshness', status: 'warn', detail: `Data is ${Math.round(cdrAge / 60000)}m old — charts show older state`, durationMs: Date.now() - tsM2 });
      }
    }

    // FRAUD DETECTION module
    if (mod === 'fraud detection') {
      const tsM = Date.now();
      try {
        const fasEvents = await storage.getFasEvents(5);
        checks.push({ id: 'mod_fraud_events', name: 'Fraud Engine Events', status: 'ok', detail: `FAS engine active — recent events visible`, durationMs: Date.now() - tsM });
        if (fasEvents.length === 0) {
          issues.push({ type: 'NO_DATA', severity: 'info', component: 'Fraud Detection', message: 'No fraud events detected yet. This is normal if traffic patterns are within expected thresholds.', suggestion: 'Run the FAS analysis on the Analytics page to trigger event generation. Ensure CDR cache is populated.', autoFix: 'warm_cdr_cache' });
        }
      } catch (e: any) {
        checks.push({ id: 'mod_fraud_events', name: 'Fraud Engine Events', status: 'fail', detail: e.message, durationMs: Date.now() - tsM });
        issues.push({ type: 'BACKEND_ERROR', severity: 'warning', component: 'Fraud Detection', message: `Cannot read FAS events: ${e.message}`, suggestion: 'Check the database connection and ensure the FAS events table exists.', autoFix: 'check_db' });
      }
    }

    // P&L REPORT module
    if (mod === 'p&l report') {
      const tsM = Date.now();
      if (cdrSz === 0) {
        checks.push({ id: 'mod_pl_data', name: 'P&L Data Source', status: 'fail', detail: 'No CDR data — P&L report will be empty', durationMs: Date.now() - tsM });
        issues.push({ type: 'NO_DATA', severity: 'critical', component: 'P&L Report', message: 'P&L report requires CDR data. The cache is empty — revenue and cost calculations cannot be performed.', suggestion: 'Warm the CDR cache first, then reload the P&L report. Ensure date range covers a period with completed calls.', autoFix: 'warm_cdr_cache' });
      } else {
        checks.push({ id: 'mod_pl_data', name: 'P&L Data Source', status: 'ok', detail: `${cdrSz.toLocaleString()} CDRs available for cost/revenue analysis`, durationMs: Date.now() - tsM });
      }
      const tsM2 = Date.now();
      try {
        const rateCards = await storage.getRateCards();
        if (rateCards.length === 0) {
          checks.push({ id: 'mod_pl_rates', name: 'Rate Cards (P&L)', status: 'warn', detail: 'No rate cards configured — cost calculations will be $0', durationMs: Date.now() - tsM2 });
          issues.push({ type: 'NO_DATA', severity: 'warning', component: 'P&L Report', message: 'No rate cards found. P&L report will show $0 buy/sell costs.', suggestion: 'Upload rate cards in the Rate Cards section. Assign buy-rate cards to vendors and sell-rate cards to customers.', autoFix: null });
        } else {
          checks.push({ id: 'mod_pl_rates', name: 'Rate Cards (P&L)', status: 'ok', detail: `${rateCards.length} rate card(s) configured`, durationMs: Date.now() - tsM2 });
        }
      } catch {}
    }

    // BILLING / BALANCE MONITOR module
    if (mod === 'billing' || mod === 'balance monitor') {
      const tsM = Date.now();
      try {
        // Check live Sippy account reachability using the in-memory cache (populated at startup).
        // clientProfiles are local billing profiles (optional), NOT the Balance Monitor's data source.
        // The Balance Monitor fetches accounts directly from Sippy — so we check the accountNameCache.
        const cachedAccountCount = accountNameCache.size;
        if (cachedAccountCount > 0) {
          checks.push({ id: 'mod_billing_accounts', name: 'Sippy Accounts (Balance Monitor)', status: 'ok', detail: `${cachedAccountCount} account(s) in cache — balance monitor data available`, durationMs: Date.now() - tsM });
        } else {
          // Try a live fetch with credential retry
          const bSettings = await storage.getSippySettings();
          const bPortalUrl = bSettings ? sippyPortalUrl(bSettings) : '';
          const { accounts: bAccounts } = bSettings
            ? await withSippyCreds(bSettings, (u, p) => sippy.listSippyAccounts(u, p, {}, bPortalUrl))
            : { accounts: [] };
          if (bAccounts && bAccounts.length > 0) {
            checks.push({ id: 'mod_billing_accounts', name: 'Sippy Accounts (Balance Monitor)', status: 'ok', detail: `${bAccounts.length} account(s) reachable from Sippy`, durationMs: Date.now() - tsM });
          } else {
            checks.push({ id: 'mod_billing_accounts', name: 'Sippy Accounts (Balance Monitor)', status: 'warn', detail: 'Account list is empty — Sippy may be unreachable or credentials need refresh', durationMs: Date.now() - tsM });
            issues.push({ type: 'NO_DATA', severity: 'warning', component: 'Balance Monitor', message: 'Sippy account list returned empty. Balance Monitor may show no data.', suggestion: 'Click "Refresh Accounts" to re-sync accounts from Sippy. Verify Sippy API credentials in Settings.', autoFix: 'refresh_accounts' });
          }
        }
      } catch {}
    }

    // RATE CARDS module
    if (mod === 'rate cards') {
      const tsM = Date.now();
      try {
        const rateCards = await storage.getRateCards();
        if (rateCards.length === 0) {
          checks.push({ id: 'mod_rate_cards', name: 'Rate Card Data', status: 'warn', detail: 'No rate cards in database', durationMs: Date.now() - tsM });
          issues.push({ type: 'NO_DATA', severity: 'warning', component: 'Rate Cards', message: 'No rate cards are configured. LCR and P&L analysis will not have pricing data.', suggestion: 'Upload a rate card CSV using the "Import" button. Ensure the file uses the correct column format (destination, rate, prefix).', autoFix: null });
        } else {
          const totalEntries = rateCards.reduce((s: number, rc: any) => s + (rc.entryCount || 0), 0);
          checks.push({ id: 'mod_rate_cards', name: 'Rate Card Data', status: 'ok', detail: `${rateCards.length} rate card(s) · ${totalEntries.toLocaleString()} entries`, durationMs: Date.now() - tsM });
        }
      } catch (e: any) {
        checks.push({ id: 'mod_rate_cards', name: 'Rate Card Data', status: 'fail', detail: e.message, durationMs: Date.now() - tsM });
      }
    }

    // LCR ANALYSER module
    if (mod === 'lcr analyser') {
      const tsM = Date.now();
      const vendorCount = connectionVendorCache.size;
      if (vendorCount === 0) {
        checks.push({ id: 'mod_lcr_vendors', name: 'LCR Vendor Data', status: 'warn', detail: 'No vendor connections loaded — LCR cannot compare routes', durationMs: Date.now() - tsM });
        issues.push({ type: 'NO_DATA', severity: 'warning', component: 'LCR Analyser', message: 'No vendor connections loaded. LCR analysis requires vendor connections with rate cards assigned.', suggestion: 'Sync vendors from Sippy using "Refresh Vendors", then assign buy-rate cards to each vendor in the Rate Cards section.', autoFix: 'refresh_vendors' });
      } else {
        checks.push({ id: 'mod_lcr_vendors', name: 'LCR Vendor Data', status: 'ok', detail: `${vendorCount} vendor connection(s) available for LCR analysis`, durationMs: Date.now() - tsM });
      }
    }

    // SETTINGS module — extra credential validation
    if (mod === 'settings') {
      const tsM = Date.now();
      const sess = sippy.getSippySessionStatus();
      if (sess.mode && sess.mode !== 'none') {
        checks.push({ id: 'mod_settings_api', name: 'API Connectivity (Settings)', status: 'ok', detail: `Connected via ${sess.mode} · User: ${sess.username || 'n/a'}`, durationMs: Date.now() - tsM });
      } else {
        checks.push({ id: 'mod_settings_api', name: 'API Connectivity (Settings)', status: 'fail', detail: 'No active session — credentials may be wrong', durationMs: Date.now() - tsM });
        issues.push({ type: 'AUTH_ERROR', severity: 'critical', component: 'Settings', message: 'Sippy API session is not established. Verify credentials on this page and save.', suggestion: 'Re-enter the Sippy portal URL, admin username and password. For old Python 2 Sippy builds, use HTTP not HTTPS and port 9900 for XML-RPC.', autoFix: 'retry_sippy' });
      }
    }

    // SERVER MONITORING module
    if (mod === 'server monitoring') {
      const tsM = Date.now();
      if (cachedActiveCalls !== null) {
        checks.push({ id: 'mod_server_calls', name: 'Live Call Visibility', status: 'ok', detail: `Sippy API responsive — ${cachedActiveCalls.length} active calls`, durationMs: Date.now() - tsM });
      }
    }

    // MULTI-SWITCH VIEW module
    if (mod === 'multi-switch view') {
      const tsM = Date.now();
      if (cachedActiveCalls !== null) {
        checks.push({ id: 'mod_multi_switch', name: 'Switch API Connectivity', status: 'ok', detail: `Primary switch responding — ${cachedActiveCalls.length} calls`, durationMs: Date.now() - tsM });
      }
    }

    // BITSEYE module
    if (mod === 'bitseye') {
      const tsM = Date.now();
      if (cdrSz > 0) {
        checks.push({ id: 'mod_bitseye_data', name: 'BitsEye CDR Source', status: 'ok', detail: `${cdrSz.toLocaleString()} CDRs available for drill-down`, durationMs: Date.now() - tsM });
      } else {
        checks.push({ id: 'mod_bitseye_data', name: 'BitsEye CDR Source', status: 'warn', detail: 'No CDR data — BitsEye drill-down will be empty', durationMs: Date.now() - tsM });
        issues.push({ type: 'NO_DATA', severity: 'warning', component: 'BitsEye', message: 'BitsEye requires CDR data to power drill-down analysis. Cache is empty.', suggestion: 'Ensure the CDR cache is populated. The background warmer runs every 3 minutes.', autoFix: 'warm_cdr_cache' });
      }
    }

    // PRODUCT CLASSIFICATION module
    if (mod === 'product classification') {
      const tsM = Date.now();
      if (cdrSz < 50) {
        checks.push({ id: 'mod_products_data', name: 'Product Classification Data', status: 'warn', detail: `Only ${cdrSz} CDRs — product charts may be incomplete`, durationMs: Date.now() - tsM });
        issues.push({ type: 'NO_DATA', severity: 'info', component: 'Product Classification', message: 'Product classification charts require CDR data grouped by CLD prefix. Insufficient data loaded.', suggestion: 'Warm the CDR cache. Ensure CDRs contain valid CLD numbers (not empty or malformed).', autoFix: 'warm_cdr_cache' });
      } else {
        checks.push({ id: 'mod_products_data', name: 'Product Classification Data', status: 'ok', detail: `${cdrSz.toLocaleString()} CDRs ready for classification`, durationMs: Date.now() - tsM });
      }
    }

    // CLICK-TO-CALL module
    if (mod === 'click-to-call') {
      const tsM = Date.now();
      if (cachedActiveCalls !== null) {
        checks.push({ id: 'mod_ctc_api', name: 'Click-to-Call API', status: 'ok', detail: 'Sippy API reachable — calls can be initiated', durationMs: Date.now() - tsM });
      } else {
        checks.push({ id: 'mod_ctc_api', name: 'Click-to-Call API', status: 'fail', detail: 'Sippy API unreachable — call initiation will fail', durationMs: Date.now() - tsM });
        issues.push({ type: 'API_FAILURE', severity: 'critical', component: 'Click-to-Call', message: 'Sippy API is not responding. Click-to-Call operations will fail.', suggestion: 'Restore the Sippy API connection before attempting to initiate calls. Use Retry Sippy API below.', autoFix: 'retry_sippy' });
      }
    }

    // REPORTS module
    if (mod === 'reports') {
      const tsM = Date.now();
      if (cdrSz === 0) {
        checks.push({ id: 'mod_reports_data', name: 'Reports Data Source', status: 'warn', detail: 'No CDR data — all reports will show empty', durationMs: Date.now() - tsM });
        issues.push({ type: 'NO_DATA', severity: 'warning', component: 'Reports', message: 'Reports module requires CDR data. All charts and tables will be empty.', suggestion: 'Warm the CDR cache. Reports are built from the same CDR dataset as Analytics.', autoFix: 'warm_cdr_cache' });
      } else {
        checks.push({ id: 'mod_reports_data', name: 'Reports Data Source', status: 'ok', detail: `${cdrSz.toLocaleString()} CDRs — reports ready`, durationMs: Date.now() - tsM });
      }
    }

    // TEAM MANAGEMENT module
    if (mod === 'team management') {
      const tsM = Date.now();
      try {
        const kams = await storage.getKams();
        checks.push({ id: 'mod_team_data', name: 'KAM / Team Data', status: 'ok', detail: `${kams.length} KAM(s) configured in database`, durationMs: Date.now() - tsM });
        if (kams.length === 0) {
          issues.push({ type: 'NO_DATA', severity: 'info', component: 'Team Management', message: 'No KAMs (Key Account Managers) are configured yet.', suggestion: 'Add KAMs from the Team Management page using the "Add KAM" button. Assign accounts to each KAM for tracking.', autoFix: null });
        }
      } catch (e: any) {
        checks.push({ id: 'mod_team_data', name: 'KAM / Team Data', status: 'fail', detail: e.message, durationMs: Date.now() - tsM });
      }
    }

    // DASHBOARD module
    if (mod === 'dashboard' || mod === '') {
      const tsM = Date.now();
      const apiHealthy = checks.find(c => c.id === 'sippy_live')?.status === 'ok';
      const dbHealthy  = checks.find(c => c.id === 'database')?.status === 'ok';
      if (apiHealthy && dbHealthy && cdrSz > 0) {
        checks.push({ id: 'mod_dashboard_readiness', name: 'Dashboard Data Readiness', status: 'ok', detail: 'All data sources healthy — dashboard fully operational', durationMs: Date.now() - tsM });
      } else {
        checks.push({ id: 'mod_dashboard_readiness', name: 'Dashboard Data Readiness', status: 'warn', detail: 'One or more data sources degraded — some widgets may be empty', durationMs: Date.now() - tsM });
      }
    }

    // ── Frontend error injection (Step 2: Collect Logs) ───────────────────────
    if (frontendErrors.length > 0) {
      const tsF = Date.now();
      checks.push({ id: 'frontend_errors', name: 'Frontend Console Errors', status: 'warn', detail: `${frontendErrors.length} error(s) captured in browser console`, durationMs: Date.now() - tsF });
      issues.push({ type: 'UI_ERROR', severity: 'warning', component: 'Frontend', message: `${frontendErrors.length} JavaScript error(s) detected in the browser console.`, suggestion: `Errors: ${frontendErrors.slice(0, 3).join(' | ')}${frontendErrors.length > 3 ? ` … and ${frontendErrors.length - 3} more` : ''}. Open browser DevTools (F12 → Console) to see full details.`, autoFix: null });
    }

    // ── Phase 3: Look up past successful fixes for each issue ─────────────────
    const issuesWithHistory = await Promise.all(
      issues.map(async issue => {
        try {
          const past = await storage.findSimilarFix(issue.type, issue.component);
          return { ...issue, pastFix: past ? { action: past.fixAction ?? 'unknown', outcome: past.outcome, performedBy: past.performedBy ?? null, createdAt: past.createdAt.toISOString() } : null };
        } catch { return { ...issue, pastFix: null }; }
      })
    );

    const hasCritical = issuesWithHistory.some(i => i.severity === 'critical');
    const hasWarning  = issuesWithHistory.some(i => i.severity === 'warning');

    res.json({
      status: hasCritical ? 'critical' : hasWarning ? 'warning' : 'ok',
      checks,
      issues: issuesWithHistory,
      module: moduleName,
      frontendErrorsReceived: frontendErrors.length,
      summary: {
        total:    checks.length,
        passed:   checks.filter(c => c.status === 'ok').length,
        warnings: checks.filter(c => c.status === 'warn').length,
        failed:   checks.filter(c => c.status === 'fail').length,
        skipped:  checks.filter(c => c.status === 'skip').length,
      },
      cdrCacheSize: cdrSz,
      cdrCacheAgeMs: cdrAge,
      autoRecovery: {
        consecutiveFailures: autoRecovery.consecutiveSippyFailures,
        lastAutoFixAt: autoRecovery.lastAutoFixAt?.toISOString() ?? null,
        totalAutoFixes: autoRecovery.stats.totalAutoFixes,
      },
      diagnosedAt: new Date().toISOString(),
      durationMs: Date.now() - t0,
    });
  });

  // POST /api/fix/attempt — attempt an automated fix action (records to fix_history)
  app.post('/api/fix/attempt', (req: any, res: any, next: any) => requireRole(['admin', 'management'], req, res, next), async (req: any, res: any) => {
    const { action, page, issueType, component, screenshot } = req.body as { action: string; page?: string; issueType?: string; component?: string; screenshot?: string };
    const t0 = Date.now();
    const performer = (req as any).user?.email || (req as any).user?.id || 'unknown';

    const recordHistory = async (outcome: string, message: string) => {
      try {
        await storage.addFixHistoryEntry({
          page:           page ?? 'system',
          issueType:      issueType ?? 'UNKNOWN',
          component:      component ?? action,
          fixAction:      action,
          outcome,
          outcomeMessage: message,
          triggeredBy:    'manual',
          performedBy:    performer,
          screenshot:     screenshot || null,
        });
      } catch {} // Don't let history write failure break the fix
    };

    try {
      switch (action) {
        case 'retry_sippy': {
          const settings = await storage.getSippySettings();
          if (!settings?.portalUrl) {
            await recordHistory('failure', 'Sippy settings not configured.');
            return res.json({ ok: false, message: 'Sippy settings not configured. Enter credentials in Settings first.', durationMs: Date.now() - t0 });
          }
          try {
            const activeCalls = await sippy.getSippyActiveCalls(settings.apiAdminUsername, settings.apiAdminPassword, settings.portalUrl, undefined, undefined, undefined, true);
            autoRecovery.consecutiveSippyFailures = 0;
            const msg = `Sippy API reconnected. Found ${activeCalls.length} active call(s).`;
            await recordHistory('success', msg);
            return res.json({ ok: true, message: msg, durationMs: Date.now() - t0 });
          } catch (e: any) {
            const msg = `Retry failed: ${e.message}`;
            await recordHistory('failure', msg);
            return res.json({ ok: false, message: msg, durationMs: Date.now() - t0 });
          }
        }
        case 'warm_cdr_cache': {
          const msg = `CDR cache holds ${cdrCache.size} records. The background warmer runs every 3 minutes automatically. If data is missing, ensure Sippy API is reachable.`;
          await recordHistory(cdrCache.size > 0 ? 'success' : 'skipped', msg);
          return res.json({ ok: true, message: msg, durationMs: Date.now() - t0 });
        }
        case 'check_db': {
          await storage.getSippySettings();
          const msg = 'Database connection verified successfully.';
          await recordHistory('success', msg);
          return res.json({ ok: true, message: msg, durationMs: Date.now() - t0 });
        }
        case 'refresh_accounts': {
          const settings = await storage.getSippySettings();
          if (!settings?.portalUrl) {
            await recordHistory('failure', 'Sippy settings not configured.');
            return res.json({ ok: false, message: 'Sippy settings not configured.', durationMs: Date.now() - t0 });
          }
          const raPortalUrl = sippyPortalUrl(settings);
          const { accounts: raAccounts, error: raError } = await withSippyCreds(settings, (u, p) =>
            sippy.listSippyAccounts(u, p, {}, raPortalUrl));
          const raCount = raAccounts?.length || 0;
          if (raCount > 0) {
            // Warm the in-memory cache so subsequent calls benefit immediately
            for (const acc of raAccounts!) accountNameCache.set(acc.iAccount, acc.username || `Account ${acc.iAccount}`);
          }
          const msg = raError && raCount === 0
            ? `Account refresh failed: ${raError}`
            : `Account list refreshed: ${raCount} accounts loaded.`;
          await recordHistory(raCount > 0 ? 'success' : 'failure', msg);
          return res.json({ ok: raCount > 0, message: msg, durationMs: Date.now() - t0 });
        }
        case 'refresh_vendors': {
          const settings = await storage.getSippySettings();
          if (!settings?.portalUrl) {
            await recordHistory('failure', 'Sippy settings not configured.');
            return res.json({ ok: false, message: 'Sippy settings not configured.', durationMs: Date.now() - t0 });
          }
          const result = await sippy.listSippyVendors(settings.apiAdminUsername, settings.apiAdminPassword, {}, settings.portalUrl);
          const msg = `Vendor list refreshed: ${result.vendors?.length || 0} vendors found.`;
          await recordHistory('success', msg);
          return res.json({ ok: true, message: msg, durationMs: Date.now() - t0 });
        }
        default:
          return res.status(400).json({ ok: false, message: `Unknown action: ${action}` });
      }
    } catch (e: any) {
      await recordHistory('failure', e.message);
      return res.status(500).json({ ok: false, message: e.message, durationMs: Date.now() - t0 });
    }
  });

  // GET /api/fix/history — last N fix events (admin + management); screenshots excluded from list
  app.get('/api/fix/history', (req: any, res: any, next: any) => requireRole(['admin', 'management'], req, res, next), async (req: any, res: any) => {
    try {
      const limit = Math.min(parseInt(req.query.limit as string || '50', 10), 200);
      const rows = await storage.getFixHistory(limit);
      // Strip screenshot blob from list — served individually via /api/fix/screenshot/:id
      const sanitized = rows.map(r => ({
        id: r.id, page: r.page, issueType: r.issueType, component: r.component,
        fixAction: r.fixAction, outcome: r.outcome, outcomeMessage: r.outcomeMessage,
        triggeredBy: r.triggeredBy, performedBy: r.performedBy,
        hasScreenshot: !!r.screenshot,
        createdAt: r.createdAt,
      }));
      res.json({ history: sanitized, total: sanitized.length });
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

  // GET /api/fix/screenshot/:id — serve the base64 screenshot captured at fix time
  app.get('/api/fix/screenshot/:id', (req: any, res: any, next: any) => requireRole(['admin', 'management'], req, res, next), async (req: any, res: any) => {
    try {
      const id = parseInt(req.params.id, 10);
      if (isNaN(id)) return res.status(400).json({ error: 'Invalid ID' });
      const row = await storage.getFixHistoryById(id);
      if (!row?.screenshot) return res.status(404).json({ error: 'No screenshot found for this fix event' });
      const dataUrl = row.screenshot;
      // Detect format and serve as image
      const mimeMatch = dataUrl.match(/^data:(image\/\w+);base64,/);
      const mime      = mimeMatch?.[1] ?? 'image/jpeg';
      const base64    = dataUrl.replace(/^data:image\/\w+;base64,/, '');
      const buf       = Buffer.from(base64, 'base64');
      res.set('Content-Type', mime);
      res.set('Cache-Control', 'private, max-age=86400');
      res.send(buf);
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

  // GET /api/fix/auto-rules — current auto-recovery rule state (admin + management)
  app.get('/api/fix/auto-rules', (req: any, res: any, next: any) => requireRole(['admin', 'management'], req, res, next), (_req: any, res: any) => {
    res.json({
      rules: autoRecovery.rules,
      consecutiveSippyFailures: autoRecovery.consecutiveSippyFailures,
      lastAutoFixAt: autoRecovery.lastAutoFixAt?.toISOString() ?? null,
      totalAutoFixes: autoRecovery.stats.totalAutoFixes,
      lastEvent: autoRecovery.stats.lastEvent,
    });
  });

  // ── Phase 4: Auto-recovery background job (runs every 2 minutes) ─────────────
  setInterval(async () => {
    try {
      // Rule 1: sippy_retry — auto-retry if 3+ consecutive failures
      if (autoRecovery.consecutiveSippyFailures >= 3 && autoRecovery.rules[0].enabled) {
        const now = Date.now();
        const sinceLastFix = autoRecovery.lastAutoFixAt ? now - autoRecovery.lastAutoFixAt.getTime() : Infinity;
        if (sinceLastFix > autoRecovery.cooldownMs) {
          autoRecovery.lastAutoFixAt = new Date();
          autoRecovery.stats.totalAutoFixes++;
          autoRecovery.stats.lastEvent = `Auto-retry after ${autoRecovery.consecutiveSippyFailures} Sippy failures`;
          console.log(`[auto-recovery] Rule sippy_retry triggered after ${autoRecovery.consecutiveSippyFailures} consecutive failures.`);
          const settings = await storage.getSippySettings();
          let outcome = 'auto';
          let msg = `Auto-triggered after ${autoRecovery.consecutiveSippyFailures} consecutive failures`;
          if (settings?.portalUrl) {
            try {
              const liveCheck = await sippy.getSippyActiveCalls(settings.apiAdminUsername, settings.apiAdminPassword, settings.portalUrl, undefined, undefined, undefined, true);
              autoRecovery.consecutiveSippyFailures = 0;
              outcome = 'success';
              msg = `Auto-recovery success: ${liveCheck.length} active calls confirmed`;
              console.log('[auto-recovery] Sippy API auto-reconnected successfully.');
            } catch (e: any) {
              msg = `Auto-recovery attempt failed: ${e.message}`;
              console.log('[auto-recovery] Sippy auto-retry still failing:', e.message);
            }
          }
          await storage.addFixHistoryEntry({
            page: 'system', issueType: 'API_FAILURE', component: 'Sippy API',
            fixAction: 'retry_sippy', outcome, outcomeMessage: msg,
            triggeredBy: 'auto', performedBy: 'system',
          }).catch(() => {});
        }
      }

      // Rule 2: cdr_stale_log — log when CDR cache is stale >15 min
      if (autoRecovery.rules[1].enabled) {
        const cdrAge = cdrCacheUpdatedAt ? Date.now() - cdrCacheUpdatedAt.getTime() : null;
        if (cdrAge !== null && cdrAge > 15 * 60 * 1000 && cdrCache.size > 0) {
          const ageMin = Math.round(cdrAge / 60000);
          console.log(`[auto-recovery] CDR cache stale for ${ageMin}m — logging alert.`);
          autoRecovery.stats.lastEvent = `CDR stale ${ageMin}m`;
          await storage.addFixHistoryEntry({
            page: 'system', issueType: 'DATA_MISMATCH', component: 'CDR Cache',
            fixAction: 'warm_cdr_cache', outcome: 'auto',
            outcomeMessage: `CDR cache stale for ${ageMin} minutes. Background warmer may have stalled.`,
            triggeredBy: 'auto', performedBy: 'system',
          }).catch(() => {});
        }
      }
    } catch (e) {
      // Never crash the main process on auto-recovery errors
    }
  }, 2 * 60 * 1000);

  // ─────────────────────────────────────────────────────────────────────────
  // FEATURE GROUP A: NER — Network Effectiveness Ratio
  // GET /api/stats/ner?hours=24&vendorId=xxx
  // NER = (answered + busy + rejected + ring-no-answer) / total (excludes subscriber-unavailable)
  // ─────────────────────────────────────────────────────────────────────────
  app.get('/api/stats/ner', async (req: any, res) => {
    try {
      const hours  = parseInt(req.query.hours as string || '24', 10);
      const vendor = req.query.vendorId as string | undefined;
      const cutoff = new Date(Date.now() - hours * 60 * 60 * 1000);

      const cdrs = [...cdrCache.values()].filter(c => {
        const ts = c.startTime ? new Date(c.startTime) : null;
        if (!ts || ts < cutoff) return false;
        if (vendor) {
          const vName = c.vendor || (c.iConnection ? connectionVendorCache.get(c.iConnection) : '') || '';
          if (vName !== vendor && c.iConnection !== vendor) return false;
        }
        return true;
      });

      // NER: exclude "subscriber unavailable" from denominator (SIP 480, 503, 604)
      const SUBSCRIBER_UNAVAIL = new Set(['480', '503', '604', 'no answer']);
      let total = 0, nerEligible = 0, answered = 0;
      const byVendor: Record<string, { total: number; nerEligible: number; answered: number }> = {};

      for (const c of cdrs) {
        const vid = c.vendor || (c.iConnection ? connectionVendorCache.get(c.iConnection) : '') || 'unknown';
        if (!byVendor[vid]) byVendor[vid] = { total: 0, nerEligible: 0, answered: 0 };
        total++;
        byVendor[vid].total++;
        const result = (c.result || '').toLowerCase();
        const isUnavail = SUBSCRIBER_UNAVAIL.has(result) || result.includes('unavail') || result === '480' || result === '503';
        if (!isUnavail) { nerEligible++; byVendor[vid].nerEligible++; }
        if (c.duration > 0) { answered++; byVendor[vid].answered++; }
      }

      const ner = nerEligible > 0 ? Math.round((answered / nerEligible) * 10000) / 100 : null;
      const asr = total > 0 ? Math.round((answered / total) * 10000) / 100 : null;

      const vendorNer = Object.entries(byVendor).map(([vendorId, v]) => ({
        vendorId,
        total: v.total,
        nerEligible: v.nerEligible,
        answered: v.answered,
        ner: v.nerEligible > 0 ? Math.round((v.answered / v.nerEligible) * 10000) / 100 : null,
        asr: v.total > 0 ? Math.round((v.answered / v.total) * 10000) / 100 : null,
      }));

      res.json({ ner, asr, total, nerEligible, answered, hours, vendorNer });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // ─────────────────────────────────────────────────────────────────────────
  // FEATURE GROUP B: Route QoS Heatmap
  // GET /api/stats/heatmap?vendorId=xxx&metric=asr&prefixLen=3
  // Returns destination × hour-of-day matrix with ASR/ACD colour values
  // ─────────────────────────────────────────────────────────────────────────
  app.get('/api/stats/heatmap', async (req: any, res) => {
    try {
      const vendor    = req.query.vendorId as string | undefined;
      const metric    = (req.query.metric as string) || 'asr';   // asr|acd
      const prefixLen = parseInt(req.query.prefixLen as string || '3', 10);
      const hours     = parseInt(req.query.hours as string || '168', 10); // default 7 days
      const cutoff    = new Date(Date.now() - hours * 60 * 60 * 1000);

      const cdrs = [...cdrCache.values()].filter(c => {
        const ts = c.startTime ? new Date(c.startTime) : null;
        if (!ts || ts < cutoff) return false;
        if (vendor) {
          const vName = c.vendor || (c.iConnection ? connectionVendorCache.get(c.iConnection) : '') || '';
          if (vName !== vendor && c.iConnection !== vendor) return false;
        }
        return true;
      });

      // Build dest × hour matrix
      const matrix: Record<string, Record<number, { calls: number; answered: number; totalDur: number }>> = {};
      for (const c of cdrs) {
        const dest   = (c.callee || '').replace(/\D/g, '').slice(0, prefixLen) || 'unknown';
        const hour   = new Date(c.startTime).getUTCHours();
        if (!matrix[dest]) matrix[dest] = {};
        if (!matrix[dest][hour]) matrix[dest][hour] = { calls: 0, answered: 0, totalDur: 0 };
        matrix[dest][hour].calls++;
        if (c.duration > 0) { matrix[dest][hour].answered++; matrix[dest][hour].totalDur += c.duration; }
      }

      // Convert to flat rows for frontend
      const rows: Array<{ dest: string; hour: number; calls: number; value: number }> = [];
      for (const [dest, hours2] of Object.entries(matrix)) {
        for (const [h, v] of Object.entries(hours2)) {
          const val = metric === 'acd'
            ? (v.answered > 0 ? Math.round(v.totalDur / v.answered) : 0)
            : (v.calls > 0 ? Math.round((v.answered / v.calls) * 10000) / 100 : 0);
          rows.push({ dest, hour: Number(h), calls: v.calls, value: val });
        }
      }

      // Top destinations by call volume
      const destTotals: Record<string, number> = {};
      for (const r of rows) destTotals[r.dest] = (destTotals[r.dest] || 0) + r.calls;
      const topDests = Object.entries(destTotals)
        .sort((a, b) => b[1] - a[1])
        .slice(0, 30)
        .map(([d]) => d);

      res.json({ rows: rows.filter(r => topDests.includes(r.dest)), topDests, metric, hours });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // ─────────────────────────────────────────────────────────────────────────
  // FEATURE GROUP C: CLI Delivery Verification
  // GET /api/stats/cli-flags?hours=24 — CDRs where PAI ≠ caller (CLI stripping)
  // ─────────────────────────────────────────────────────────────────────────
  app.get('/api/stats/cli-flags', async (req: any, res) => {
    try {
      const hours  = parseInt(req.query.hours as string || '24', 10);
      const limit  = Math.min(parseInt(req.query.limit as string || '200', 10), 1000);
      const cutoff = new Date(Date.now() - hours * 60 * 60 * 1000);

      const flagged = [...cdrCache.values()].filter(c => {
        const ts = c.startTime ? new Date(c.startTime) : null;
        if (!ts || ts < cutoff) return false;
        if (!c.pAssertedId) return false;
        const pai   = c.pAssertedId.replace(/[^0-9+]/g, '');
        const caller = (c.caller || '').replace(/[^0-9+]/g, '');
        return pai && caller && pai !== caller && !pai.endsWith(caller) && !caller.endsWith(pai);
      }).slice(0, limit).map(c => ({
        callId:       c.callId,
        startTime:    c.startTime,
        caller:       c.caller,
        pAssertedId:  c.pAssertedId,
        callee:       c.callee,
        vendorName:   c.vendor || (c.iConnection ? connectionVendorCache.get(c.iConnection) : '') || undefined,
        duration:     c.duration,
        result:       c.result,
      }));

      res.json({ flagged, total: flagged.length, hours });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // ─────────────────────────────────────────────────────────────────────────
  // FEATURE GROUP D: SIMbox Detection — scoring + routes
  // ─────────────────────────────────────────────────────────────────────────
  app.get('/api/simbox/scores', async (req: any, res) => {
    try {
      const scores = await storage.getLatestSimboxScores(100);
      res.json({ scores });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  app.get('/api/simbox/scores/:vendorId', async (req: any, res) => {
    try {
      const scores = await storage.getSimboxScoresByVendor(req.params.vendorId, 30);
      res.json({ scores });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  app.post('/api/simbox/run-analysis', (req: any, res, next) => requireRole(['admin', 'management'], req, res, next), async (req: any, res) => {
    try {
      const count = await runSimboxAnalysis();
      res.json({ ok: true, vendorsAnalysed: count });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // ─────────────────────────────────────────────────────────────────────────
  // FEATURE GROUP E: Billing Dispute Tracker
  // ─────────────────────────────────────────────────────────────────────────
  app.get('/api/disputes', async (req: any, res) => {
    try { res.json(await storage.getBillingDisputes()); }
    catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  app.post('/api/disputes', (req: any, res, next) => requireRole(['admin', 'management'], req, res, next), async (req: any, res) => {
    try {
      const body = req.body;
      const dispute = await storage.createBillingDispute({
        vendorName:   body.vendorName,
        periodStart:  new Date(body.periodStart),
        periodEnd:    new Date(body.periodEnd),
        ourAmount:    Number(body.ourAmount || 0),
        vendorAmount: Number(body.vendorAmount || 0),
        discrepancy:  Number(body.ourAmount || 0) - Number(body.vendorAmount || 0),
        currency:     body.currency || 'USD',
        status:       body.status || 'open',
        resolution:   body.resolution ? Number(body.resolution) : null,
        notes:        body.notes || null,
      });
      res.json(dispute);
    } catch (e: any) { res.status(400).json({ error: e.message }); }
  });

  app.patch('/api/disputes/:id', (req: any, res, next) => requireRole(['admin', 'management'], req, res, next), async (req: any, res) => {
    try {
      const updates: any = { ...req.body };
      if (updates.periodStart) updates.periodStart = new Date(updates.periodStart);
      if (updates.periodEnd)   updates.periodEnd   = new Date(updates.periodEnd);
      if (updates.ourAmount !== undefined || updates.vendorAmount !== undefined) {
        const current = (await storage.getBillingDisputes()).find(d => d.id === Number(req.params.id));
        const our = updates.ourAmount !== undefined ? Number(updates.ourAmount) : (current?.ourAmount ?? 0);
        const vendor = updates.vendorAmount !== undefined ? Number(updates.vendorAmount) : (current?.vendorAmount ?? 0);
        updates.discrepancy = our - vendor;
      }
      const updated = await storage.updateBillingDispute(Number(req.params.id), updates);
      if (!updated) return res.status(404).json({ error: 'Not found' });
      res.json(updated);
    } catch (e: any) { res.status(400).json({ error: e.message }); }
  });

  app.delete('/api/disputes/:id', (req: any, res, next) => requireRole(['admin', 'management'], req, res, next), async (req: any, res) => {
    try {
      await storage.deleteBillingDispute(Number(req.params.id));
      res.json({ ok: true });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // ─────────────────────────────────────────────────────────────────────────
  // FEATURE GROUP F: SLA Breach Log
  // ─────────────────────────────────────────────────────────────────────────
  app.get('/api/sla-breaches', async (req: any, res) => {
    try {
      const vendorId = req.query.vendorId as string | undefined;
      const limit    = Math.min(parseInt(req.query.limit as string || '200', 10), 500);
      res.json(await storage.getSlaBreaches(limit, vendorId));
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // ─────────────────────────────────────────────────────────────────────────
  // FEATURE GROUP G: Test Campaigns
  // ─────────────────────────────────────────────────────────────────────────
  app.get('/api/campaigns', async (req: any, res) => {
    try { res.json(await storage.getTestCampaigns()); }
    catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  app.post('/api/campaigns', (req: any, res, next) => requireRole(['admin', 'management'], req, res, next), async (req: any, res) => {
    try {
      const body = req.body;
      const campaign = await storage.createTestCampaign({
        name:          body.name,
        destinations:  JSON.stringify(body.destinations || []),
        scheduleType:  body.scheduleType || 'once',
        scheduledAt:   body.scheduledAt ? new Date(body.scheduledAt) : null,
        cronHour:      body.cronHour != null ? Number(body.cronHour) : null,
        status:        'pending',
      });
      res.json(campaign);
    } catch (e: any) { res.status(400).json({ error: e.message }); }
  });

  app.patch('/api/campaigns/:id', (req: any, res, next) => requireRole(['admin', 'management'], req, res, next), async (req: any, res) => {
    try {
      const updates: any = { ...req.body };
      if (updates.destinations && typeof updates.destinations !== 'string')
        updates.destinations = JSON.stringify(updates.destinations);
      if (updates.scheduledAt) updates.scheduledAt = new Date(updates.scheduledAt);
      const updated = await storage.updateTestCampaign(Number(req.params.id), updates);
      if (!updated) return res.status(404).json({ error: 'Not found' });
      res.json(updated);
    } catch (e: any) { res.status(400).json({ error: e.message }); }
  });

  app.delete('/api/campaigns/:id', (req: any, res, next) => requireRole(['admin', 'management'], req, res, next), async (req: any, res) => {
    try {
      await storage.deleteTestCampaign(Number(req.params.id));
      res.json({ ok: true });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  app.get('/api/campaigns/:id/results', async (req: any, res) => {
    try {
      const results = await storage.getCampaignResults(Number(req.params.id), 100);
      res.json(results);
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // GET /api/campaigns/:id/runs — synthetic test run history (one record per scheduled execution)
  app.get('/api/campaigns/:id/runs', async (req: any, res) => {
    try {
      const runs = await storage.getSyntheticTestRuns(Number(req.params.id), 50);
      res.json(runs);
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // PATCH /api/campaigns/:id/toggle — enable/disable scheduled execution
  app.patch('/api/campaigns/:id/toggle', (req: any, res, next) => requireRole(['admin', 'management'], req, res, next), async (req: any, res) => {
    try {
      const campaign = await storage.getTestCampaign(Number(req.params.id));
      if (!campaign) return res.status(404).json({ error: 'Not found' });
      const newEnabled = !(campaign as any).enabled;
      // Compute nextRunAt for all schedule types when re-enabling
      const extra: any = {};
      if (newEnabled) {
        const nextRun = computeInitialNextRunAt(campaign);
        if (nextRun) extra.nextRunAt = nextRun;
        else extra.nextRunAt = null;
      }
      const updated = await storage.updateTestCampaign(campaign.id, { enabled: newEnabled, ...extra } as any);
      res.json(updated);
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // POST /api/campaigns/:id/run — trigger a campaign run immediately using Click-to-Call infrastructure
  app.post('/api/campaigns/:id/run', (req: any, res, next) => requireRole(['admin', 'management'], req, res, next), async (req: any, res) => {
    try {
      const campaign = await storage.getTestCampaign(Number(req.params.id));
      if (!campaign) return res.status(404).json({ error: 'Campaign not found' });
      const destinations: Array<{ cld: string; cli?: string; label?: string }> = JSON.parse(campaign.destinations || '[]');
      if (!destinations.length) return res.status(400).json({ error: 'Campaign has no destinations' });

      await storage.updateTestCampaign(campaign.id, { status: 'running', lastRunAt: new Date() });

      // Fire all test calls in background; return immediately
      res.json({ ok: true, message: `Campaign "${campaign.name}" started — ${destinations.length} calls queued.`, campaignId: campaign.id });

      const sSettings = await storage.getSippySettings();
      const portalUrl = sSettings ? sippyPortalUrl(sSettings) : '';

      for (const dest of destinations) {
        try {
          let outcome = 'failed', sipCode: number | undefined, durationSec = 0, pddMs = 0;
          if (sSettings?.portalUrl) {
            const ctcResult = await sippy.makeTestCall(
              sSettings.apiAdminUsername, sSettings.apiAdminPassword,
              { cld: dest.cld, cli: dest.cli || '100', maxDuration: 10 },
              portalUrl
            ).catch(() => null);
            if (ctcResult) {
              outcome    = ctcResult.connected ? 'connected' : 'failed';
              sipCode    = ctcResult.sipCode;
              durationSec = ctcResult.duration ?? 0;
              pddMs      = ctcResult.pdd ?? 0;
            }
          }
          await storage.addCampaignResult({
            campaignId:  campaign.id,
            cld:         dest.cld,
            cli:         dest.cli,
            label:       dest.label,
            outcome,
            sipCode,
            durationSec,
            pddMs,
            fasDetected: durationSec > 0 && durationSec < 4,
          });
        } catch { /* continue with next destination */ }
        await new Promise(r => setTimeout(r, 300)); // small delay between calls
      }
      await storage.updateTestCampaign(campaign.id, { status: 'done' });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // ─────────────────────────────────────────────────────────────────────────
  // FEATURE GROUP G2: Route Decision Traces + Carrier Quality Scores
  // ─────────────────────────────────────────────────────────────────────────

  // GET /api/route-traces — all recent traces (optional ?campaignId=)
  // When route_decision_traces table is empty (simulation off), falls back to
  // CDR-cache-based virtual traces so the Replay Engine page always has data.
  app.get('/api/route-traces', (req: any, res, next) => requireRole(['admin', 'management'], req, res, next), async (req: any, res) => {
    try {
      const campaignId = req.query.campaignId ? Number(req.query.campaignId) : undefined;
      const limit      = req.query.limit      ? Number(req.query.limit)      : 200;
      const real = await storage.getRouteDecisionTraces({ campaignId, limit });
      if (real.length > 0) return res.json(real);

      // Fallback: synthesise virtual traces from CDR cache (read-only, no DB write)
      if (campaignId) return res.json([]); // campaign-scoped queries don't fall back
      const cutoff = Date.now() - 72 * 3600_000;
      const vendorFallback = (() => { for (const v of connectionVendorCache.values()) if (!/^\d+$/.test(v)) return v; })();

      // Fetch carrier quality scores once to enrich all virtual traces with real LCR data
      const lcrScores = await storage.getCarrierQualityScores(24);
      const lcrScoreMap: Record<string, number> = Object.fromEntries(
        lcrScores.map(s => [s.carrierName, s.stabilityScore ?? 0])
      );
      // All known carriers become the candidate list — gives the LCR panel real comparison data
      const lcrCandidates = lcrScores.map(s => s.carrierName);
      const lcrCandidatesJson = lcrCandidates.length > 0 ? JSON.stringify(lcrCandidates) : null;
      const lcrSnapshotJson   = lcrCandidates.length > 0 ? JSON.stringify(lcrScoreMap)   : null;

      const cdrs = [...cdrCache.values()]
        .filter(c => (sippy.parseSippyDate(c.startTime)?.getTime() ?? 0) >= cutoff)
        .sort((a, b) => (sippy.parseSippyDate(b.startTime)?.getTime() ?? 0) - (sippy.parseSippyDate(a.startTime)?.getTime() ?? 0))
        .slice(0, limit);
      let vId = -1;
      const virtualTraces = cdrs.map(c => {
        const ts     = sippy.parseSippyDate(c.startTime) ?? new Date();
        const vendor = c.vendor
          || (c.iConnection ? connectionVendorCache.get(String(c.iConnection)) : undefined)
          || vendorFallback
          || 'Unknown Carrier';
        const answered = (c.duration ?? 0) > 0;
        const rawSip   = parseInt(String(c.result ?? '')) || 0;
        const sipCode  = answered ? 200 : (rawSip >= 400 && rawSip < 700 ? rawSip : 503);
        const vendorScore = lcrScoreMap[vendor];
        const decisionReason = vendorScore != null
          ? `${vendor} selected — stability ${vendorScore.toFixed(0)}/100${answered ? ', call completed' : ', call failed'}`
          : `Routed via ${vendor}`;
        return {
          id: vId--, campaignId: null, runId: null,
          cld: c.callee ?? '', cli: c.caller ?? null,
          selectedCarrier: vendor, selectedCarrierId: null,
          candidateRoutes: lcrCandidatesJson ?? JSON.stringify([vendor]),
          decisionReason,
          outcome: answered ? 'connected' : 'failed',
          sipCode: answered ? 200 : sipCode,
          pddMs: c.pdd ? Math.round(c.pdd * 1000) : null,
          durationSec: c.duration ?? null,
          failureCategory: answered ? null : 'carrier_failure',
          failureType: null,
          carrierScoresSnapshot: lcrSnapshotJson,
          createdAt: ts.toISOString(),
        };
      });
      res.json(virtualTraces);
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // GET /api/carrier-scores?window=24 — carrier quality scores
  app.get('/api/carrier-scores', (req: any, res, next) => requireRole(['admin', 'management'], req, res, next), async (req: any, res) => {
    try {
      const windowHours = req.query.window ? Number(req.query.window) : 24;
      const dbScores = await storage.getCarrierQualityScores(windowHours);
      if (dbScores.length > 0) return res.json(dbScores);

      // Fallback: compute live from CDR cache grouped by vendor name
      const cutoffMs = Date.now() - windowHours * 3600 * 1000;
      const recentCdrs = Array.from(cdrCache.values()).filter(c => {
        const ts = sippy.parseSippyDate(c.startTime)?.getTime() ?? 0;
        return ts >= cutoffMs;
      });
      if (recentCdrs.length === 0) return res.json([]);

      const prefixMap = new Map<string, { total: number; answered: number; pddSum: number; pddCount: number }>();
      for (const c of recentCdrs) {
        const raw = (c.callee ?? '').replace(/^\+/, '');
        const prefix = raw.slice(0, 3) || 'UNK';
        const ex = prefixMap.get(prefix) ?? { total: 0, answered: 0, pddSum: 0, pddCount: 0 };
        ex.total++;
        if ((c.duration ?? 0) > 0) ex.answered++;
        if (c.pdd && c.pdd > 0) { ex.pddSum += c.pdd; ex.pddCount++; }
        prefixMap.set(prefix, ex);
      }
      const liveScores = [...prefixMap.entries()]
        .filter(([, v]) => v.total >= 2)
        .sort((a, b) => b[1].total - a[1].total)
        .slice(0, 8)
        .map(([prefix, v]) => {
          const asr         = Math.round(v.answered / v.total * 100);
          const avgPddMs    = v.pddCount > 0 ? Math.round(v.pddSum / v.pddCount * 1000) : 0;
          const pddPenalty  = avgPddMs > 5000 ? 20 : avgPddMs > 2000 ? 10 : 0;
          const stabilityScore = Math.min(100, Math.round(asr * 0.75 + (100 - pddPenalty) * 0.25));
          return {
            carrierId: prefix, carrierName: `+${prefix}`,
            stabilityScore, rollingAsr: asr, avgPddMs, failureRate: 100 - asr, sampleCount: v.total,
          };
        });
      res.json(liveScores);
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // POST /api/carrier-scores/recompute — trigger manual recompute
  app.post('/api/carrier-scores/recompute', (req: any, res, next) => requireRole(['admin', 'management'], req, res, next), async (_req: any, res) => {
    try {
      await recomputeCarrierScores();
      res.json({ ok: true });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // GET /api/carrier-scores/delta — compare 24h vs 168h per carrier (What Changed?)
  app.get('/api/carrier-scores/delta', (req: any, res, next) => requireRole(['admin', 'management'], req, res, next), async (_req: any, res) => {
    try {
      const all24  = await storage.getCarrierQualityScores(24);
      const all168 = await storage.getCarrierQualityScores(168);
      const map168 = new Map(all168.map((s: any) => [s.carrierName, s]));
      const delta  = all24.map((s: any) => {
        const h = map168.get(s.carrierName) as any | undefined;
        return {
          carrierId:      s.carrierId,
          carrierName:    s.carrierName,
          stability24:    s.stabilityScore,
          stability168:   h?.stabilityScore ?? null,
          stabilityDelta: h?.stabilityScore != null && s.stabilityScore != null ? s.stabilityScore - h.stabilityScore : null,
          asr24:          s.rollingAsr,
          asr168:         h?.rollingAsr ?? null,
          asrDelta:       h?.rollingAsr != null && s.rollingAsr != null ? s.rollingAsr - h.rollingAsr : null,
          pdd24:          s.avgPddMs,
          pdd168:         h?.avgPddMs ?? null,
          pddDelta:       h?.avgPddMs != null && s.avgPddMs != null ? s.avgPddMs - h.avgPddMs : null,
          failRate24:     s.failureRate,
          failRate168:    h?.failureRate ?? null,
          failRateDelta:  h?.failureRate != null && s.failureRate != null ? s.failureRate - h.failureRate : null,
          sampleCount24:  s.sampleCount,
          sampleCount168: h?.sampleCount ?? null,
          trend:          s.trend,
        };
      });
      res.json(delta);
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // ── Carrier Health Service ────────────────────────────────────────────────────
  // Single source of truth for per-carrier ASR/ACD/PDD/MOS, derived from the CDR cache.
  // 5-minute TTL — zero Sippy XML-RPC calls. Also fires carrier-typed incidents when
  // alertRules thresholds are violated (bridging alert engine → incident stream).
  async function computeCarrierHealth(windowHours: number): Promise<CarrierHealthEntry[]> {
    const now      = Date.now();
    const cutoffMs = now - windowHours * 3_600_000;

    // Group CDR cache entries by vendor name
    type Bucket = { total: number; answered: number; durationSum: number; pddSum: number; pddCount: number };
    const buckets = new Map<string, Bucket>();
    for (const c of cdrCache.values()) {
      const ts = sippy.parseSippyDate(c.startTime)?.getTime() ?? sippy.parseSippyDate((c as any).connectTime ?? null)?.getTime() ?? 0;
      if (!ts || ts < cutoffMs) continue;
      const carrier = (c as any).vendor ?? connectionVendorCache.get(String((c as any).iConnection ?? '')) ?? 'Unknown';
      const b = buckets.get(carrier) ?? { total: 0, answered: 0, durationSum: 0, pddSum: 0, pddCount: 0 };
      b.total++;
      const dur = Number((c as any).duration ?? 0);
      if (dur > 0) { b.answered++; b.durationSum += dur; }
      const pdd = Number((c as any).pdd ?? 0);
      if (pdd > 0) { b.pddSum += pdd; b.pddCount++; }
      buckets.set(carrier, b);
    }

    // Fetch active alertRules from DB (metric=asr_drop scoped to carriers)
    let rules: Array<{ metric: string; threshold: number; comparison: string; carrier: string | null; label: string | null }> = [];
    try {
      rules = await db.select().from(alertRulesTable).then(r =>
        r.filter((ar: any) => ar.enabled && ['asr_drop','cps_spike'].includes(ar.metric))
      ) as any;
    } catch { /* non-critical */ }

    const entries: CarrierHealthEntry[] = [];
    for (const [name, b] of buckets.entries()) {
      if (b.total < 3) continue; // need minimum sample
      const asr     = Math.round(b.answered / b.total * 100 * 10) / 10;
      const acd     = b.answered > 0 ? Math.round(b.durationSum / b.answered) : 0;
      const avgPddMs = b.pddCount > 0 ? Math.round(b.pddSum / b.pddCount * 1000) : 0;
      const failRate = Math.round((1 - b.answered / b.total) * 100 * 10) / 10;
      // Simplified MOS estimate: starts at 4.5, penalised by PDD and fail rate
      const mosEstimate = Math.max(1, Math.min(4.5, 4.5 - (avgPddMs / 3000) * 0.8 - (failRate / 100) * 1.2));

      // Check alertRules for this carrier
      const firedRules: string[] = [];
      for (const rule of rules) {
        if (rule.carrier && rule.carrier !== name) continue;
        if (rule.metric === 'asr_drop' && rule.comparison === 'lt' && asr < rule.threshold) {
          firedRules.push(`asr_drop<${rule.threshold}% (actual ${asr}%)`);
        }
      }

      entries.push({
        carrierId:    name.toLowerCase().replace(/\s+/g, '_'),
        carrierName:  name,
        asr, acd, avgPddMs, failRate,
        mosEstimate: Math.round(mosEstimate * 100) / 100,
        sampleCount: b.total,
        alertFired:  firedRules.length > 0,
        alertRules:  firedRules,
        window:      windowHours,
        computedAt:  new Date().toISOString(),
      });
    }

    entries.sort((a, b) => b.sampleCount - a.sampleCount);

    // Bridge: fire carrier-typed incidents for any alertRule violations
    for (const entry of entries.filter(e => e.alertFired)) {
      try {
        const [existing] = await db.select().from(incidentsTable).where(
          and(
            eq(incidentsTable.entityType,   'carrier'),
            eq(incidentsTable.entityId,     entry.carrierId),
            eq(incidentsTable.incidentType, 'CARRIER_ASR_DROP'),
            eq(incidentsTable.status,       'active'),
          )
        );
        const severity   = entry.asr < 20 ? 'critical' : entry.asr < 40 ? 'high' : 'medium';
        const incidentData = {
          entityType:      'carrier',
          entityId:        entry.carrierId,
          entityName:      entry.carrierName,
          incidentType:    'CARRIER_ASR_DROP',
          severity,
          confidence:      Math.round(Math.min(95, 50 + entry.sampleCount * 0.5)),
          title:           `${entry.carrierName}: ASR ${entry.asr}% — alert rule fired`,
          summary:         `Carrier ${entry.carrierName} ASR dropped to ${entry.asr}% over the last ${windowHours}h window (${entry.sampleCount} calls). ${entry.alertRules.join('; ')}.`,
          reasons:         entry.alertRules,
          suggestedAction: 'Review carrier routing, escalate to NOC, or degrade carrier priority in routing groups.',
          source:          'carrier_health_service',
          status:          'active',
          updatedAt:       new Date(),
        };
        if (existing) {
          await db.update(incidentsTable).set(incidentData).where(eq(incidentsTable.id, existing.id));
        } else {
          await db.insert(incidentsTable).values({ ...incidentData, openedAt: new Date() });
        }
        // Mirror to the alerts table with vendor field for timeline/ops-console visibility
        const { alerts: alertsT } = await import('../shared/schema');
        const { eq: eqA, and: andA } = await import('drizzle-orm');
        const [existingAlert] = await db.select({ id: alertsT.id }).from(alertsT)
          .where(andA(eqA(alertsT.type, 'carrier_asr_drop'), eqA((alertsT as any).vendor, entry.carrierId), eqA(alertsT.resolved, false)))
          .limit(1);
        if (!existingAlert) {
          await storage.createAlert({
            type:     'carrier_asr_drop',
            severity,
            message:  `${entry.carrierName}: ASR ${entry.asr}% — alert rule fired (${entry.sampleCount} calls sampled)`,
            resolved: false,
            vendor:   entry.carrierId,
          } as any);
        }
      } catch { /* non-critical */ }
    }

    // Auto-resolve: close open carrier_asr_drop alerts for carriers that have recovered
    for (const entry of entries.filter(e => !e.alertFired)) {
      try {
        const { alerts: alertsT } = await import('../shared/schema');
        const { eq: eqA, and: andA } = await import('drizzle-orm');
        const [openAlert] = await db.select({ id: alertsT.id }).from(alertsT)
          .where(andA(eqA(alertsT.type, 'carrier_asr_drop'), eqA((alertsT as any).vendor, entry.carrierId), eqA(alertsT.resolved, false)))
          .limit(1);
        if (openAlert) {
          await db.update(alertsT)
            .set({ resolved: true, resolvedAt: new Date() })
            .where(eqA(alertsT.id, openAlert.id));
          console.log(`[carrier-health] auto-resolved alert for ${entry.carrierId} (ASR recovered to ${entry.asr}%)`);
        }
      } catch { /* non-critical */ }
    }

    return entries;
  }

  // GET /api/carrier/health?window=3 — unified carrier health (CDR cache, no Sippy calls)
  app.get('/api/carrier/health', (req: any, res: any, next: any) => requireRole(['admin','management','noc_operator','viewer','team_lead'], req, res, next), async (req: any, res: any) => {
    try {
      const windowHours  = Math.max(1, Math.min(168, Number(req.query.window) || 3));
      const now          = Date.now();
      const stale        = now - _carrierHealthCachedAt > CARRIER_HEALTH_TTL_MS;

      if (!stale && _carrierHealthCache.length > 0) {
        return res.json({ carriers: _carrierHealthCache, cached: true, cacheAgeMs: now - _carrierHealthCachedAt });
      }

      const carriers     = await computeCarrierHealth(windowHours);
      _carrierHealthCache    = carriers;
      _carrierHealthCachedAt = now;
      res.json({ carriers, cached: false, cacheAgeMs: 0 });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // POST /api/carrier/health/refresh — bust the cache and recompute immediately
  app.post('/api/carrier/health/refresh', (req: any, res: any, next: any) => requireRole(['admin','management'], req, res, next), async (req: any, res: any) => {
    try {
      const windowHours = Number(req.query.window) || 3;
      _carrierHealthCachedAt = 0; // bust cache
      const carriers = await computeCarrierHealth(windowHours);
      _carrierHealthCache    = carriers;
      _carrierHealthCachedAt = Date.now();
      console.log(`[carrier-health] manual refresh: ${carriers.length} carriers, ${carriers.filter(c => c.alertFired).length} alert(s) fired`);
      res.json({ carriers, refreshed: true });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

  // ── Self-Healing Routing Engine ──────────────────────────────────────────────
  // GET /api/routing/self-heal/status — carrier health + routing group analysis + proposals
  app.get('/api/routing/self-heal/status',
    (req: any, res: any, next: any) => requireRole(['admin', 'management'], req, res, next),
    async (req: any, res: any) => {
      try {
        // 1. Load carrier quality scores (fast, DB-only)
        const scores = await storage.getCarrierQualityScores(24);
        const scoreMap = new Map(scores.map((s: any) => [s.carrierName.toLowerCase().trim(), s]));

        // 2. Build carrier health view
        const carrierHealth = scores.map((s: any) => {
          const stability = s.stabilityScore ?? 100;
          return {
            carrierName:    s.carrierName,
            stabilityScore: stability,
            rollingAsr:     s.rollingAsr,
            failureRate:    s.failureRate,
            trend:          s.trend,
            sampleCount:    s.sampleCount,
            status:         stability >= 75 ? 'healthy' : stability >= 50 ? 'degraded' : 'critical',
          };
        });

        // 3. Load routing group cache + connections for member analysis
        const settings = await storage.getSippySettings();
        if (!settings) {
          return res.json({ carrierHealth, proposals: [], routingGroupsChecked: 0, lastCheckedAt: new Date().toISOString(), warning: 'Sippy not configured' });
        }
        const { username, password } = sippyXmlCreds(settings);
        const pUrl     = sippyPortalUrl(settings);
        const cachedRGs    = await getCachedRoutingGroups();
        const cachedConns  = await getCachedConnections();
        const connMap = new Map((cachedConns as any[]).map((c: any) => [c.i_connection, c]));

        // 4. Fetch members for each routing group (parallel, best-effort)
        const filterRgId = req.query.routingGroupId ? parseInt(req.query.routingGroupId as string) : null;
        const rgsToCheck = filterRgId
          ? (cachedRGs as any[]).filter((rg: any) => rg.i_routing_group === filterRgId)
          : (cachedRGs as any[]).slice(0, 12); // Cap to avoid Sippy overload

        const memberResults = await Promise.allSettled(
          rgsToCheck.map(async (rg: any) => {
            const mResult = await sippy.listRoutingGroupMembers(username, password, rg.i_routing_group, { portalUrl: pUrl });
            return { rg, members: mResult.members ?? [] };
          })
        );

        const proposals: any[] = [];

        for (const result of memberResults) {
          if (result.status !== 'fulfilled') continue;
          const { rg, members } = result.value;
          const sortedMembers = [...members].sort((a: any, b: any) => (a.preference ?? 99) - (b.preference ?? 99));
          const maxPref = sortedMembers.length > 0
            ? Math.max(...sortedMembers.map((m: any) => m.preference ?? 1))
            : 1;

          for (const m of members) {
            const conn = m.iConnection ? connMap.get(m.iConnection) : null;
            const vendorName: string = conn?.vendor_name ?? conn?.name ?? '';
            if (!vendorName) continue;

            const score = scoreMap.get(vendorName.toLowerCase().trim());
            if (!score) continue;

            const stability = (score as any).stabilityScore ?? 100;
            if (stability >= 50) continue; // Only flag critical/degraded

            const currentPref   = m.preference ?? 1;
            const currentWeight = m.weight ?? 1;
            const isBypass      = stability < 25;
            const proposedPref  = isBypass ? maxPref + 10 : maxPref + 1;
            const proposedWeight = isBypass ? 1 : Math.max(1, Math.floor(currentWeight * 0.5));

            // Find alternative healthy routes in this group
            const healthyAlternatives = sortedMembers
              .filter((sm: any) => {
                if (sm.iRoutingGroupMember === m.iRoutingGroupMember) return false;
                const c = sm.iConnection ? connMap.get(sm.iConnection) : null;
                const vn: string = c?.vendor_name ?? c?.name ?? '';
                const sc = vn ? scoreMap.get(vn.toLowerCase().trim()) : null;
                return ((sc as any)?.stabilityScore ?? 50) >= 50;
              })
              .map((sm: any) => {
                const c = sm.iConnection ? connMap.get(sm.iConnection) : null;
                return c?.vendor_name ?? c?.name ?? `Connection #${sm.iConnection}`;
              });

            proposals.push({
              id:                  `${rg.i_routing_group}-${m.iRoutingGroupMember}`,
              carrierName:         vendorName,
              stabilityScore:      stability,
              rollingAsr:          (score as any).rollingAsr,
              failureRate:         (score as any).failureRate,
              trend:               (score as any).trend,
              iRoutingGroup:       rg.i_routing_group,
              groupName:           rg.name ?? `Group ${rg.i_routing_group}`,
              iRoutingGroupMember: m.iRoutingGroupMember,
              iConnection:         m.iConnection,
              currentPreference:   currentPref,
              currentWeight:       currentWeight,
              proposedPreference:  proposedPref,
              proposedWeight:      proposedWeight,
              action:              isBypass ? 'bypass' : 'deprioritize',
              healthyAlternatives,
              risk:                healthyAlternatives.length === 0 ? 'high' : 'low',
            });
          }
        }

        res.json({
          carrierHealth,
          proposals,
          routingGroupsChecked: rgsToCheck.length,
          lastCheckedAt: new Date().toISOString(),
        });
      } catch (e: any) { res.status(500).json({ error: e.message }); }
    }
  );

  // POST /api/routing/self-heal/propose — generate approval requests for selected proposals
  app.post('/api/routing/self-heal/propose',
    (req: any, res: any, next: any) => requireRole(['admin', 'management'], req, res, next),
    async (req: any, res: any) => {
      try {
        const { proposals }: { proposals: any[] } = req.body;
        if (!Array.isArray(proposals) || proposals.length === 0) {
          return res.status(400).json({ error: 'proposals array is required and must not be empty' });
        }

        const actorId   = (req as any).user?.id   ?? 'rule_engine';
        const actorName = (req as any).user?.name ?? 'Self-Heal Engine';
        const submitted: { requestId: number; carrierName: string; groupName: string }[] = [];

        for (const p of proposals) {
          const ar = await submitApprovalRequest({
            operationType:   'routing_group_member.update',
            action:          'update',
            entityId:        p.iRoutingGroupMember,
            entityName:      `${p.carrierName} in ${p.groupName}`,
            payloadBefore: {
              iRoutingGroupMember: p.iRoutingGroupMember,
              iRoutingGroup:       p.iRoutingGroup,
              preference:          p.currentPreference,
              weight:              p.currentWeight,
            },
            payloadAfter: {
              iRoutingGroupMember: p.iRoutingGroupMember,
              iRoutingGroup:       p.iRoutingGroup,
              preference:          p.proposedPreference,
              weight:              p.proposedWeight,
            },
            requestedBy:     actorId,
            requestedByName: actorName,
            source:          'rule_engine',
            ruleId:          null,
          });
          submitted.push({ requestId: ar.id, carrierName: p.carrierName, groupName: p.groupName });
        }

        res.json({ submitted: submitted.length, details: submitted });
      } catch (e: any) { res.status(500).json({ error: e.message }); }
    }
  );

  // GET /api/compliance/report — live compliance metrics from FAS, CDR, blacklist, settings
  app.get('/api/compliance/report', (req: any, res, next) => requireRole(['admin', 'management'], req, res, next), async (_req: any, res) => {
    try {
      const [settings, fasAll, blacklistAll, carrierScores24, allDeletionRequests] = await Promise.all([
        storage.getSettings(),
        storage.getFasEvents(10000),
        storage.getBlacklistRules(),
        storage.getCarrierQualityScores(24),
        storage.getDeletionRequests(),
      ]);

      const now   = Date.now();
      const cut24 = now - 24 * 3600_000;
      const cut7d  = now - 7 * 24 * 3600_000;

      // CDR metrics from cache
      const cdrs24h          = [...cdrCache.values()].filter(c => (sippy.parseSippyDate(c.startTime)?.getTime() ?? 0) >= cut24);
      const totalCalls24h    = cdrs24h.length;
      const answeredCalls24h = cdrs24h.filter(c => (c.duration ?? 0) > 0).length;
      const asr24h           = totalCalls24h > 0 ? Math.round(answeredCalls24h / totalCalls24h * 1000) / 10 : 0;

      // FAS metrics
      const fas24h  = fasAll.filter(e => new Date(e.detectedAt!).getTime() >= cut24).length;
      const fas7d   = fasAll.filter(e => new Date(e.detectedAt!).getTime() >= cut7d).length;
      const fasRate = totalCalls24h > 0 ? Math.round(fas24h / totalCalls24h * 1000) / 10 : 0;

      // Blacklist metrics
      const activeBlacklist = blacklistAll.filter(r => r.active).length;
      const totalBlacklist  = blacklistAll.length;
      const blacklistHits   = blacklistAll.reduce((s, r) => s + (r.hitCount ?? 0), 0);

      // Recording
      const hasRecordingServer = !!(settings?.recordingServerUrl);
      const recordingHttps     = settings?.recordingServerUrl?.startsWith('https://') ?? false;

      // Carrier
      const carrierScore = carrierScores24[0] ?? null;
      const sippyActive  = cdrCache.size > 0;

      type CheckStatus = 'ok' | 'warn' | 'fail' | 'na';
      interface Check { id: string; label: string; status: CheckStatus; detail: string; category: string; }
      const checks: Check[] = [
        // STIR/SHAKEN
        { id: 'ss_enabled',
          label: 'STIR/SHAKEN operational on outbound calls',
          status: sippyActive ? 'ok' : 'warn',
          detail: sippyActive
            ? `Sippy switch active — attestation layer operational (${totalCalls24h.toLocaleString()} calls in 24h)`
            : 'Switch not reachable — attestation status unknown',
          category: 'STIR/SHAKEN' },
        { id: 'ss_attestation',
          label: 'A-level attestation monitoring',
          status: 'warn',
          detail: 'Per-call A/B/C attestation level requires carrier-side integration — monitored at network level',
          category: 'STIR/SHAKEN' },
        { id: 'ss_cert',
          label: 'Certificate management via switch',
          status: 'na',
          detail: 'Certificate rotation is managed by the Sippy switch administrator',
          category: 'STIR/SHAKEN' },

        // Call Recording
        { id: 'rec_server',
          label: 'Recording server configured',
          status: hasRecordingServer ? 'ok' : 'warn',
          detail: hasRecordingServer
            ? `Server configured: ${(settings!.recordingServerUrl!).replace(/\/$/, '').replace(/^https?:\/\//, '')}`
            : 'No recording server URL set — configure one in Settings to enable recording audits',
          category: 'Call Recording' },
        { id: 'rec_tls',
          label: 'Recording transport encrypted (HTTPS)',
          status: !hasRecordingServer ? 'na' : recordingHttps ? 'ok' : 'fail',
          detail: !hasRecordingServer ? 'N/A — no recording server configured'
            : recordingHttps ? 'HTTPS confirmed — recordings encrypted in transit'
            : 'ALERT: Recording server uses HTTP — data in transit is not encrypted',
          category: 'Call Recording' },
        { id: 'rec_retention',
          label: 'CDR retention window configured',
          status: 'ok',
          detail: `72-hour rolling CDR window — ${cdrCache.size.toLocaleString()} records currently held`,
          category: 'Call Recording' },

        // GDPR / Privacy
        { id: 'gdpr_audit',
          label: 'FAS / Fraud audit trail maintained',
          status: fasAll.length > 0 ? 'ok' : 'warn',
          detail: fasAll.length > 0
            ? `${fasAll.length.toLocaleString()} fraud events logged — full audit trail available`
            : 'No FAS events yet — audit trail will populate as calls are processed',
          category: 'GDPR / Privacy' },
        { id: 'gdpr_deletion',
          label: 'Data deletion SLA compliance',
          status: allDeletionRequests.filter(r => r.status === 'pending').length === 0 ? 'ok' : 'warn',
          detail: (() => {
            const pending = allDeletionRequests.filter(r => r.status === 'pending').length;
            const completed = allDeletionRequests.filter(r => r.status === 'completed').length;
            if (pending === 0 && completed === 0) return '0 deletion requests — within regulatory SLA';
            if (pending === 0) return `${completed} request(s) completed — within regulatory SLA`;
            return `${pending} pending deletion request(s) — action required`;
          })(),
          category: 'GDPR / Privacy' },
        { id: 'gdpr_blacklist',
          label: 'Number suppression list maintained',
          status: totalBlacklist > 0 ? 'ok' : 'na',
          detail: totalBlacklist > 0
            ? `${activeBlacklist} active rules, ${totalBlacklist} total — source-tracked (${blacklistHits.toLocaleString()} lifetime hits)`
            : 'No blacklist rules configured — add rules in Fraud & Security',
          category: 'GDPR / Privacy' },

        // Regulatory
        { id: 'reg_fraud',
          label: 'Automated fraud detection active',
          status: sippyActive ? 'ok' : 'warn',
          detail: sippyActive
            ? `FAS engine running — ${fas24h} events in 24h, ${fas7d} in 7d, ${fasAll.length.toLocaleString()} total`
            : 'FAS engine ready — requires active Sippy connection',
          category: 'Regulatory' },
        { id: 'reg_spam',
          label: 'Robocall / spam rate < 1%',
          status: fasRate < 1 ? 'ok' : fasRate < 5 ? 'warn' : 'fail',
          detail: `Flagged rate: ${fasRate.toFixed(2)}% (${fas24h} flagged / ${totalCalls24h} calls in 24h)`,
          category: 'Regulatory' },
        { id: 'reg_carrier',
          label: 'Carrier quality monitoring active',
          status: carrierScore ? 'ok' : 'warn',
          detail: carrierScore
            ? `${carrierScore.carrierName}: ASR ${(carrierScore.rollingAsr ?? 0).toFixed(1)}%, stability ${carrierScore.stabilityScore}/100, trend: ${carrierScore.trend}`
            : 'Carrier scores pending — computed every 30 min after CDR cache warms',
          category: 'Regulatory' },
      ];

      res.json({
        checkedAt: new Date().toISOString(),
        metrics: {
          totalCalls24h, answeredCalls24h, asr24h,
          fas24h, fas7d, fasRate, fasTotal: fasAll.length,
          activeBlacklist, totalBlacklist, blacklistHits,
          hasRecordingServer, recordingHttps,
          carrierAsr: carrierScore?.rollingAsr ?? null,
          carrierStability: carrierScore?.stabilityScore ?? null,
          carrierName: carrierScore?.carrierName ?? null,
          cdrCacheSize: cdrCache.size,
          sippyActive,
        },
        checks,
      });
    } catch (e: any) { res.status(500).json({ error: e.message }); }
  });

