  // GET /api/routing-rules/metrics?window=5 — live metric snapshot per vendor from CDR cache
  app.get('/api/routing-rules/metrics', (req: any, res: any, next: any) => requireRole(['admin','management','noc_operator'], req, res, next), async (req: any, res: any) => {
    try {
      const windowMin = Math.min(120, Math.max(1, parseInt((req.query.window as string) || '15', 10)));
      const cutoff = Date.now() - windowMin * 60_000;

      // Group CDR cache by vendor
      const vendorMap = new Map<string, { total: number; answered: number; durSum: number; pddSum: number; pddCount: number }>();
      for (const c of cdrCache.values() as any) {
        const ts = c.startTime ? new Date(c.startTime).getTime() : 0;
        if (ts < cutoff) continue;
        const vendor = (c.vendor as string) || 'Unknown';
        const e = vendorMap.get(vendor) ?? { total: 0, answered: 0, durSum: 0, pddSum: 0, pddCount: 0 };
        e.total++;
        const dur = Number(c.duration ?? 0);
        if (dur > 0) { e.answered++; e.durSum += dur; }
        const pdd = Number(c.pdd ?? 0);
        if (pdd > 0) { e.pddSum += pdd; e.pddCount++; }
        vendorMap.set(vendor, e);
      }

      // Live concurrent calls per vendor from liveCallsCache
      const liveByVendor = new Map<string, number>();
      for (const lc of (liveCallsCache.calls ?? []) as any[]) {
        const v = lc.vendor || lc.connectionName || 'Unknown';
        liveByVendor.set(v, (liveByVendor.get(v) ?? 0) + 1);
      }

      const vendors = [...vendorMap.entries()]
        .sort((a, b) => b[1].total - a[1].total)
        .map(([vendor, m]) => {
          const asr = m.total > 0 ? parseFloat(((m.answered / m.total) * 100).toFixed(2)) : null;
          const acd = m.answered > 0 ? parseFloat((m.durSum / m.answered).toFixed(1)) : null;
          const pdd = m.pddCount > 0 ? parseFloat((m.pddSum / m.pddCount).toFixed(2)) : null;
          const concurrent = liveByVendor.get(vendor) ?? 0;
          return { vendor, total: m.total, answered: m.answered, asr, acd, pdd, concurrent };
        });

      res.json({ window: windowMin, vendors, generatedAt: new Date().toISOString() });
    } catch (e: any) { res.status(500).json({ message: e.message }); }
  });

  // GET /api/campaigns/carrier-matrix — per-carrier MOS quality matrix from synthetic test results
  app.get('/api/campaigns/carrier-matrix', (req: any, res: any, next: any) => requireRole(['admin','management','noc_operator'], req, res, next), async (req: any, res: any) => {
    try {
      const { db } = await import('./db');
      const { routeDecisionTraces } = await import('../shared/schema');
      const { desc } = await import('drizzle-orm');

      const cutoff = new Date(Date.now() - 30 * 86_400_000); // last 30 days
      const traces = await db.select().from(routeDecisionTraces)
        .where((await import('drizzle-orm')).gte(routeDecisionTraces.createdAt, cutoff))
        .orderBy(desc(routeDecisionTraces.createdAt))
        .limit(5000);

      // Group by selectedCarrier
      const matrix = new Map<string, {
        total: number; connected: number; failed: number;
        pddSum: number; pddCount: number; durSum: number; durCount: number;
        recentPdds: number[]; sipCodes: Map<number, number>;
      }>();

      for (const t of traces) {
        const carrier = t.selectedCarrier || 'Unknown';
        const e = matrix.get(carrier) ?? {
          total: 0, connected: 0, failed: 0,
          pddSum: 0, pddCount: 0, durSum: 0, durCount: 0,
          recentPdds: [], sipCodes: new Map(),
        };
        e.total++;
        if (t.outcome === 'connected') {
          e.connected++;
          if (t.pddMs && t.pddMs > 0) { e.pddSum += t.pddMs; e.pddCount++; e.recentPdds.push(t.pddMs); }
          if (t.durationSec && t.durationSec > 0) { e.durSum += t.durationSec; e.durCount++; }
        } else {
          e.failed++;
        }
        if (t.sipCode) { e.sipCodes.set(t.sipCode, (e.sipCodes.get(t.sipCode) ?? 0) + 1); }
        matrix.set(carrier, e);
      }

      // MOS estimation and grading — delegates to shared ITU-T G.107 utility
      const estimateMOS = (pddMs: number) => estimateMOSFromPDD(pddMs);
      const mosGrade    = (m: number)     => mosToGrade(m);

      const rows = [...matrix.entries()]
        .filter(([, e]) => e.total >= 2)
        .map(([carrier, e]) => {
          const asr = e.total > 0 ? parseFloat(((e.connected / e.total) * 100).toFixed(2)) : null;
          const avgPddMs = e.pddCount > 0 ? parseFloat((e.pddSum / e.pddCount).toFixed(1)) : null;
          const avgDurSec = e.durCount > 0 ? parseFloat((e.durSum / e.durCount).toFixed(1)) : null;
          const estimatedMos = avgPddMs ? estimateMOS(avgPddMs) : null;
          const grade = estimatedMos ? mosGrade(estimatedMos) : 'N/A';
          // Top SIP error codes
          const topErrors = [...e.sipCodes.entries()]
            .filter(([code]) => code >= 400)
            .sort((a, b) => b[1] - a[1])
            .slice(0, 3)
            .map(([code, count]) => ({ code, count }));
          return {
            carrier, total: e.total, connected: e.connected, failed: e.failed,
            asr, avgPddMs, avgDurSec, estimatedMos, grade, topErrors,
          };
        })
        .sort((a, b) => (b.estimatedMos ?? 0) - (a.estimatedMos ?? 0));

      res.json({ rows, total: traces.length, windowDays: 30 });
    } catch (e: any) { res.status(500).json({ message: e.message }); }
  });

  // GET /api/resellers/:id/stats?days=30 — CDR-based usage, revenue, and margin for one reseller
  app.get('/api/resellers/:id/stats', (req: any, res: any, next: any) => requireRole(['admin', 'management'], req, res, next), async (req: any, res: any) => {
    try {
      const { db } = await import('./db');
      const { resellerProfiles } = await import('../shared/schema');
      const { eq } = await import('drizzle-orm');
      const id = parseInt(req.params.id, 10);
      if (isNaN(id)) return res.status(400).json({ message: 'Invalid id' });
      const [reseller] = await db.select().from(resellerProfiles).where(eq(resellerProfiles.id, id));
      if (!reseller) return res.status(404).json({ message: 'Reseller not found' });

      const days = Math.min(90, Math.max(1, parseInt(req.query.days as string || '30', 10)));
      const cutoff = Date.now() - days * 86_400_000;
      const markup = reseller.markupPercent ?? 0;

      // Filter CDR cache: match iCustomer if set, else return empty (no PII leak)
      const matchCdr = (c: any): boolean => {
        if (!reseller.iCustomer) return false;
        const ts = c.startTime ? new Date(c.startTime).getTime()
                 : c.connectTime ? new Date(c.connectTime).getTime() : 0;
        if (ts < cutoff) return false;
        return Number(c.iCustomer) === reseller.iCustomer;
      };

      const cdrs = [...cdrCache.values()].filter(matchCdr);

      let totalCalls = 0, answeredCalls = 0, totalSec = 0, totalCost = 0;
      const destMap = new Map<string, { calls: number; secs: number; cost: number }>();
      const dayMap  = new Map<string, { calls: number; answered: number; mins: number; cost: number }>();

      for (const c of cdrs as any[]) {
        totalCalls++;
        const answered = (c.duration ?? 0) > 0;
        if (answered) { answeredCalls++; totalSec += c.duration ?? 0; }
        totalCost += c.cost ?? 0;

        // Top destinations
        const dest = (c.callee ?? '').replace(/\d{4,}$/, 'XXXX'); // anonymise last digits
        const dEntry = destMap.get(dest) ?? { calls: 0, secs: 0, cost: 0 };
        dEntry.calls++; if (answered) dEntry.secs += c.duration ?? 0; dEntry.cost += c.cost ?? 0;
        destMap.set(dest, dEntry);

        // Daily breakdown
        const ts = c.startTime || c.connectTime;
        if (ts) {
          const day = new Date(ts).toISOString().slice(0, 10);
          const dDay = dayMap.get(day) ?? { calls: 0, answered: 0, mins: 0, cost: 0 };
          dDay.calls++; if (answered) { dDay.answered++; dDay.mins += (c.duration ?? 0) / 60; }
          dDay.cost += c.cost ?? 0;
          dayMap.set(day, dDay);
        }
      }

      const totalMins   = totalSec / 60;
      const revenue     = totalCost * (1 + markup / 100);
      const margin      = revenue - totalCost;
      const marginPct   = revenue > 0 ? (margin / revenue) * 100 : 0;
      const asr         = totalCalls > 0 ? (answeredCalls / totalCalls) * 100 : 0;
      const acd         = answeredCalls > 0 ? totalSec / answeredCalls : 0;

      const topDestinations = [...destMap.entries()]
        .sort((a, b) => b[1].secs - a[1].secs)
        .slice(0, 12)
        .map(([dest, d]) => ({
          dest, calls: d.calls, mins: +(d.secs / 60).toFixed(2),
          cost: +d.cost.toFixed(4), revenue: +(d.cost * (1 + markup / 100)).toFixed(4),
        }));

      // Fill daily series for the window (last 30 days at most for chart)
      const chartDays = Math.min(days, 30);
      const dailySeries = [];
      for (let i = chartDays - 1; i >= 0; i--) {
        const d = new Date(Date.now() - i * 86_400_000).toISOString().slice(0, 10);
        const entry = dayMap.get(d) ?? { calls: 0, answered: 0, mins: 0, cost: 0 };
        dailySeries.push({ date: d, calls: entry.calls, answered: entry.answered, mins: +entry.mins.toFixed(2), cost: +entry.cost.toFixed(4), revenue: +(entry.cost * (1 + markup / 100)).toFixed(4) });
      }

      res.json({
        resellerId: id, days, markup,
        totalCalls, answeredCalls, totalMins: +totalMins.toFixed(2),
        cost: +totalCost.toFixed(4), revenue: +revenue.toFixed(4),
        margin: +margin.toFixed(4), marginPct: +marginPct.toFixed(2),
        asr: +asr.toFixed(2), acd: +acd.toFixed(1),
        topDestinations, dailySeries,
        cdrSource: reseller.iCustomer ? 'cdr_cache' : 'no_customer_linked',
      });
    } catch (e: any) { res.status(500).json({ message: e.message }); }
  });

  // GET /api/resellers/:id/statement?month=YYYY-MM — monthly invoice/statement data
  app.get('/api/resellers/:id/statement', (req: any, res: any, next: any) => requireRole(['admin', 'management'], req, res, next), async (req: any, res: any) => {
    try {
      const { db } = await import('./db');
      const { resellerProfiles } = await import('../shared/schema');
      const { eq } = await import('drizzle-orm');
      const id = parseInt(req.params.id, 10);
      if (isNaN(id)) return res.status(400).json({ message: 'Invalid id' });
      const [reseller] = await db.select().from(resellerProfiles).where(eq(resellerProfiles.id, id));
      if (!reseller) return res.status(404).json({ message: 'Reseller not found' });

      // Parse month (default = current month)
      const monthStr = (req.query.month as string) || new Date().toISOString().slice(0, 7);
      const [yy, mm] = monthStr.split('-').map(Number);
      const monthStart = new Date(yy, mm - 1, 1).getTime();
      const monthEnd   = new Date(yy, mm, 1).getTime(); // exclusive

      const markup = reseller.markupPercent ?? 0;

      const cdrs = [...cdrCache.values()].filter((c: any) => {
        if (!reseller.iCustomer) return false;
        if (Number(c.iCustomer) !== reseller.iCustomer) return false;
        const ts = c.startTime ? new Date(c.startTime).getTime()
                 : c.connectTime ? new Date(c.connectTime).getTime() : 0;
        return ts >= monthStart && ts < monthEnd;
      }) as any[];

      // Build line items grouped by destination prefix (first 4 digits)
      const lineMap = new Map<string, { calls: number; answered: number; secs: number; cost: number }>();
      let totalCalls = 0, answeredCalls = 0, totalSec = 0, totalCost = 0;

      for (const c of cdrs) {
        totalCalls++;
        const answered = (c.duration ?? 0) > 0;
        if (answered) { answeredCalls++; totalSec += c.duration ?? 0; }
        totalCost += c.cost ?? 0;

        const prefix = (c.callee ?? '').slice(0, 6) || 'Unknown';
        const e = lineMap.get(prefix) ?? { calls: 0, answered: 0, secs: 0, cost: 0 };
        e.calls++; if (answered) { e.answered++; e.secs += c.duration ?? 0; } e.cost += c.cost ?? 0;
        lineMap.set(prefix, e);
      }

      const lineItems = [...lineMap.entries()]
        .sort((a, b) => b[1].secs - a[1].secs)
        .map(([prefix, e]) => ({
          prefix, calls: e.calls, answered: e.answered,
          mins: +(e.secs / 60).toFixed(4),
          cost: +e.cost.toFixed(6),
          revenue: +(e.cost * (1 + markup / 100)).toFixed(6),
          margin: +(e.cost * (markup / 100)).toFixed(6),
        }));

      const revenue = totalCost * (1 + markup / 100);

      res.json({
        resellerId: id, month: monthStr, markup,
        resellerName: reseller.name, brandName: reseller.brandName,
        contactEmail: reseller.contactEmail,
        totalCalls, answeredCalls,
        totalMins: +(totalSec / 60).toFixed(4),
        cost: +totalCost.toFixed(6), revenue: +revenue.toFixed(6),
        margin: +(revenue - totalCost).toFixed(6),
        asr: totalCalls > 0 ? +((answeredCalls / totalCalls) * 100).toFixed(2) : 0,
        lineItems,
        generatedAt: new Date().toISOString(),
      });
    } catch (e: any) { res.status(500).json({ message: e.message }); }
  });

  // ── Account Management — Companies ───────────────────────────────────────────

  app.get('/api/companies', (req: any, res: any, next: any) => requireRole(['admin','management'], req, res, next), async (req: any, res) => {
    try {
      const rows = await storage.getCompanies();
      res.json({ companies: rows });
    } catch (e: any) { res.status(500).json({ message: e.message }); }
  });

  app.post('/api/companies', (req: any, res: any, next: any) => requireRole(['admin','management'], req, res, next), async (req: any, res) => {
    try {
      const { basic, billing, contacts = [], bankAccounts = [] } = req.body ?? {};
      if (!basic?.name?.trim()) return res.status(400).json({ message: 'Company name is required' });
      if (!basic?.shortCode?.trim()) return res.status(400).json({ message: 'Short code is required' });
      const company = await storage.createCompany({
        name: basic.name.trim(),
        shortCode: basic.shortCode.trim().toUpperCase(),
        country: basic.country || null,
        kam: basic.kam || null,
        status: basic.status || 'active',
        companyType: basic.companyType || 'retail',
        contractType: basic.contractType || 'bilateral',
        department: basic.department || null,
        team: basic.team || null,
        clientTimezone: basic.clientTimezone || null,
        vendorTimezone: basic.vendorTimezone || null,
        currency: basic.currency || 'USD',
        vendorBillingCycle: billing?.vendorBillingCycle || 'weekly_cutoff',
        vendorGracePeriod: billing?.vendorGracePeriod ?? 3,
        vendorCreditLimit: billing?.vendorCreditLimit ?? 0,
        disputeOverPct: billing?.disputeOverPct ?? 0,
        clientBillingCycle: billing?.clientBillingCycle || 'weekly_cutoff',
        clientGracePeriod: billing?.clientGracePeriod ?? 3,
        clientCreditLimit: billing?.clientCreditLimit ?? 0,
        disputeOverVal: billing?.disputeOverVal ?? 0,
        paymentTerm: billing?.paymentTerm || 'prepaid',
        legalNameCi: billing?.legalNameCi || null,
        legalNameVen: billing?.legalNameVen || null,
        invoiceEmail: billing?.invoiceEmail || null,
        notes: null,
        createdBy: (req as any).user?.claims?.sub || null,
      }, contacts, bankAccounts);
      res.json({ company });
    } catch (e: any) {
      const msg = e.message || '';
      if (msg.includes('unique') || msg.includes('duplicate')) return res.status(409).json({ message: 'Company name or short code already exists' });
      res.status(500).json({ message: msg });
    }
  });

  app.get('/api/companies/:id', (req: any, res: any, next: any) => requireRole(['admin','management'], req, res, next), async (req: any, res) => {
    try {
      const id = parseInt(req.params.id, 10);
      if (isNaN(id)) return res.status(400).json({ message: 'Invalid ID' });
      const company = await storage.getCompany(id);
      if (!company) return res.status(404).json({ message: 'Company not found' });
      res.json({ company });
    } catch (e: any) { res.status(500).json({ message: e.message }); }
  });

  app.put('/api/companies/:id', (req: any, res: any, next: any) => requireRole(['admin','management'], req, res, next), async (req: any, res) => {
    try {
      const id = parseInt(req.params.id, 10);
      if (isNaN(id)) return res.status(400).json({ message: 'Invalid ID' });
      const updated = await storage.updateCompany(id, req.body);
      res.json({ company: updated });
    } catch (e: any) { res.status(500).json({ message: e.message }); }
  });

  app.delete('/api/companies/:id', (req: any, res: any, next: any) => requireRole(['admin'], req, res, next), async (req: any, res) => {
    try {
      const id = parseInt(req.params.id, 10);
      if (isNaN(id)) return res.status(400).json({ message: 'Invalid ID' });
      await storage.deleteCompany(id);
      res.json({ success: true });
    } catch (e: any) { res.status(500).json({ message: e.message }); }
  });

  // ── Account Management — Client IP Approval Requests ─────────────────────────

  app.get('/api/client-ip-requests', (req: any, res: any, next: any) => requireRole(['admin','management'], req, res, next), async (req: any, res) => {
    try {
      const rows = await storage.getClientIpRequests();
      const companyId = req.query.companyId ? parseInt(req.query.companyId as string, 10) : null;
      const filtered = companyId ? rows.filter((r: any) => r.companyId === companyId) : rows;
      res.json({ requests: filtered });
    } catch (e: any) { res.status(500).json({ message: e.message }); }
  });

  app.post('/api/client-ip-requests', (req: any, res: any, next: any) => requireRole(['admin','management'], req, res, next), async (req: any, res) => {
    try {
      const { clientName, companyId, ipAddress, trunk, description } = req.body ?? {};
      if (!clientName?.trim()) return res.status(400).json({ message: 'Client name is required' });
      if (!ipAddress?.trim()) return res.status(400).json({ message: 'IP address is required' });
      const existing = await storage.findClientIpRequest(ipAddress.trim(), clientName.trim());
      if (existing && existing.status === 'pending') return res.status(409).json({ message: 'IP already submitted and pending approval' });
      const row = await storage.createClientIpRequest({
        clientName: clientName.trim(),
        companyId: companyId ? parseInt(companyId, 10) : null,
        ipAddress: ipAddress.trim(),
        trunk: trunk || null,
        description: description || null,
        status: 'pending',
        submittedBy: (req as any).user?.claims?.sub || null,
        reviewedBy: null,
        rejectionReason: null,
        reviewedAt: null,
      });
      res.json({ request: row });
    } catch (e: any) { res.status(500).json({ message: e.message }); }
  });

  app.patch('/api/client-ip-requests/:id/approve', (req: any, res: any, next: any) => requireRole(['admin'], req, res, next), async (req: any, res) => {
    try {
      const id = parseInt(req.params.id, 10);
      const reviewer = (req as any).user?.claims?.sub || 'admin';
      const updated = await storage.updateClientIpRequest(id, { status: 'approved', reviewedBy: reviewer, reviewedAt: new Date() });
      // Incremental sync: if the company is already provisioned, push auth rule to Sippy immediately
      if (updated.companyId) {
        try {
          const company = await storage.getCompany(updated.companyId);
          if (company?.provisioningStatus === 'provisioned' && company.sippyIAccount) {
            const settings = await storage.getSettings();
            const { username, password } = sippyXmlCreds(settings as any);
            await sippy.addSippyAuthRule(username, password, { iAccount: company.sippyIAccount, iProtocol: 1, remoteIp: updated.ipAddress });
          }
        } catch (syncErr: any) {
          console.warn('[IP Approve] Incremental Sippy sync failed:', syncErr.message);
        }
      }
      res.json({ request: updated });
    } catch (e: any) { res.status(500).json({ message: e.message }); }
  });

  app.patch('/api/client-ip-requests/:id/reject', (req: any, res: any, next: any) => requireRole(['admin'], req, res, next), async (req: any, res) => {
    try {
      const id = parseInt(req.params.id, 10);
      const { reason } = req.body ?? {};
      const reviewer = (req as any).user?.claims?.sub || 'admin';
      const updated = await storage.updateClientIpRequest(id, { status: 'rejected', reviewedBy: reviewer, rejectionReason: reason || null, reviewedAt: new Date() });
      res.json({ request: updated });
    } catch (e: any) { res.status(500).json({ message: e.message }); }
  });

  // ── Account Management — Client Wizard Submit ─────────────────────────────────

  app.post('/api/client-wizard/submit', (req: any, res: any, next: any) => requireRole(['admin','management'], req, res, next), async (req: any, res) => {
    try {
      const { step1, step2, trunks, ips, iCustomer = 1 } = req.body ?? {};
      if (!step1?.userId?.trim()) return res.status(400).json({ message: 'User ID is required' });
      if (!step1?.companyId) return res.status(400).json({ message: 'Company is required' });
      const companyId = parseInt(step1.companyId, 10);
      const company = await storage.getCompany(companyId);
      if (!company) return res.status(404).json({ message: 'Company not found' });
      const draft = JSON.stringify({ step1, step2, trunks, ips, iCustomer });
      // If already provisioned — update the draft only (do NOT reset status to pending_provision,
      // and do NOT block the save).  The provision button is separately guarded.
      if (company.provisioningStatus === 'provisioned') {
        await storage.updateCompany(companyId, { wizardDraft: draft } as any);
        return res.json({ success: true, companyId, status: 'provisioned', alreadyProvisioned: true });
      }
      await storage.updateCompany(companyId, { wizardDraft: draft, provisioningStatus: 'pending_provision' } as any);
      res.json({ success: true, companyId, status: 'pending_provision' });
    } catch (e: any) { res.status(500).json({ message: e.message }); }
  });

  // POST /api/companies/:id/provision — provision a client to Sippy (admin only)
  app.post('/api/companies/:id/provision', (req: any, res: any, next: any) => requireRole(['admin'], req, res, next), async (req: any, res) => {
    try {
      const companyId = parseInt(req.params.id, 10);
      if (isNaN(companyId)) return res.status(400).json({ message: 'Invalid company ID' });
      const company = await storage.getCompany(companyId);
      if (!company) return res.status(404).json({ message: 'Company not found' });
      if (company.provisioningStatus === 'provisioned') return res.status(409).json({ message: 'Client already provisioned in Sippy' });
      if (!company.wizardDraft) return res.status(400).json({ message: 'No wizard draft found. Complete the client wizard first.' });
      const ipRequests = await storage.getClientIpRequests(companyId);
      const pendingIps = ipRequests.filter((r: any) => r.status === 'pending');
      const approvedIps = ipRequests.filter((r: any) => r.status === 'approved');
      if (pendingIps.length > 0) return res.status(400).json({ message: `${pendingIps.length} IP(s) still pending approval. Approve or reject all IPs before provisioning.` });
      if (approvedIps.length === 0) return res.status(400).json({ message: 'No approved IPs. Approve at least one IP before provisioning.' });
      const draft = JSON.parse(company.wizardDraft);
      const { step1, trunks, iCustomer = 1 } = draft;
      const settings = await storage.getSettings();
      const { username, password } = sippyXmlCreds(settings as any);
      const portalUrl = sippyPortalUrl(settings as any);
      const adminUser = (settings as any)?.apiAdminUsername || (settings as any)?.portalUsername || '';
      const adminPass = (settings as any)?.apiAdminPassword || (settings as any)?.portalPassword || '';
      const portalUser = (settings as any)?.portalUsername || '';
      const portalPass = (settings as any)?.portalPassword || '';
      const adminWebPassword = (settings as any)?.adminWebPassword || undefined;
      const primaryTrunk = trunks?.[0] ?? {};
      // Naming convention: base = shortCode (e.g. "PTCL"), then distinct suffixes per object
      const planBase    = company.shortCode || company.name;
      const tariffName  = `${planBase}-TARIFF`;
      const servicePlanName = `${planBase}-SP`;

      // ── Step 1: create tariff named <CODE>-TARIFF ──────────────────────────
      let servicePlanId: string | undefined;
      let servicePlanCreated = false;
      let servicePlanFallbackName: string | undefined;
      try {
        const tariffRes = await sippy.createSippyTariff(username, password, { name: tariffName, currency: 'USD' }, portalUrl);
        if (tariffRes.success && tariffRes.iTariff) {
          console.log(`[Provision] Tariff "${tariffName}" id=${tariffRes.iTariff}${tariffRes.message.includes('reusing') ? ' (reused)' : ''}`);
          // ── Step 2: create service plan named <CODE>-SP ────────────────────
          const planRes = await sippy.createSippyServicePlan(
            portalUrl, adminUser, adminPass, portalUser, portalPass,
            servicePlanName, tariffRes.iTariff, undefined, 3, adminWebPassword,
          );
          if (planRes.success && planRes.planId) {
            servicePlanId = String(planRes.planId);
            servicePlanCreated = true;
            console.log(`[Provision] Service plan "${servicePlanName}" id=${planRes.planId}${planRes.alreadyExists ? ' (already existed)' : ''}`);
          } else {
            console.error(`[Provision] Service plan creation incomplete: ${planRes.error || 'no plan ID'}`);
            // Service plan portal write failed — discover an existing billing plan via XML-RPC
            // so pushAccountToSippy can use a valid ID without its own probe round-trip.
            const bpFallback = await sippy.listSippyBillingPlans(username, password, portalUrl);
            if (bpFallback.plans.length > 0) {
              servicePlanId = String(bpFallback.plans[0].id);
              servicePlanFallbackName = bpFallback.plans[0].name;
              console.log(`[Provision] Using fallback billing plan: ${bpFallback.plans[0].id} "${bpFallback.plans[0].name}"`);
            }
          }
        } else {
          console.error(`[Provision] Tariff creation failed: ${tariffRes.message}`);
        }
      } catch (e: any) {
        console.error(`[Provision] Tariff/plan setup error (non-fatal): ${e.message}`);
      }

      const displayName = step1.displayName || company.name;
      const result = await sippy.pushAccountToSippy({
        name: displayName,
        type: 'client',
        username: step1.userId,
        voipPassword: step1.password,
        webPassword: step1.password,
        companyName: displayName,
        iCustomer,
        servicePlan: servicePlanId,
        routingGroup: primaryTrunk.routingGroupId || undefined,
        maxSessions: primaryTrunk.maxSessions ? parseInt(primaryTrunk.maxSessions, 10) : 0,
        maxCallsPerSecond: primaryTrunk.maxCps ? parseFloat(primaryTrunk.maxCps) : undefined,
        maxSessionTime: primaryTrunk.maxTime ? parseInt(primaryTrunk.maxTime, 10) : 3600,
        preferredCodec: primaryTrunk.codec && primaryTrunk.codec !== 'none' ? parseInt(primaryTrunk.codec, 10) : null,
        usePreferredCodecOnly: !!primaryTrunk.useCodecOnly,
        disallowLoops: !!primaryTrunk.preventLoops,
        regAllowed: primaryTrunk.allowRegistration !== false ? 1 : 0,
        cldTranslationRule: primaryTrunk.cldTranslation || '',
        email: step1.notifEmailTo || undefined,
        cc: step1.notifEmailCc || undefined,
        currency: 'USD',
      }, { username, password }, portalUrl);
      let iAccount: number | undefined = result?.i_account;
      // Always attempt username lookup when no i_account returned — covers:
      // 1. Portal-path creates account but returns no ID
      // 2. createAccount faults "already exists" (previous attempt), need to find existing account
      if (!iAccount) {
        console.log(`[Provision] No i_account in response (success=${result?.success}) — looking up account by username: ${step1.userId}`);
        const lookupResult = await sippy.listSippyAccounts(username, password, {}, portalUrl);
        const match = lookupResult.accounts.find((a: any) =>
          a.username?.toLowerCase() === step1.userId?.toLowerCase()
        );
        if (match) {
          iAccount = match.iAccount;
          console.log(`[Provision] Found account ID via lookup: ${iAccount}`);
        } else {
          // Try scoped to iCustomer as a second attempt
          const lookupResult2 = await sippy.listSippyAccounts(username, password, { iCustomer: iCustomer ?? 1 }, portalUrl);
          const match2 = lookupResult2.accounts.find((a: any) =>
            a.username?.toLowerCase() === step1.userId?.toLowerCase()
          );
          if (match2) {
            iAccount = match2.iAccount;
            console.log(`[Provision] Found account ID via scoped lookup (iCustomer=${iCustomer}): ${iAccount}`);
          }
        }
      }
      if (!iAccount) {
        const createMsg = result?.message || 'unknown error';
        const createDetail = (result as any)?.detail || '';
        console.error(`[Provision] createAccount failed — message: ${createMsg} | detail: ${createDetail}`);
        throw new Error(`Could not provision account "${step1.userId}" on Sippy. Creation result: ${createMsg}${createDetail ? ` Detail: ${createDetail}` : ''}. The account may not exist yet — check Sippy portal.`);
      }
      // Normalize IPs: strip leading zeros per octet (e.g. 191.098.6.9 → 191.98.6.9)
      const normIp = (ip: string) => ip.split('.').map(o => parseInt(o, 10).toString()).join('.');
      const authErrors: string[] = [];
      for (const ipReq of approvedIps) {
        const normalizedIp = normIp(ipReq.ipAddress);
        if (normalizedIp !== ipReq.ipAddress) console.log(`[Provision] Normalized IP: ${ipReq.ipAddress} → ${normalizedIp}`);
        console.log(`[Provision] Adding Sippy auth rule: iAccount=${iAccount}, ip=${normalizedIp}, protocol=SIP`);
        const authResult = await sippy.addSippyAuthRule(
          username, password,
          { iAccount, iProtocol: 1, remoteIp: normalizedIp },
          portalUrl,
        );
        if (authResult.success) {
          console.log(`[Provision] Auth rule added OK for ${ipReq.ipAddress} → i_authentication=${authResult.iAuthentication}`);
        } else {
          console.error(`[Provision] Auth rule FAILED for ${ipReq.ipAddress}: ${authResult.message}`);
          authErrors.push(`${ipReq.ipAddress}: ${authResult.message}`);
        }
      }
      const reviewer = (req as any).user?.claims?.sub || 'admin';
      await storage.updateCompany(companyId, { provisioningStatus: 'provisioned', sippyIAccount: iAccount, provisionedAt: new Date(), provisionedBy: reviewer } as any);
      const servicePlanNote = servicePlanCreated
        ? undefined
        : servicePlanFallbackName
          ? `Service plan "${servicePlanName}" could not be auto-created (Sippy portal permission). Account was assigned fallback plan "${servicePlanFallbackName}". Manually create "${servicePlanName}" in Sippy → Customers → Service Plans and reassign this account.`
          : `Service plan "${servicePlanName}" could not be auto-created. Please create it manually in Sippy and assign it to account "${step1.userId}".`;
      res.json({ success: true, iAccount, authErrors: authErrors.length ? authErrors : undefined, servicePlanNote });
    } catch (e: any) { res.status(500).json({ message: e.message }); }
  });

  // POST /api/companies/:id/add-auth-rules — re-push all approved IPs as Sippy auth rules (admin only)
  app.post('/api/companies/:id/add-auth-rules', (req: any, res: any, next: any) => requireRole(['admin'], req, res, next), async (req: any, res) => {
    try {
      const companyId = parseInt(req.params.id, 10);
      const company   = await storage.getCompany(companyId);
      if (!company) return res.status(404).json({ message: 'Company not found.' });
      if (!company.sippyIAccount) return res.status(400).json({ message: 'Company has no Sippy account ID — provision first.' });

      const creds     = await storage.getSippyCredentials?.();
      const settings  = await storage.getSettings?.();
      const portalUrl = settings?.portalUrl || process.env.SIPPY_PORTAL_URL || '';
      const username  = creds?.apiAdminUsername || process.env.SIPPY_ADMIN_USERNAME || '';
      const password  = creds?.apiAdminPassword || process.env.SIPPY_ADMIN_PASSWORD || '';

      const allIps    = await storage.getClientIpRequests(companyId);
      const approvedIps = allIps.filter((r: any) => r.status === 'approved');
      if (approvedIps.length === 0) return res.status(400).json({ message: 'No approved IPs for this company.' });

      const iAccount  = company.sippyIAccount;
      const results: { ip: string; success: boolean; message: string; iAuthentication?: number }[] = [];

      // Normalize IP: strip leading zeros from each octet (e.g. 191.098.6.9 → 191.98.6.9)
      // Sippy rejects IPs with leading-zero octets ("Parameter remote_ip has incorrect format").
      const normalizeIp = (ip: string) =>
        ip.split('.').map(o => parseInt(o, 10).toString()).join('.');

      for (const ipReq of approvedIps) {
        const normalizedIp = normalizeIp(ipReq.ipAddress);
        if (normalizedIp !== ipReq.ipAddress) {
          console.log(`[AddAuthRules] Normalized IP: ${ipReq.ipAddress} → ${normalizedIp}`);
        }
        console.log(`[AddAuthRules] Adding auth rule: iAccount=${iAccount}, ip=${normalizedIp}`);
        const authResult = await sippy.addSippyAuthRule(
          username, password,
          { iAccount, iProtocol: 1, remoteIp: normalizedIp },
          portalUrl,
        );
        console.log(`[AddAuthRules] ${ipReq.ipAddress}: ${authResult.success ? `OK (i_authentication=${authResult.iAuthentication})` : `FAILED: ${authResult.message}`}`);
        results.push({ ip: ipReq.ipAddress, success: authResult.success, message: authResult.message, iAuthentication: authResult.iAuthentication });
      }

      const failed = results.filter(r => !r.success);
      res.json({ success: failed.length === 0, results, failCount: failed.length });
    } catch (e: any) { res.status(500).json({ message: e.message }); }
  });

